"\n/* =================================================================\n   STATE\n   ================================================================= */\nconst S = {\n    persona: null,\n    tab: localStorage.getItem('mmcp-tab') || 'overview',\n    refreshTimer: null,\n    charts: {},\n    mem: { page: 1, tag: '', q: '', perPage: 20 },\n    statusPoll: null,\n    dashCache: null,\n    initTime: Date.now()\n};\n\nconst CHART_COLORS = ['#a78bfa','#f472b6','#60a5fa','#34d399','#fbbf24','#fb923c','#f87171','#2dd4bf','#a3e635','#e879f9'];\nconst EMOTION_COLORS = {\n    joy:'#fbbf24', sadness:'#60a5fa', anger:'#f87171', fear:'#a78bfa',\n    surprise:'#fb923c', disgust:'#6ee7b7', love:'#ec4899', neutral:'#94a3b8',\n    anticipation:'#F59E0B', trust:'#10B981', anxiety:'#8B5CF6', excitement:'#EC4899',\n    frustration:'#DC2626', nostalgia:'#92400E', pride:'#F97316', shame:'#BE185D',\n    guilt:'#78350F', loneliness:'#1E3A5F', contentment:'#065F46', curiosity:'#0891B2',\n    awe:'#5B21B6', relief:'#34D399',\n    happiness:'#fbbf24', calm:'#2dd4bf'\n};\n\n/* =================================================================\n   UTILITIES\n   ================================================================= */\nfunction esc(s) {\n    if (!s) return '';\n    const d = document.createElement('div');\n    d.textContent = String(s);\n    return d.innerHTML.replace(/\"/g, '&quot;');\n}\nfunction truncate(s, n) { return s && s.length > n ? s.slice(0, n) + '...' : (s || ''); }\nfunction relativeTime(iso) {\n    if (!iso) return '--';\n    const diff = Date.now() - new Date(iso).getTime();\n    if (diff < 0) return 'just now';\n    if (diff < 60000) return Math.floor(diff/1000) + 's ago';\n    if (diff < 3600000) return Math.floor(diff/60000) + 'm ago';\n    if (diff < 86400000) return Math.floor(diff/3600000) + 'h ago';\n    return Math.floor(diff/86400000) + 'd ago';\n}\nfunction fmtDate(iso) {\n    if (!iso) return '--';\n    return new Date(iso).toLocaleDateString('ja-JP', {month:'short', day:'numeric'});\n}\n\n/* Persona storage helpers 窶・write to both keys for backward compatibility */\nfunction getStoredPersona() {\n    return localStorage.getItem('mmcp-persona') || localStorage.getItem('selected_persona') || null;\n}\nfunction setStoredPersona(persona) {\n    localStorage.setItem('mmcp-persona', persona);\n    localStorage.setItem('selected_persona', persona);\n}\n\n/* =================================================================\n   TOAST NOTIFICATIONS\n   ================================================================= */\nfunction toast(msg, type='info') {\n    const c = document.getElementById('toast-container');\n    const t = document.createElement('div');\n    t.className = 'toast toast-' + type;\n    t.textContent = msg;\n    c.appendChild(t);\n    setTimeout(() => t.remove(), 3200);\n}\n\n/* =================================================================\n   API HELPER\n   ================================================================= */\nasync function api(path, opts={}) {\n    try {\n        const resp = await fetch(path, {\n            headers: { 'Content-Type': 'application/json', ...opts.headers },\n            ...opts\n        });\n        if (!resp.ok) {\n            const err = await resp.json().catch(() => ({error: resp.statusText}));\n            throw new Error(err.error || resp.statusText);\n        }\n        return await resp.json();\n    } catch (e) {\n        console.error('API error:', path, e);\n        throw e;\n    }\n}\n\n/* =================================================================\n   CHART HELPERS\n   ================================================================= */\nfunction destroyChart(id) {\n    if (S.charts[id]) { S.charts[id].destroy(); delete S.charts[id]; }\n}\nfunction chartOpts(extra={}) {\n    const color = getComputedStyle(document.documentElement).getPropertyValue('--text-muted').trim() || '#94a3b8';\n    return {\n        responsive: true,\n        maintainAspectRatio: false,\n        plugins: {\n            legend: { labels: { color, font: { size: 11 } } },\n            ...extra.plugins\n        },\n        scales: extra.scales ? Object.fromEntries(\n            Object.entries(extra.scales).map(([k,v]) => [k, { ...v, ticks: { color, ...(v.ticks||{}) }, grid: { color: 'rgba(167,139,250,0.08)', ...(v.grid||{}) } }])\n        ) : undefined\n    };\n}\n\n/* =================================================================\n   SKELETON HELPERS\n   ================================================================= */\nfunction skeletonCard() {\n    return '<div class=\"glass p-6\"><div class=\"skeleton skeleton-title\"></div><div class=\"skeleton skeleton-text\" style=\"width:80%\"></div><div class=\"skeleton skeleton-text\" style=\"width:60%\"></div></div>';\n}\nfunction errorCard(msg) {\n    return '<div class=\"glass p-6 text-center\" style=\"color:var(--accent-red)\"><p style=\"font-size:1.2rem;margin-bottom:8px\">笞・・/p><p>' + esc(msg) + '</p></div>';\n}\n\n/* =================================================================\n   THEME TOGGLE\n   ================================================================= */\nfunction applyTheme() {\n    const dark = localStorage.getItem('mmcp-dark') !== 'false';\n    document.documentElement.className = dark ? 'dark' : 'light';\n    document.getElementById('dark-toggle').textContent = dark ? '嫌' : '笘・・;\n    // Re-render charts for color update\n    Object.values(S.charts).forEach(c => c.update());\n}\nfunction toggleTheme() {\n    const isDark = document.documentElement.classList.contains('dark');\n    localStorage.setItem('mmcp-dark', isDark ? 'false' : 'true');\n    applyTheme();\n}\n\n/* =================================================================\n   SKELETON LOADING\n   ================================================================= */\nfunction showSkeleton(tabId) {\n    const container = document.getElementById('tab-' + tabId);\n    if (!container) return;\n    const skeletons = {\n        overview: '<div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6\">'\n            + '<div class=\"skeleton skeleton-card glass\"></div>'.repeat(4)\n            + '</div><div class=\"grid grid-cols-1 lg:grid-cols-2 gap-6\">'\n            + '<div class=\"skeleton glass\" style=\"height:200px\"></div>'.repeat(2) + '</div>',\n        analytics: '<div class=\"skeleton skeleton-chart glass mb-6\"></div>'\n            + '<div class=\"grid grid-cols-1 md:grid-cols-2 gap-4\">'\n            + '<div class=\"skeleton glass\" style=\"height:200px\"></div>'.repeat(2) + '</div>',\n        memories: '<div class=\"skeleton skeleton-line mb-4\" style=\"height:48px\"></div>'\n            + '<div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4\">'\n            + '<div class=\"skeleton skeleton-card glass\"></div>'.repeat(6) + '</div>',\n        settings: '<div class=\"skeleton glass mb-4\" style=\"height:160px\"></div>'.repeat(3),\n        graph: '<div class=\"skeleton glass\" style=\"height:600px\"></div>',\n        'import-export': '<div class=\"skeleton glass mb-4\" style=\"height:200px\"></div>'\n            + '<div class=\"skeleton glass\" style=\"height:200px\"></div>',\n        personas: '<div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4\">'\n            + '<div class=\"skeleton skeleton-card glass\"></div>'.repeat(3) + '</div>',\n        admin: '<div class=\"skeleton glass\" style=\"height:300px\"></div>',\n        timeline: '<div class=\"skeleton glass\" style=\"height:500px\"></div>'\n    };\n    /* graph / import-export / personas / chat / timeline manage their own loading state via\n       inner elements (#graph-loading, #persona-grid, #export-preview, #chat-messages, #tl-loading).\n       Replacing their innerHTML would destroy those elements and cause\n       silent failures in the corresponding load functions. */\n    if (tabId === 'graph' || tabId === 'import-export' || tabId === 'personas' || tabId === 'chat' || tabId === 'timeline') return;\n    const content = container.querySelector('[id$=\"-content\"]') || container;\n    content.innerHTML = skeletons[tabId] || '<div class=\"skeleton skeleton-card glass\"></div>';\n}\n\n/* =================================================================\n   TAB SWITCHING\n   ================================================================= */\nfunction switchTab(tab) {\n    S.tab = tab;\n    localStorage.setItem('mmcp-tab', tab);\n    document.querySelectorAll('.tab-btn').forEach(b => {\n        const isActive = b.dataset.tab === tab;\n        b.classList.toggle('active', isActive);\n        b.setAttribute('aria-selected', isActive);\n    });\n    document.querySelectorAll('.tab-panel').forEach(p => {\n        p.classList.toggle('active', p.id === 'tab-' + tab);\n    });\n    showSkeleton(tab);\n    loadTab(tab);\n}\nfunction loadTab(tab) {\n    if (!S.persona && tab !== 'settings' && tab !== 'personas') return;\n    switch(tab) {\n        case 'overview': loadOverview(); break;\n        case 'analytics': loadAnalytics(); break;\n        case 'memories': loadMemories(); break;\n        case 'graph': loadGraph(); break;\n        case 'import-export': loadImportExport(); break;\n        case 'personas': loadPersonas(); break;\n        case 'settings': loadSettings(); break;\n        case 'chat': loadChat(); break;\n        case 'admin': loadAdmin(); break;\n    }\n}\n\n/* =================================================================\n   MEMORY DETAIL MODAL\n   ================================================================= */\nfunction openMemModal(mem) {\n    const overlay = document.getElementById('mem-modal-overlay');\n    const content = document.getElementById('mem-modal-content');\n    const tags = (mem.tags || []).map(t => '<span class=\"badge badge-purple\">' + esc(t) + '</span>').join(' ');\n    const emoHtml = mem.emotion_type ? '<span class=\"badge badge-pink\">・ ' + esc(mem.emotion_type) + (mem.emotion_intensity != null ? ' (' + (mem.emotion_intensity * 100).toFixed(0) + '%)' : '') + '</span>' : '';\n    content.innerHTML = `\n        <div class=\"mem-modal-header\">\n            <div>\n                <div style=\"font-size:0.7rem;color:var(--text-muted);margin-bottom:4px\">Memory Key</div>\n                <div style=\"font-family:monospace;font-size:0.85rem;color:var(--accent-purple)\">${esc(mem.memory_key)}</div>\n            </div>\n            <button class=\"mem-modal-close\" onclick=\"closeMemModal()\">笨・/button>\n        </div>\n        <div class=\"mem-modal-content\">${esc(mem.content)}</div>\n        <div>\n            ${tags || emoHtml ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Tags/Emotion</span><span>${tags} ${emoHtml}</span></div>` : ''}\n            ${mem.importance != null ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Importance</span><span style=\"color:var(--accent-yellow)\">${(mem.importance).toFixed(2)}</span></div>` : ''}\n            ${mem.strength != null ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Strength</span><span style=\"color:var(--accent-green)\">笞｡${(mem.strength).toFixed(3)}</span></div>` : ''}\n            ${mem.privacy_level ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Privacy</span><span>${esc(mem.privacy_level)}</span></div>` : ''}\n            ${mem.source_context ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Source</span><span style=\"color:var(--text-muted)\">${esc(mem.source_context)}</span></div>` : ''}\n            ${mem.created_at ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Created</span><span>套 ${relativeTime(mem.created_at)} <span style=\"color:var(--text-muted);font-size:0.75rem\">(${new Date(mem.created_at).toLocaleString('ja-JP')})</span></span></div>` : ''}\n            ${mem.updated_at ? `<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Updated</span><span>套 ${relativeTime(mem.updated_at)}</span></div>` : ''}\n        </div>`;\n    overlay.style.display = 'flex';\n    overlay.classList.add('show');\n    document.addEventListener('keydown', _memModalKeyHandler);\n}\nfunction closeMemModal() {\n    const overlay = document.getElementById('mem-modal-overlay');\n    overlay.classList.remove('show');\n    setTimeout(() => { overlay.style.display = 'none'; }, 220);\n    document.removeEventListener('keydown', _memModalKeyHandler);\n}\nfunction _memModalKeyHandler(e) { if (e.key === 'Escape') closeMemModal(); }\n\n/* =================================================================\n   LAST UPDATE TIMESTAMP\n   ================================================================= */\nfunction updateLastTime() {\n    const el = document.getElementById('last-update');\n    if (el) el.textContent = 'Last: ' + new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit', second: '2-digit' });\n}\n\n/* =================================================================\n   AUTO REFRESH\n   ================================================================= */\nfunction setAutoRefresh(sec) {\n    if (S.refreshTimer) { clearInterval(S.refreshTimer); S.refreshTimer = null; }\n    if (sec > 0) {\n        S.refreshTimer = setInterval(() => loadTab(S.tab), sec * 1000);\n    }\n}\n\n/* =================================================================\n   INITIALIZATION\n   ================================================================= */\nasync function init() {\n    // Theme\n    applyTheme();\n\n    // Load personas\n    try {\n        const data = await api('/api/personas');\n        const personas = data.personas || [];\n        const sel = document.getElementById('persona-select');\n        sel.innerHTML = '';\n        if (personas.length === 0) {\n            sel.innerHTML = '<option value=\"\">No personas found</option>';\n            document.getElementById('overview-content').innerHTML =\n                '<div class=\"glass p-8 text-center\"><div style=\"font-size:2rem;margin-bottom:12px\">､ｷ</div><p style=\"color:var(--text-secondary)\">No personas found. Create a persona to get started.</p></div>';\n            return;\n        }\n        personas.forEach(p => {\n            const opt = document.createElement('option');\n            opt.value = p; opt.textContent = p;\n            sel.appendChild(opt);\n        });\n        // 蜆ｪ蜈亥ｺｦ: __INITIAL_PERSONA__ > localStorage > personas[0]\n        const savedPersona = localStorage.getItem('mmcp-persona');\n        let _target = null;\n        if (window.__INITIAL_PERSONA__) {\n            _target = window.__INITIAL_PERSONA__;\n        } else if (savedPersona && personas.some(p => (p.id || p) === savedPersona)) {\n            _target = savedPersona;\n        } else {\n            _target = personas[0]?.id || personas[0];\n        }\n        S.persona = _target;\n        sel.value = _target;\n        switchTab(S.tab);\n    } catch (e) {\n        toast('Failed to load personas: ' + e.message, 'error');\n    }\n\n    // Event: Persona change\n    document.getElementById('persona-select').onchange = (e) => {\n        S.persona = e.target.value;\n        S.dashCache = null;\n        // Reset pagination/search without losing extended properties from memories.js\n        Object.assign(S.mem, { page: 1, tag: '', q: '', perPage: 20,\n            selectMode: false, advOpen: false, dateFrom: '', dateTo: '',\n            searchTags: [], emotion: '' });\n        if (S.mem.selected instanceof Set) S.mem.selected.clear();\n        loadTab(S.tab);\n    };\n\n    // Event: Tab switch\n    document.querySelectorAll('.tab-btn').forEach(btn => {\n        btn.addEventListener('click', () => switchTab(btn.dataset.tab));\n    });\n\n    // Event: Refresh button\n    document.getElementById('refresh-btn').onclick = () => {\n        S.dashCache = null;\n        loadTab(S.tab);\n    };\n\n    // Event: Auto-refresh\n    document.getElementById('auto-refresh').onchange = (e) => {\n        setAutoRefresh(parseInt(e.target.value));\n    };\n\n    // Event: Theme toggle\n    document.getElementById('dark-toggle').onclick = toggleTheme;\n\n    // Keyboard: tab navigation\n    document.addEventListener('keydown', (e) => {\n        if (e.altKey && ((e.key >= '1' && e.key <= '9') || e.key === '0')) {\n            e.preventDefault();\n            const tabs = ['overview','analytics','memories','timeline','graph','import-export','personas','chat','settings','admin'];\n            const idx = e.key === '0' ? 9 : parseInt(e.key) - 1;\n            switchTab(tabs[idx]);\n        }\n    });\n}\n\n/* =================================================================\n   COUNT-UP ANIMATION\n   ================================================================= */\nfunction animateCount(el, target, duration) {\n    duration = duration || 800;\n    const startTime = performance.now();\n    function update(currentTime) {\n        const elapsed = currentTime - startTime;\n        const progress = Math.min(elapsed / duration, 1);\n        const eased = 1 - Math.pow(1 - progress, 3);\n        el.textContent = Math.round(target * eased).toLocaleString();\n        if (progress < 1) requestAnimationFrame(update);\n    }\n    requestAnimationFrame(update);\n}\n\n/* =================================================================\n   STAGGERED CARD ANIMATION\n   ================================================================= */\nfunction animateCards(container) {\n    if (!container) return;\n    const cards = container.querySelectorAll('.glass');\n    cards.forEach(function(card, i) {\n        card.style.opacity = '0';\n        card.style.transform = 'translateY(16px)';\n        setTimeout(function() {\n            card.style.transition = 'opacity 0.4s ease, transform 0.4s ease';\n            card.style.opacity = '1';\n            card.style.transform = 'translateY(0)';\n        }, i * 60);\n    });\n}\n\n/* =================================================================\n   MOBILE NAV TOGGLE\n   ================================================================= */\nfunction toggleMobileNav() {\n    const nav = document.querySelector('.tab-bar');\n    if (nav) nav.classList.toggle('mobile-open');\n}\n\n/* =================================================================\n   KEYBOARD SHORTCUTS (Ctrl+F / Escape)\n   ================================================================= */\ndocument.addEventListener('keydown', function(e) {\n    if ((e.ctrlKey || e.metaKey) && e.key === 'f') {\n        var searchInput = document.querySelector('.tab-panel.active input[type=\"text\"][placeholder*=\"earch\"]');\n        if (searchInput) { e.preventDefault(); searchInput.focus(); }\n    }\n    if (e.key === 'Escape') {\n        document.querySelectorAll('.mem-modal-overlay').forEach(function(m) {\n            m.style.display = 'none';\n            m.classList.remove('show');\n        });\n    }\n});\n\n/* =================================================================\n   ARIA LABELS ON LOAD\n   ================================================================= */\ndocument.addEventListener('DOMContentLoaded', function() {\n    document.querySelectorAll('.tab-btn').forEach(function(btn, i) {\n        btn.setAttribute('role', 'tab');\n        btn.setAttribute('aria-label', btn.textContent.trim());\n        btn.setAttribute('tabindex', '0');\n    });\n    document.querySelectorAll('.tab-panel').forEach(function(tab) {\n        tab.setAttribute('role', 'tabpanel');\n    });\n    var tablist = document.querySelector('.tab-bar');\n    if (tablist) tablist.setAttribute('role', 'tablist');\n});\n\n// Boot\ninit();\n\n\n\n// --- Block CRUD helpers (global scope) ---\nfunction showCreateBlock() {\n    document.getElementById('block-modal-title').textContent = '笨擾ｸ・New Block';\n    document.getElementById('block-modal-mode').value = 'create';\n    document.getElementById('block-modal-name').value = '';\n    document.getElementById('block-modal-name').disabled = false;\n    document.getElementById('block-modal-content').value = '';\n    document.getElementById('block-modal-priority').value = '0';\n    document.getElementById('block-edit-modal').style.display = 'flex';\n}\n\nfunction showEditBlock(name, content, priority) {\n    document.getElementById('block-modal-title').textContent = '笨擾ｸ・Edit Block: ' + name;\n    document.getElementById('block-modal-mode').value = 'edit';\n    document.getElementById('block-modal-name').value = name;\n    document.getElementById('block-modal-name').disabled = true;\n    document.getElementById('block-modal-content').value = content || '';\n    document.getElementById('block-modal-priority').value = priority || 0;\n    document.getElementById('block-edit-modal').style.display = 'flex';\n}\n\nfunction hideBlockModal() {\n    document.getElementById('block-edit-modal').style.display = 'none';\n}\n\nasync function saveBlock() {\n    var name = document.getElementById('block-modal-name').value.trim();\n    var content = document.getElementById('block-modal-content').value.trim();\n    var priority = parseInt(document.getElementById('block-modal-priority').value) || 0;\n    if (!name || !content) { toast('Block name and content required', 'error'); return; }\n    try {\n        await api('/api/blocks/' + encodeURIComponent(S.persona), {\n            method: 'POST',\n            headers: {'Content-Type': 'application/json'},\n            body: JSON.stringify({block_name: name, content: content, priority: priority})\n        });\n        hideBlockModal();\n        toast('Block saved!', 'success');\n        loadOverview();\n    } catch (e) { toast('Failed to save block: ' + e.message, 'error'); }\n}\n\nasync function deleteBlock(name) {\n    if (!confirm('Delete block \"' + name + '\"?')) return;\n    try {\n        await api('/api/blocks/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(name), {method: 'DELETE'});\n        toast('Block deleted', 'success');\n        loadOverview();\n    } catch (e) { toast('Failed: ' + e.message, 'error'); }\n}\n\n// --- Inventory CRUD helpers (global scope) ---\nasync function deleteItem(itemName) {\n    if (!confirm('Delete item: ' + itemName + '?')) return;\n    try {\n        await api('/api/items/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(itemName), {method:'DELETE'});\n        loadOverview();\n    } catch (e) {\n        alert('Failed to delete item: ' + e.message);\n    }\n}\n\nfunction openAddItemModal() {\n    const m = document.getElementById('add-item-modal');\n    if (m) { m.style.display = 'flex'; }\n}\n\nfunction closeAddItemModal() {\n    const m = document.getElementById('add-item-modal');\n    if (m) { m.style.display = 'none'; }\n    ['new-item-name','new-item-category','new-item-desc','new-item-qty'].forEach(id => {\n        const el = document.getElementById(id);\n        if (el) el.value = id === 'new-item-qty' ? '1' : '';\n    });\n}\n\nasync function saveNewItem() {\n    const nameEl = document.getElementById('new-item-name');\n    const name = (nameEl ? nameEl.value : '').trim();\n    if (!name) { alert('Item name is required'); return; }\n    const category = (document.getElementById('new-item-category') || {}).value || '';\n    const desc = (document.getElementById('new-item-desc') || {}).value || '';\n    const qty = parseInt((document.getElementById('new-item-qty') || {}).value || '1', 10) || 1;\n    try {\n        await api('/api/items/' + encodeURIComponent(S.persona), {\n            method: 'POST',\n            headers: {'Content-Type':'application/json'},\n            body: JSON.stringify({item_name: name, category: category || null, description: desc || null, quantity: qty})\n        });\n        closeAddItemModal();\n        loadOverview();\n    } catch (e) {\n        alert('Failed to add item: ' + e.message);\n    }\n}\n\nasync function changeEquipSlot(slot, itemName) {\n    try {\n        const body = {};\n        body[slot] = itemName;\n        await api('/api/items/' + encodeURIComponent(S.persona) + '/equip', {\n            method: 'POST',\n            headers: {'Content-Type':'application/json'},\n            body: JSON.stringify(body)\n        });\n        loadOverview();\n    } catch (e) {\n        alert('Failed to change equipment: ' + e.message);\n    }\n}\n\nasync function unequipSlot(slot) {\n    try {\n        await api('/api/items/' + encodeURIComponent(S.persona) + '/unequip', {\n            method: 'POST',\n            headers: {'Content-Type':'application/json'},\n            body: JSON.stringify({slots: [slot]})\n        });\n        loadOverview();\n    } catch (e) {\n        alert('Failed to unequip: ' + e.message);\n    }\n}\n\nasync function loadOverview() {\n    const el = document.getElementById('overview-content');\n    try {\n        const data = await api('/api/dashboard/' + encodeURIComponent(S.persona));\n        S.dashCache = data;\n        const stats = data.stats || {};\n        const ctx = data.context || {};\n        const equip = data.equipment || {};\n        const items = data.items || [];\n        const str = data.strengths || {};\n\n        // --- Build tag/emotion distributions from stats ---\n        const tagDist = stats.tag_distribution || {};\n        const emoDist = stats.emotion_distribution || {};\n        const topTags = Object.entries(tagDist).sort((a,b) => b[1]-a[1]).slice(0,5);\n        const topEmo = Object.entries(emoDist).sort((a,b) => b[1]-a[1]).slice(0,5);\n\n        // --- Memory Type Distribution (decision/milestone/preference/problem/emotional) ---\n        const MEMORY_TYPES = {\n            'decision':  {color: 'badge-blue',   icon: 'ｧｭ'},\n            'milestone': {color: 'badge-green',  icon: '醇'},\n            'preference':{color: 'badge-purple', icon: '凋'},\n            'problem':   {color: 'badge-red',    icon: '笞・・},\n            'emotional': {color: 'badge-pink',   icon: '猪'},\n        };\n        const memTypeCounts = {};\n        Object.entries(MEMORY_TYPES).forEach(([k]) => {\n            if (tagDist[k]) memTypeCounts[k] = tagDist[k];\n        });\n        const hasMemTypes = Object.keys(memTypeCounts).length > 0;\n\n        // --- Equipment display ---\n        const EQUIP_SLOTS = ['top','bottom','shoes','outer','accessories','head'];\n        let equipHtml = '<div style=\"display:grid;gap:6px;margin-top:8px\">';\n        EQUIP_SLOTS.forEach(slot => {\n            const current = equip[slot];\n            const itemName = typeof current === 'string' ? current : (current ? (current.name || '') : '');\n            equipHtml += '<div style=\"display:flex;align-items:center;gap:8px\">';\n            equipHtml += '<span class=\"badge badge-blue\" style=\"min-width:80px;text-align:center\">' + esc(slot) + '</span>';\n            if (itemName) {\n                equipHtml += '<span style=\"flex:1;font-size:0.85rem;color:var(--text-secondary)\">' + esc(itemName) + '</span>';\n                equipHtml += '<button data-slot=\"' + esc(slot) + '\" onclick=\"unequipSlot(this.dataset.slot)\" style=\"font-size:0.72rem;padding:2px 8px;border-radius:4px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.05);color:var(--text-muted);cursor:pointer\" title=\"Unequip\">笨・/button>';\n            } else {\n                equipHtml += '<span style=\"flex:1;font-size:0.82rem;color:var(--text-muted);font-style:italic\">empty</span>';\n                const slotItems = items.filter(it => it.name);\n                if (slotItems.length > 0) {\n                    equipHtml += '<select data-slot=\"' + esc(slot) + '\" onchange=\"if(this.value) changeEquipSlot(this.dataset.slot, this.value)\" style=\"font-size:0.78rem;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.15);border-radius:4px;color:var(--text-secondary);padding:2px 4px\"><option value=\"\">equip...</option>';\n                    slotItems.forEach(it => { equipHtml += '<option value=\"' + esc(it.name) + '\">' + esc(it.name) + '</option>'; });\n                    equipHtml += '</select>';\n                }\n            }\n            equipHtml += '</div>';\n        });\n        equipHtml += '</div>';\n\n        // --- Core blocks ---\n        let blocksHtml = '';\n        if (data.blocks && data.blocks.length > 0) {\n            data.blocks.forEach(b => {\n                const name = typeof b === 'string' ? b : (b.name || b.block_name || 'block');\n                const content = typeof b === 'object' ? (b.content || b.value || '') : '';\n                const priority = typeof b === 'object' ? b.priority : null;\n                blocksHtml += '<div style=\"padding:10px 0;border-bottom:1px solid rgba(255,255,255,0.05)\">';\n                blocksHtml += '<div style=\"display:flex;align-items:center;gap:8px;margin-bottom:4px\">';\n                blocksHtml += '<span style=\"font-weight:600;color:var(--accent-purple);font-size:0.85rem\">' + esc(name) + '</span>';\n                if (priority != null) blocksHtml += '<span class=\"badge badge-yellow\">P' + esc(String(priority)) + '</span>';\n                blocksHtml += '<div style=\"display:flex;gap:6px;margin-left:auto\">';\n                blocksHtml += '<button class=\"glass-btn\" data-bname=\"' + esc(name) + '\" data-bcontent=\"' + esc(content) + '\" data-bpriority=\"' + (priority || 0) + '\" onclick=\"var el=this;showEditBlock(el.dataset.bname,el.dataset.bcontent,parseInt(el.dataset.bpriority||0))\" style=\"padding:3px 10px;font-size:0.75rem\">笨擾ｸ・Edit</button>';\n                blocksHtml += '<button class=\"glass-btn\" data-bname=\"' + esc(name) + '\" onclick=\"deleteBlock(this.dataset.bname)\" style=\"padding:3px 10px;font-size:0.75rem;color:var(--accent-red)\">&#128465; Delete</button>';\n                blocksHtml += '</div>';\n                blocksHtml += '</div>';\n                if (content) blocksHtml += '<div style=\"font-size:0.82rem;color:var(--text-muted)\">' + esc(truncate(String(content), 80)) + '</div>';\n                blocksHtml += '</div>';\n            });\n        } else {\n            blocksHtml = '<span style=\"color:var(--text-muted)\">No core memory blocks</span>';\n        }\n\n        // --- Goals & Promises ---\n        function getStatusIcon(status) {\n            if (status === 'active') return '売';\n            if (status === 'achieved' || status === 'fulfilled') return '笨・;\n            if (status === 'cancelled') return '笶・;\n            return '売';\n        }\n\n        function renderGoalItems(goalItems, label) {\n            if (!goalItems || goalItems.length === 0) return '<span style=\"color:var(--text-muted)\">No ' + label + '</span>';\n            let html = '';\n            goalItems.forEach(item => {\n                const content = typeof item === 'string' ? item : (item.content || item.description || item.title || JSON.stringify(item));\n                const status = typeof item === 'object' ? (item.status || 'active').toLowerCase() : 'active';\n                const icon = getStatusIcon(status);\n                html += '<div style=\"display:flex;align-items:center;gap:8px;padding:6px 0\">';\n                html += '<span>' + icon + '</span>';\n                html += '<span style=\"flex:1;font-size:0.85rem;color:var(--text-secondary)\">' + esc(content) + '</span>';\n                const ts = typeof item === 'object' && (item.created_at || item.date);\n                if (ts) html += '<span style=\"font-size:0.72rem;color:var(--text-muted)\">' + relativeTime(ts) + '</span>';\n                html += '</div>';\n            });\n            return html;\n        }\n\n        const effectiveGoals = data.goals || [];\n        const effectivePromises = data.promises || [];\n\n        // --- Profile: user_info / persona_info / relationship ---\n        const userInfo = ctx.user_info || {};\n        const personaInfo = ctx.persona_info || {};\n        const relStatus = ctx.relationship_status || ctx.relationship_type || '--';\n\n        // --- Inventory items HTML ---\n        let invHtml = '';\n        if (items.length === 0) {\n            invHtml = '<span style=\"color:var(--text-muted)\">No items in inventory</span>';\n        } else {\n            invHtml = '<div style=\"display:grid;gap:4px\">';\n            items.forEach(it => {\n                const desc = it.description || '';\n                const truncDesc = desc.length > 40 ? desc.slice(0, 40) + '...' : desc;\n                invHtml += '<div style=\"display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid rgba(255,255,255,0.04)\">';\n                invHtml += '<span class=\"badge badge-blue\">' + esc(it.category || 'item') + '</span>';\n                invHtml += '<span style=\"flex:1;font-size:0.85rem;color:var(--text-secondary)\" title=\"' + esc(desc) + '\">' + esc(it.name) + '</span>';\n                if (it.quantity > 1) invHtml += '<span style=\"font-size:0.78rem;color:var(--text-muted)\">x' + it.quantity + '</span>';\n                if (truncDesc) invHtml += '<span class=\"badge badge-purple\" title=\"' + esc(desc) + '\">' + esc(truncDesc) + '</span>';\n                invHtml += '<button data-item=\"' + esc(it.name) + '\" onclick=\"deleteItem(this.dataset.item)\" style=\"padding:2px 8px;border-radius:4px;border:1px solid rgba(255,100,100,0.3);background:rgba(255,100,100,0.08);color:#f87171;cursor:pointer;font-size:0.78rem\" title=\"Delete item\">卵・・/button>';\n                invHtml += '</div>';\n            });\n            invHtml += '</div>';\n        }\n\n        // --- Recent memories grouped by date (for 7-day chart) ---\n        const recent = data.recent || [];\n        const dayMap = {};\n        const now = new Date();\n        for (let i = 6; i >= 0; i--) {\n            const d = new Date(now); d.setDate(d.getDate() - i);\n            dayMap[d.toISOString().slice(0,10)] = 0;\n        }\n        recent.forEach(m => {\n            const d = (m.created_at || '').slice(0,10);\n            if (d in dayMap) dayMap[d]++;\n        });\n        // Augment with stats if available\n        if (stats.daily_counts) {\n            Object.entries(stats.daily_counts).forEach(([d, c]) => { if (d in dayMap) dayMap[d] = c; });\n        }\n        const dayLabels = Object.keys(dayMap).map(d => fmtDate(d));\n        const dayCounts = Object.values(dayMap);\n\n        // --- Render (new section order) ---\n        el.innerHTML = `\n        <!-- Goals & Promises -->\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\">識 Goals & Promises</div>\n            <div class=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n                <div>\n                    <div style=\"font-size:0.8rem;font-weight:600;color:var(--accent-green);margin-bottom:8px\">Goals</div>\n                    ${renderGoalItems(effectiveGoals, 'goals')}\n                </div>\n                <div>\n                    <div style=\"font-size:0.8rem;font-weight:600;color:var(--accent-pink);margin-bottom:8px\">Promises</div>\n                    ${renderGoalItems(effectivePromises, 'promises')}\n                </div>\n            </div>\n        </div>\n        <!-- Emotion / State -->\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\">牒 Emotion &amp; State</div>\n            <div class=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n                <div>\n                    <div style=\"font-size:2rem;font-weight:700;color:var(--accent-yellow);margin-bottom:4px\">${esc(ctx.emotion || '--')}</div>\n                    <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:12px\">Emotion${ctx.emotion_intensity != null ? ' ﾂｷ ' + (ctx.emotion_intensity * 100).toFixed(0) + '% intensity' : ''}</div>\n                    <div style=\"display:flex;flex-direction:column;gap:6px\">\n                        <div><span style=\"font-size:0.78rem;color:var(--text-muted)\">Physical: </span><span style=\"font-size:0.85rem\">${esc(ctx.physical_state || '--')}</span></div>\n                        <div><span style=\"font-size:0.78rem;color:var(--text-muted)\">Mental: </span><span style=\"font-size:0.85rem\">${esc(ctx.mental_state || '--')}</span></div>\n                        <div style=\"display:flex;align-items:center;gap:6px;flex-wrap:wrap\"><span style=\"font-size:0.78rem;color:var(--text-muted);min-width:78px\">訣 Env:</span>${stats.environment ? '<span class=\"badge badge-blue\">' + esc(stats.environment) + '</span>' : '<span style=\"color:var(--text-muted);font-size:0.82rem\">--</span>'}</div>\n                        <div style=\"display:flex;align-items:center;gap:6px;flex-wrap:wrap\"><span style=\"font-size:0.78rem;color:var(--text-muted);min-width:78px\">汐 Action:</span>${stats.action_tag ? '<span class=\"badge badge-green\">' + esc(stats.action_tag) + '</span>' : '<span style=\"color:var(--text-muted);font-size:0.82rem\">--</span>'}</div>\n                        <div style=\"display:flex;align-items:center;gap:6px;flex-wrap:wrap\"><span style=\"font-size:0.78rem;color:var(--text-muted);min-width:78px\">町 Speech:</span>${stats.speech_style ? '<span class=\"badge badge-purple\">' + esc(stats.speech_style) + '</span>' : '<span style=\"color:var(--text-muted);font-size:0.82rem\">--</span>'}</div>\n                    </div>\n                </div>\n                <div>\n                    <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:8px;font-weight:600\">Equipment</div>\n                    ${equipHtml}\n                </div>\n            </div>\n            <div style=\"margin-top:16px;border-top:1px solid rgba(255,255,255,0.06);padding-top:14px\">\n                <div style=\"font-size:0.78rem;color:var(--text-muted);font-weight:600;margin-bottom:10px\">Body Sensations</div>\n                <div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:16px\">\n                    <div>\n                        <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:5px\">\n                            <span style=\"font-size:0.78rem;color:var(--text-muted)\">櫨 Fatigue</span>\n                            <span style=\"font-size:0.78rem;color:var(--text-secondary);font-weight:600\">${stats.fatigue != null ? (stats.fatigue * 100).toFixed(0) + '%' : '--'}</span>\n                        </div>\n                        <div style=\"height:6px;background:rgba(255,255,255,0.08);border-radius:3px;overflow:hidden\">\n                            <div style=\"height:100%;width:${stats.fatigue != null ? (stats.fatigue * 100).toFixed(1) : 0}%;background:linear-gradient(90deg,#f87171,#fca5a5);border-radius:3px;transition:width 0.4s ease\"></div>\n                        </div>\n                    </div>\n                    <div>\n                        <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:5px\">\n                            <span style=\"font-size:0.78rem;color:var(--text-muted)\">減 Warmth</span>\n                            <span style=\"font-size:0.78rem;color:var(--text-secondary);font-weight:600\">${stats.warmth != null ? (stats.warmth * 100).toFixed(0) + '%' : '--'}</span>\n                        </div>\n                        <div style=\"height:6px;background:rgba(255,255,255,0.08);border-radius:3px;overflow:hidden\">\n                            <div style=\"height:100%;width:${stats.warmth != null ? (stats.warmth * 100).toFixed(1) : 0}%;background:linear-gradient(90deg,#f9a8d4,#fda4af);border-radius:3px;transition:width 0.4s ease\"></div>\n                        </div>\n                    </div>\n                    <div>\n                        <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:5px\">\n                            <span style=\"font-size:0.78rem;color:var(--text-muted)\">笞｡ Arousal</span>\n                            <span style=\"font-size:0.78rem;color:var(--text-secondary);font-weight:600\">${stats.arousal != null ? (stats.arousal * 100).toFixed(0) + '%' : '--'}</span>\n                        </div>\n                        <div style=\"height:6px;background:rgba(255,255,255,0.08);border-radius:3px;overflow:hidden\">\n                            <div style=\"height:100%;width:${stats.arousal != null ? (stats.arousal * 100).toFixed(1) : 0}%;background:linear-gradient(90deg,#a78bfa,#c4b5fd);border-radius:3px;transition:width 0.4s ease\"></div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <!-- Core Memory Blocks -->\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\" style=\"justify-content:space-between\">\n                <span>&#129504; Core Memory Blocks</span>\n                <button onclick=\"showCreateBlock()\" class=\"glass-btn\" style=\"padding:4px 12px;font-size:0.78rem\">&#65291; New Block</button>\n            </div>\n            ${blocksHtml}\n        </div>\n        <!-- Profile & Relationship -->\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\">側 Profile &amp; Relationship</div>\n            <div class=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n                <div>\n                    <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:8px;font-weight:600\">Relationship</div>\n                    <div style=\"font-size:0.9rem;color:var(--accent-pink);font-weight:600;margin-bottom:12px\">${esc(relStatus)}</div>\n                    ${ctx.last_conversation_time ? `<div style=\"margin-bottom:12px;display:flex;align-items:center;gap:8px\"><span style=\"font-size:0.78rem;color:var(--text-muted)\">武 Last session:</span><span class=\"badge badge-blue\">${relativeTime(ctx.last_conversation_time)}</span></div>` : ''}\n                    <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:6px;font-weight:600\">User Info</div>\n                    ${Object.entries(userInfo).length ? Object.entries(userInfo).map(([k,v]) => `<div style=\"display:flex;gap:8px;padding:4px 0;font-size:0.85rem\"><span style=\"color:var(--text-muted);min-width:120px\">${esc(k.replace(/_/g,' '))}</span><span style=\"color:var(--text-secondary)\">${esc(String(v))}</span></div>`).join('') : '<span style=\"color:var(--text-muted)\">No user info</span>'}\n                </div>\n                <div>\n                    <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:6px;font-weight:600\">Persona Info</div>\n                    ${(() => { const _GOALS_KEYS = new Set(['goals','promises','active_promises','current_goals']); const filtered = Object.entries(personaInfo).filter(([k]) => !_GOALS_KEYS.has(k)); return filtered.length ? filtered.map(([k,v]) => `<div style=\"display:flex;gap:8px;padding:4px 0;font-size:0.85rem\"><span style=\"color:var(--text-muted);min-width:120px\">${esc(k.replace(/_/g,' '))}</span><span style=\"color:var(--accent-purple)\">${esc(String(v))}</span></div>`).join('') : '<span style=\"color:var(--text-muted)\">No persona info</span>'; })()}\n                </div>\n            </div>\n        </div>\n        <!-- Memory Stats -->\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\">嶋 Memory Stats</div>\n            <div class=\"grid grid-cols-2 md:grid-cols-4 gap-4 mb-4\">\n                <div><div class=\"stat-value\">${stats.total_count ?? '--'}</div><div class=\"stat-label\">Total Memories</div></div>\n                <div><div class=\"stat-value\" style=\"color:var(--accent-green)\">${str.avg ?? '--'}</div><div class=\"stat-label\">Avg Strength</div></div>\n                <div><div class=\"stat-value\" style=\"color:var(--accent-blue)\">${stats.tagged_ratio != null ? (stats.tagged_ratio * 100).toFixed(1) + '%' : '--'}</div><div class=\"stat-label\">Tagged</div></div>\n                <div><div class=\"stat-value\" style=\"color:var(--accent-yellow)\">${stats.linked_ratio != null ? (stats.linked_ratio * 100).toFixed(1) + '%' : '--'}</div><div class=\"stat-label\">Linked</div></div>\n            </div>\n            <div style=\"margin-bottom:10px\">\n                <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:6px\">Top Tags</div>\n                <div style=\"display:flex;flex-wrap:wrap;gap:6px\">${topTags.length ? topTags.map(([t,c]) => '<span class=\"badge badge-purple\">' + esc(t) + ' <span style=\"opacity:0.7\">(' + c + ')</span></span>').join('') : '<span style=\"color:var(--text-muted)\">--</span>'}</div>\n            </div>\n            ${hasMemTypes ? `<div style=\"margin-bottom:10px\">\n                <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:6px\">Memory Types</div>\n                <div style=\"display:flex;flex-wrap:wrap;gap:6px\">${Object.entries(memTypeCounts).map(([t,c]) => '<span class=\"badge ' + MEMORY_TYPES[t].color + '\">' + MEMORY_TYPES[t].icon + ' ' + esc(t) + ' <span style=\"opacity:0.7\">(' + c + ')</span></span>').join('')}</div>\n            </div>` : ''}\n            <div>\n                <div style=\"font-size:0.78rem;color:var(--text-muted);margin-bottom:6px\">Top Emotions</div>\n                <div style=\"display:flex;flex-wrap:wrap;gap:6px\">${topEmo.length ? topEmo.map(([e,c]) => '<span class=\"badge badge-pink\">' + esc(e) + ' <span style=\"opacity:0.7\">(' + c + ')</span></span>').join('') : '<span style=\"color:var(--text-muted)\">--</span>'}</div>\n            </div>\n        </div>\n        <!-- Inventory -->\n        <div class=\"glass p-6 mb-6\">\n            <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:12px\">\n                <div class=\"card-title\" style=\"margin-bottom:0\">賜 Inventory</div>\n                <button onclick=\"openAddItemModal()\" style=\"padding:4px 14px;border-radius:6px;border:1px solid rgba(167,139,250,0.4);background:rgba(167,139,250,0.1);color:var(--accent-purple);cursor:pointer;font-size:0.82rem;font-weight:600\">+ Add Item</button>\n            </div>\n            ${invHtml}\n        </div>\n        <!-- Charts -->\n        <div class=\"grid grid-cols-1 lg:grid-cols-2 gap-6\">\n            <div class=\"glass p-6\">\n                <div class=\"card-title\">套 7-Day Timeline</div>\n                <div style=\"height:220px;position:relative\"><canvas id=\"chart-timeline\"></canvas></div>\n            </div>\n            <div class=\"glass p-6\">\n                <div class=\"card-title\">捷・・Tag Distribution</div>\n                <div style=\"height:220px;position:relative\"><canvas id=\"chart-tags\"></canvas></div>\n            </div>\n        </div>\n        <!-- Add Item Modal -->\n        <div id=\"add-item-modal\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:1000;align-items:center;justify-content:center\">\n            <div style=\"background:#1e1b2e;border:1px solid rgba(167,139,250,0.3);border-radius:14px;padding:28px;width:420px;max-width:92vw;box-shadow:0 24px 64px rgba(0,0,0,0.6)\">\n                <div style=\"font-weight:700;font-size:1.05rem;margin-bottom:18px;color:var(--accent-purple)\">筐・Add Inventory Item</div>\n                <div style=\"display:flex;flex-direction:column;gap:12px\">\n                    <input id=\"new-item-name\" type=\"text\" placeholder=\"Item name *\" style=\"width:100%;padding:8px 12px;border-radius:7px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.07);color:var(--text-primary);font-size:0.88rem;outline:none;box-sizing:border-box\">\n                    <input id=\"new-item-category\" type=\"text\" placeholder=\"Category (e.g. clothing, weapon)\" style=\"width:100%;padding:8px 12px;border-radius:7px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.07);color:var(--text-primary);font-size:0.88rem;outline:none;box-sizing:border-box\">\n                    <input id=\"new-item-desc\" type=\"text\" placeholder=\"Description\" style=\"width:100%;padding:8px 12px;border-radius:7px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.07);color:var(--text-primary);font-size:0.88rem;outline:none;box-sizing:border-box\">\n                    <input id=\"new-item-qty\" type=\"number\" value=\"1\" min=\"1\" placeholder=\"Quantity\" style=\"width:100%;padding:8px 12px;border-radius:7px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.07);color:var(--text-primary);font-size:0.88rem;outline:none;box-sizing:border-box\">\n                </div>\n                <div style=\"display:flex;gap:10px;justify-content:flex-end;margin-top:20px\">\n                    <button onclick=\"closeAddItemModal()\" style=\"padding:7px 18px;border-radius:7px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.05);color:var(--text-muted);cursor:pointer;font-size:0.88rem\">Cancel</button>\n                    <button onclick=\"saveNewItem()\" style=\"padding:7px 18px;border-radius:7px;border:1px solid rgba(167,139,250,0.5);background:rgba(167,139,250,0.2);color:var(--accent-purple);cursor:pointer;font-size:0.88rem;font-weight:600\">Save</button>\n                </div>\n            </div>\n        </div>\n        <!-- Block Edit Modal -->\n        <div id=\"block-edit-modal\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.6);backdrop-filter:blur(8px);z-index:1000;align-items:center;justify-content:center\">\n            <div class=\"glass p-6\" style=\"max-width:500px;width:90%;border-radius:16px;max-height:80vh;overflow-y:auto\">\n                <h3 style=\"font-size:1.2rem;font-weight:600;color:var(--text-primary);margin-bottom:16px\">\n                    <span id=\"block-modal-title\">&#9999;&#65039; New Block</span></h3>\n                <input type=\"hidden\" id=\"block-modal-mode\" value=\"create\">\n                <div style=\"margin-bottom:12px\">\n                    <label style=\"display:block;font-size:0.85rem;color:var(--text-muted);margin-bottom:4px\">Block Name</label>\n                    <input type=\"text\" id=\"block-modal-name\" class=\"glass-input\" style=\"width:100%;padding:8px 12px;box-sizing:border-box\" placeholder=\"e.g. system_notes\">\n                </div>\n                <div style=\"margin-bottom:12px\">\n                    <label style=\"display:block;font-size:0.85rem;color:var(--text-muted);margin-bottom:4px\">Content</label>\n                    <textarea id=\"block-modal-content\" class=\"glass-input\" rows=\"6\" style=\"width:100%;padding:8px 12px;box-sizing:border-box;resize:vertical\"></textarea>\n                </div>\n                <div style=\"margin-bottom:16px\">\n                    <label style=\"display:block;font-size:0.85rem;color:var(--text-muted);margin-bottom:4px\">Priority (0-100)</label>\n                    <input type=\"number\" id=\"block-modal-priority\" class=\"glass-input\" style=\"width:100%;padding:8px 12px;box-sizing:border-box\" value=\"0\" min=\"0\" max=\"100\">\n                </div>\n                <div style=\"display:flex;gap:12px;justify-content:flex-end\">\n                    <button onclick=\"hideBlockModal()\" class=\"glass-btn\" style=\"padding:8px 20px\">Cancel</button>\n                    <button onclick=\"saveBlock()\" class=\"glass-btn\" style=\"padding:8px 20px;background:var(--accent);color:white\">Save</button>\n                </div>\n            </div>\n        </div>`;\n\n        // --- Charts ---\n        destroyChart('chart-timeline');\n        destroyChart('chart-tags');\n        const tlCtx = document.getElementById('chart-timeline');\n        if (tlCtx) {\n            S.charts['chart-timeline'] = new Chart(tlCtx, {\n                type: 'bar',\n                data: { labels: dayLabels, datasets: [{ label: 'Memories', data: dayCounts, backgroundColor: 'rgba(167,139,250,0.5)', borderColor: '#a78bfa', borderWidth: 1, borderRadius: 6 }] },\n                options: chartOpts({ plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } }, x: {} } })\n            });\n        }\n        const allTags = Object.entries(tagDist).sort((a,b) => b[1]-a[1]).slice(0, 8);\n        const tgCtx = document.getElementById('chart-tags');\n        if (tgCtx && allTags.length) {\n            S.charts['chart-tags'] = new Chart(tgCtx, {\n                type: 'doughnut',\n                data: { labels: allTags.map(t=>t[0]), datasets: [{ data: allTags.map(t=>t[1]), backgroundColor: CHART_COLORS.slice(0, allTags.length), borderWidth: 0 }] },\n                options: { ...chartOpts(), cutout: '60%' }\n            });\n        }\n        updateLastTime();\n    } catch (e) {\n        el.innerHTML = errorCard('Failed to load overview: ' + e.message);\n    }\n}\nasync function loadAnalytics(days=7) {\n    const el = document.getElementById('analytics-content');\n    try {\n        if (typeof Chart === 'undefined') {\n            el.innerHTML = errorCard('Chart.js library not available. Please check internet connectivity.');\n            return;\n        }\n        const [emoData, strData] = await Promise.all([\n            api('/api/emotions/' + encodeURIComponent(S.persona) + '?days=' + days),\n            api('/api/strengths/' + encodeURIComponent(S.persona))\n        ]);\n\n        // --- Build emotion timeline datasets ---\n        const history = emoData.history || {};\n        const dates = Object.keys(history).sort();\n        const emotionTypes = new Set();\n        dates.forEach(d => (history[d] || []).forEach(r => emotionTypes.add(r.emotion_type)));\n        const datasets = [];\n        [...emotionTypes].forEach((etype, i) => {\n            const data = dates.map(d => {\n                const records = (history[d] || []).filter(r => r.emotion_type === etype);\n                return records.length ? records.reduce((s,r) => s + (r.intensity || 0.5), 0) / records.length : null;\n            });\n            datasets.push({\n                label: etype,\n                data: data,\n                borderColor: EMOTION_COLORS[etype] || CHART_COLORS[i % CHART_COLORS.length],\n                backgroundColor: (EMOTION_COLORS[etype] || CHART_COLORS[i % CHART_COLORS.length]) + '22',\n                fill: true,\n                tension: 0.4,\n                pointRadius: 3,\n                spanGaps: true\n            });\n        });\n\n        // --- Strength histogram ---\n        const histogram = strData.histogram || [];\n        const total = strData.total || 0;\n        const values = (strData.strengths || []).map(s => s.strength);\n        const avgStr = values.length ? (values.reduce((a,b)=>a+b,0)/values.length).toFixed(3) : '0';\n        const weak = values.filter(v => v < 0.3).length;\n        const strong = values.filter(v => v > 0.7).length;\n\n        // --- Render Charts ---\n        const strengthEmpty = (total === 0 || (histogram.length && histogram.every(h => h.count === 0)));\n        destroyChart('chart-emotions');\n        destroyChart('chart-strength');\n\n        el.innerHTML = `\n        <div class=\"glass p-6 mb-6\">\n            <div class=\"card-title\" style=\"justify-content:space-between;flex-wrap:wrap\">\n                <span>眺 Emotion Timeline</span>\n                <div style=\"display:flex;gap:6px\">\n                    <button class=\"glass-btn emo-days-btn ${days===7?'active':''}\" data-days=\"7\" style=\"padding:4px 12px;font-size:0.78rem\">7d</button>\n                    <button class=\"glass-btn emo-days-btn ${days===30?'active':''}\" data-days=\"30\" style=\"padding:4px 12px;font-size:0.78rem\">30d</button>\n                    <button class=\"glass-btn emo-days-btn ${days===90?'active':''}\" data-days=\"90\" style=\"padding:4px 12px;font-size:0.78rem\">3M</button>\n                    <button class=\"glass-btn emo-days-btn ${days===365?'active':''}\" data-days=\"365\" style=\"padding:4px 12px;font-size:0.78rem\">1Y</button>\n                </div>\n            </div>\n            <div style=\"height:280px;position:relative\"><canvas id=\"chart-emotions\"></canvas></div>\n        </div>\n        <div class=\"glass p-6\">\n            <div class=\"card-title\">ｧｪ Memory Strength Distribution</div>\n            <div style=\"display:flex;gap:20px;margin-bottom:16px;flex-wrap:wrap;font-size:0.85rem\">\n                <div><span style=\"color:var(--text-muted)\">Total:</span> <span style=\"font-weight:600\">${total}</span></div>\n                <div><span style=\"color:var(--text-muted)\">Avg:</span> <span style=\"color:var(--accent-green);font-weight:600\">${avgStr}</span></div>\n                <div><span style=\"color:var(--text-muted)\">Weak (&lt;0.3):</span> <span style=\"color:var(--accent-red);font-weight:600\">${weak}</span></div>\n                <div><span style=\"color:var(--text-muted)\">Strong (&gt;0.7):</span> <span style=\"color:var(--accent-green);font-weight:600\">${strong}</span></div>\n            </div>\n            <div style=\"height:250px;position:relative\">${strengthEmpty ? '<div style=\"display:flex;align-items:center;justify-content:center;height:200px;color:var(--text-muted)\">No memory strength data yet 窶・memories need to be recalled first</div>' : '<canvas id=\"chart-strength\"></canvas>'}</div>\n        </div>`;\n\n        // Emotion days buttons\n        document.querySelectorAll('.emo-days-btn').forEach(btn => {\n            btn.addEventListener('click', () => loadAnalytics(parseInt(btn.dataset.days)));\n        });\n\n        const emoCtx = document.getElementById('chart-emotions');\n        if (emoCtx && datasets.length) {\n            S.charts['chart-emotions'] = new Chart(emoCtx, {\n                type: 'line',\n                data: { labels: dates.map(d => fmtDate(d)), datasets },\n                options: chartOpts({ scales: { y: { min: 0, max: 1 }, x: {} } })\n            });\n        } else if (emoCtx) {\n            emoCtx.parentElement.innerHTML = '<div style=\"display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-muted)\">No emotion data for this period</div>';\n        }\n\n        const strCtx = document.getElementById('chart-strength');\n        if (strCtx && histogram.length) {\n            S.charts['chart-strength'] = new Chart(strCtx, {\n                type: 'bar',\n                data: {\n                    labels: histogram.map(h => h.range),\n                    datasets: [{\n                        label: 'Count',\n                        data: histogram.map(h => h.count),\n                        backgroundColor: histogram.map((_, i) => {\n                            const ratio = i / 9;\n                            if (ratio < 0.3) return 'rgba(248,113,113,0.5)';\n                            if (ratio < 0.7) return 'rgba(251,191,36,0.5)';\n                            return 'rgba(52,211,153,0.5)';\n                        }),\n                        borderWidth: 0,\n                        borderRadius: 4\n                    }]\n                },\n                options: chartOpts({ plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true }, x: {} } })\n            });\n        }\n\n        updateLastTime();\n    } catch (e) {\n        el.innerHTML = errorCard('Failed to load analytics: ' + e.message);\n    }\n}\n/* =================================================================\n   MEMORIES TAB 窶・Extended State + Full CRUD\n   ================================================================= */\nObject.assign(S.mem, {\n    sort: 'date_desc', viewMode: 'compact', selectMode: false, selected: new Set(),\n    searchMode: 'hybrid', dateFrom: '', dateTo: '', impMin: 0, impMax: 1,\n    searchTags: [], emotion: '', advOpen: false\n});\n\n/* 笏笏 Hash to hue 笏笏 */\nfunction hashToHue(str) {\n    var h = 0;\n    for (var i = 0; i < str.length; i++) { h = str.charCodeAt(i) + ((h << 5) - h); }\n    return Math.abs(h) % 360;\n}\n\n/* 笏笏 Tag chip HTML 笏笏 */\nfunction tagChipHtml(tag) {\n    var hue = hashToHue(tag);\n    return '<span class=\"mem-tag-chip\" style=\"--chip-hue:' + hue + '\">' + esc(tag) + '</span>';\n}\n\n/* 笏笏 Client-side sort helper 笏笏 */\nfunction _sortMemories(arr) {\n    var s = S.mem.sort;\n    var sorted = arr.slice();\n    if (s === 'date_desc') sorted.sort(function(a,b){ return (b.created_at||'').localeCompare(a.created_at||''); });\n    else if (s === 'date_asc') sorted.sort(function(a,b){ return (a.created_at||'').localeCompare(b.created_at||''); });\n    else if (s === 'imp_desc') sorted.sort(function(a,b){ return (b.importance||0) - (a.importance||0); });\n    else if (s === 'str_desc') sorted.sort(function(a,b){ return (b.strength||0) - (a.strength||0); });\n    else if (s === 'updated_desc') sorted.sort(function(a,b){ return (b.updated_at||'').localeCompare(a.updated_at||''); });\n    return sorted;\n}\n\n/* 笏笏 Client-side filter helper 笏笏 */\nfunction _filterMemories(arr) {\n    return arr.filter(function(m) {\n        if (S.mem.dateFrom) {\n            var d = m.created_at ? m.created_at.slice(0,10) : '';\n            if (d < S.mem.dateFrom) return false;\n        }\n        if (S.mem.dateTo) {\n            var d2 = m.created_at ? m.created_at.slice(0,10) : '';\n            if (d2 > S.mem.dateTo) return false;\n        }\n        var imp = m.importance != null ? m.importance : 0;\n        if (imp < S.mem.impMin || imp > S.mem.impMax) return false;\n        if (S.mem.searchTags.length > 0) {\n            var mtags = m.context_tags || m.tags || [];\n            var hasTag = false;\n            for (var i = 0; i < S.mem.searchTags.length; i++) {\n                if (mtags.indexOf(S.mem.searchTags[i]) !== -1) { hasTag = true; break; }\n            }\n            if (!hasTag) return false;\n        }\n        if (S.mem.emotion && m.emotion_type !== S.mem.emotion) return false;\n        return true;\n    });\n}\n\n/* ================================================================\n   loadMemories\n   ================================================================ */\nasync function loadMemories(page) {\n    if (page != null) S.mem.page = page;\n    var el = document.getElementById('memories-content');\n\n    /* Build tag dropdown options from cache */\n    var tagOptions = '<option value=\"\">All Tags</option>';\n    var allKnownTags = [];\n    if (S.dashCache && S.dashCache.stats && S.dashCache.stats.tag_distribution) {\n        Object.keys(S.dashCache.stats.tag_distribution).sort().forEach(function(t) {\n            tagOptions += '<option value=\"' + esc(t) + '\"' + (S.mem.tag === t ? ' selected' : '') + '>' + esc(t) + '</option>';\n            allKnownTags.push(t);\n        });\n    }\n\n    try {\n        var data, memories, totalPages = 0, totalCount = 0, isSearch = false;\n        if (S.mem.q) {\n            isSearch = true;\n            var searchUrl = '/api/search/' + encodeURIComponent(S.persona)\n                + '?q=' + encodeURIComponent(S.mem.q)\n                + '&limit=50'\n                + '&mode=' + encodeURIComponent(S.mem.searchMode);\n            data = await api(searchUrl);\n            var results = data.results || [];\n            memories = results.map(function(r) {\n                var m = Object.assign({}, r.memory || {});\n                m._score = r.score; m._source = r.source;\n                return m;\n            });\n            memories = _filterMemories(memories);\n            memories = _sortMemories(memories);\n        } else {\n            var url = '/api/observations/' + encodeURIComponent(S.persona)\n                + '?page=' + S.mem.page\n                + '&per_page=' + S.mem.perPage\n                + '&sort=desc';\n            if (S.mem.tag) url += '&tag=' + encodeURIComponent(S.mem.tag);\n            data = await api(url);\n            memories = data.memories || [];\n            memories = _filterMemories(memories);\n            memories = _sortMemories(memories);\n            totalPages = data.total_pages || 1;\n            totalCount = data.total_count || 0;\n        }\n        renderMemoryList(el, memories, tagOptions, totalPages, totalCount, isSearch, allKnownTags);\n        bindMemoryEvents();\n        updateLastTime();\n    } catch (e) {\n        el.innerHTML = errorCard('Failed to load memories: ' + e.message);\n    }\n}\n\n/* ================================================================\n   renderMemoryList\n   ================================================================ */\nfunction renderMemoryList(el, memories, tagOptions, totalPages, totalCount, isSearch, allKnownTags) {\n    var selMode = S.mem.selectMode;\n    var cbClass = selMode ? 'mem-cb show' : 'mem-cb';\n    allKnownTags = allKnownTags || [];\n\n    /* 笏笏 Search bar 笏笏 */\n    var html = '<div class=\"glass p-4 mb-6\">';\n    html += '<div style=\"display:flex;gap:8px;flex-wrap:wrap;align-items:center\">';\n    html += '<input id=\"mem-search\" type=\"text\" class=\"glass-input\" style=\"flex:1;min-width:200px\" placeholder=\"Search memories...\" value=\"' + esc(S.mem.q) + '\">';\n    html += '<select id=\"mem-tag\" class=\"glass-input\">' + tagOptions + '</select>';\n    html += '<button id=\"mem-search-btn\" class=\"glass-btn\">&#128269; Search</button>';\n    html += '<button id=\"adv-search-toggle\" class=\"glass-btn\" style=\"font-size:0.8rem\">&#128269; Advanced</button>';\n    html += '</div>';\n\n    /* 笏笏 Advanced search panel 笏笏 */\n    html += '<div id=\"adv-search-panel\" class=\"adv-search-panel' + (S.mem.advOpen ? ' open' : '') + '\">';\n\n    /* Search mode */\n    html += '<div class=\"adv-search-row\" style=\"margin-top:8px\">';\n    html += '<span class=\"adv-search-label\">Mode</span>';\n    html += '<div class=\"mode-btn-group\">';\n    var modes = ['semantic','keyword','hybrid','smart'];\n    for (var mi = 0; mi < modes.length; mi++) {\n        var m = modes[mi];\n        html += '<button class=\"mode-btn adv-mode-btn' + (S.mem.searchMode === m ? ' active' : '') + '\" data-mode=\"' + m + '\">' + m + '</button>';\n    }\n    html += '</div></div>';\n\n    /* Date range */\n    html += '<div class=\"adv-search-row\">';\n    html += '<span class=\"adv-search-label\">Date From</span>';\n    html += '<input type=\"date\" id=\"adv-date-from\" class=\"glass-input\" style=\"font-size:0.8rem\" value=\"' + esc(S.mem.dateFrom) + '\">';\n    html += '<span class=\"adv-search-label\" style=\"min-width:auto\">To</span>';\n    html += '<input type=\"date\" id=\"adv-date-to\" class=\"glass-input\" style=\"font-size:0.8rem\" value=\"' + esc(S.mem.dateTo) + '\">';\n    html += '</div>';\n\n    /* Importance range */\n    html += '<div class=\"adv-search-row\">';\n    html += '<span class=\"adv-search-label\">Importance</span>';\n    html += '<span class=\"range-value\" id=\"adv-imp-min-val\">' + S.mem.impMin.toFixed(2) + '</span>';\n    html += '<input type=\"range\" class=\"glass-range\" id=\"adv-imp-min\" min=\"0\" max=\"1\" step=\"0.01\" value=\"' + S.mem.impMin + '\" style=\"max-width:140px\">';\n    html += '<span style=\"color:var(--text-muted);font-size:0.75rem\">~</span>';\n    html += '<input type=\"range\" class=\"glass-range\" id=\"adv-imp-max\" min=\"0\" max=\"1\" step=\"0.01\" value=\"' + S.mem.impMax + '\" style=\"max-width:140px\">';\n    html += '<span class=\"range-value\" id=\"adv-imp-max-val\">' + S.mem.impMax.toFixed(2) + '</span>';\n    html += '</div>';\n\n    /* Tags filter pills */\n    html += '<div class=\"adv-search-row\">';\n    html += '<span class=\"adv-search-label\">Tags</span>';\n    html += '<div class=\"filter-tags-wrap\" id=\"adv-tags-wrap\">';\n    for (var ti = 0; ti < allKnownTags.length; ti++) {\n        var t = allKnownTags[ti];\n        var isActive = S.mem.searchTags.indexOf(t) !== -1;\n        html += '<span class=\"filter-tag adv-filter-tag' + (isActive ? ' active' : '') + '\" data-tag=\"' + esc(t) + '\">' + esc(t) + '</span>';\n    }\n    if (allKnownTags.length === 0) html += '<span style=\"font-size:0.75rem;color:var(--text-muted)\">No tags available</span>';\n    html += '</div></div>';\n\n    /* Emotion filter */\n    html += '<div class=\"adv-search-row\">';\n    html += '<span class=\"adv-search-label\">Emotion</span>';\n    html += '<select id=\"adv-emotion\" class=\"glass-input\" style=\"font-size:0.8rem\">';\n    html += '<option value=\"\">Any</option>';\n    var emos = ['joy','sadness','anger','fear','surprise','disgust','love','neutral','anticipation','trust','anxiety','excitement','frustration','nostalgia','pride','shame','guilt','loneliness','contentment','curiosity','awe','relief'];\n    for (var ei = 0; ei < emos.length; ei++) {\n        html += '<option value=\"' + emos[ei] + '\"' + (S.mem.emotion === emos[ei] ? ' selected' : '') + '>' + emos[ei] + '</option>';\n    }\n    html += '</select></div>';\n\n    /* Apply / Clear buttons */\n    html += '<div class=\"adv-search-row\" style=\"justify-content:flex-end;margin-top:4px\">';\n    html += '<button id=\"adv-clear-btn\" class=\"glass-btn\" style=\"font-size:0.78rem\">Clear</button>';\n    html += '<button id=\"adv-apply-btn\" class=\"glass-btn glass-btn-success\" style=\"font-size:0.78rem\">Apply Filters</button>';\n    html += '</div>';\n\n    html += '</div>'; /* close adv-search-panel */\n    html += '</div>'; /* close glass */\n\n    /* 笏笏 Toolbar row 笏笏 */\n    html += '<div class=\"mem-toolbar\">';\n    html += '<button id=\"mem-new-btn\" class=\"glass-btn glass-btn-success\" style=\"font-size:0.82rem\">&#10133; New Memory</button>';\n    html += '<button id=\"mem-select-toggle\" class=\"glass-btn\" style=\"font-size:0.82rem\">' + (selMode ? '&#9745; Select ON' : '&#9744; Select') + '</button>';\n    html += '<div class=\"mem-toolbar-spacer\"></div>';\n    html += '<select id=\"mem-sort\" class=\"glass-input mem-sort-select\">';\n    var sortOpts = [['date_desc','Newest First'],['date_asc','Oldest First'],['imp_desc','Importance \\u2193'],['str_desc','Strength \\u2193'],['updated_desc','Recently Updated']];\n    for (var si = 0; si < sortOpts.length; si++) {\n        html += '<option value=\"' + sortOpts[si][0] + '\"' + (S.mem.sort === sortOpts[si][0] ? ' selected' : '') + '>' + sortOpts[si][1] + '</option>';\n    }\n    html += '</select>';\n    html += '<div class=\"view-toggle\">';\n    html += '<button class=\"view-btn' + (S.mem.viewMode === 'card' ? ' active' : '') + '\" data-view=\"card\">&#9638; Cards</button>';\n    html += '<button class=\"view-btn' + (S.mem.viewMode === 'compact' ? ' active' : '') + '\" data-view=\"compact\">&#9776; Compact</button>';\n    html += '</div>';\n    html += '</div>';\n\n    /* 笏笏 Batch bar 笏笏 */\n    html += '<div id=\"mem-batch-bar\" class=\"mem-batch-bar' + (selMode ? ' active' : '') + '\">';\n    html += '<button id=\"batch-select-all\" class=\"glass-btn\" style=\"font-size:0.78rem\">Select All</button>';\n    html += '<button id=\"batch-deselect\" class=\"glass-btn\" style=\"font-size:0.78rem\">Deselect All</button>';\n    html += '<div class=\"mem-toolbar-spacer\"></div>';\n    html += '<button id=\"batch-delete\" class=\"glass-btn glass-btn-danger\" style=\"font-size:0.78rem\">&#128465; Delete Selected (<span id=\"batch-count\">' + S.mem.selected.size + '</span>)</button>';\n    html += '</div>';\n\n    /* 笏笏 Memory items 笏笏 */\n    html += '<div id=\"mem-list\" class=\"glass\" style=\"overflow:hidden\">';\n    if (memories.length === 0) {\n        html += '<div style=\"padding:40px;text-align:center;color:var(--text-muted)\">No memories found</div>';\n    } else if (S.mem.viewMode === 'compact') {\n        /* 笏笏 Compact view 笏笏 */\n        memories.forEach(function(m) {\n            var key = m.memory_key || m.key || '';\n            var checked = S.mem.selected.has(key) ? ' checked' : '';\n            var tags = (m.context_tags || m.tags || []);\n            var tagsHtml = tags.slice(0, 3).map(function(t){ return tagChipHtml(t); }).join(' ');\n            var impPct = m.importance != null ? (m.importance * 100) : 0;\n            var timeStr = m.created_at ? relativeTime(m.created_at) : '';\n            var memJson = encodeURIComponent(JSON.stringify({\n                memory_key: key, content: m.content || '',\n                tags: tags, emotion_type: m.emotion_type || '',\n                emotion_intensity: m.emotion_intensity, importance: m.importance,\n                strength: m.strength, privacy_level: m.privacy_level || '',\n                source_context: m.source_context || '',\n                created_at: m.created_at || '', updated_at: m.updated_at || '',\n                _score: m._score != null ? m._score : null,\n                _source: m._source || ''\n            }));\n\n            html += '<div class=\"memory-compact\" data-memkey=\"' + esc(key) + '\" data-memjson=\"' + memJson + '\">';\n            html += '<span class=\"' + cbClass + '\"><input type=\"checkbox\" class=\"mem-checkbox\" data-key=\"' + esc(key) + '\"' + checked + '></span>';\n            html += '<span class=\"mem-compact-key\">' + esc(truncate(key, 20)) + '</span>';\n            html += '<span class=\"mem-compact-content\">' + esc(truncate(m.content || '', 80)) + '</span>';\n            html += '<span class=\"mem-compact-meta\">' + tagsHtml + '</span>';\n            html += '<span class=\"mem-compact-meta\"><span class=\"mem-compact-imp\"><span class=\"mem-compact-imp-fill\" style=\"width:' + impPct + '%\"></span></span></span>';\n            html += '<span class=\"mem-compact-meta\" style=\"font-size:0.72rem;color:var(--text-muted);min-width:50px\">' + timeStr + '</span>';\n            html += '</div>';\n        });\n    } else {\n        /* 笏笏 Card view 笏笏 */\n        memories.forEach(function(m) {\n            var key = m.memory_key || m.key || '';\n            var checked = S.mem.selected.has(key) ? ' checked' : '';\n            var tags = (m.context_tags || m.tags || []);\n            var tagsHtml = tags.map(function(t){ return tagChipHtml(t); }).join(' ');\n            var emoColor = EMOTION_COLORS[m.emotion_type] || '#94a3b8';\n            var emoHtml = m.emotion_type ? '<span class=\"badge\" style=\"background:' + emoColor + '22;color:' + emoColor + ';border:1px solid ' + emoColor + '44\">' + esc(m.emotion_type) + (m.emotion_intensity != null ? '(' + m.emotion_intensity.toFixed(1) + ')' : '') + '</span>' : '';\n            var strHtml = m.strength != null ? '<span style=\"color:var(--accent-yellow)\">\\u26A1' + m.strength.toFixed(2) + '</span>' : '';\n            var timeHtml = m.created_at ? '<span>\\uD83D\\uDCC5 ' + relativeTime(m.created_at) + '</span>' : '';\n            var scoreHtml = m._score != null ? '<span class=\"badge badge-green\">Score: ' + m._score.toFixed(3) + '</span>' : '';\n            var memJson = encodeURIComponent(JSON.stringify({\n                memory_key: key, content: m.content || '',\n                tags: tags, emotion_type: m.emotion_type || '',\n                emotion_intensity: m.emotion_intensity, importance: m.importance,\n                strength: m.strength, privacy_level: m.privacy_level || '',\n                source_context: m.source_context || '',\n                created_at: m.created_at || '', updated_at: m.updated_at || '',\n                _score: m._score != null ? m._score : null,\n                _source: m._source || ''\n            }));\n\n            html += '<div class=\"memory-card\" style=\"cursor:pointer\" data-memkey=\"' + esc(key) + '\" data-memjson=\"' + memJson + '\">';\n            html += '<div style=\"display:flex;align-items:center;gap:8px\">';\n            html += '<span class=\"' + cbClass + '\"><input type=\"checkbox\" class=\"mem-checkbox\" data-key=\"' + esc(key) + '\"' + checked + '></span>';\n            html += '<div class=\"memory-key\">' + esc(key) + '</div>';\n            html += '</div>';\n            html += '<div class=\"memory-content\">' + esc(truncate(m.content || '', 200)) + '</div>';\n            html += '<div class=\"memory-meta\">' + tagsHtml + ' ' + emoHtml + ' ' + strHtml + ' ' + scoreHtml + ' ' + timeHtml + '</div>';\n            html += '</div>';\n        });\n    }\n    html += '</div>'; /* close mem-list */\n\n    /* 笏笏 Pagination 笏笏 */\n    if (!isSearch && totalPages > 0) {\n        html += '<div style=\"display:flex;justify-content:center;align-items:center;gap:12px;margin-top:16px\">';\n        html += '<button class=\"glass-btn mem-page-btn\" data-page=\"' + (S.mem.page - 1) + '\"' + (S.mem.page <= 1 ? ' disabled style=\"opacity:0.4;pointer-events:none\"' : '') + '>\\u25C0 Prev</button>';\n        html += '<span style=\"font-size:0.85rem;color:var(--text-muted)\">Page ' + S.mem.page + ' of ' + totalPages + ' (' + totalCount + ' total)</span>';\n        html += '<button class=\"glass-btn mem-page-btn\" data-page=\"' + (S.mem.page + 1) + '\"' + (S.mem.page >= totalPages ? ' disabled style=\"opacity:0.4;pointer-events:none\"' : '') + '>Next \\u25B6</button>';\n        html += '</div>';\n    }\n    el.innerHTML = html;\n}\n\n/* ================================================================\n   bindMemoryEvents\n   ================================================================ */\nfunction bindMemoryEvents() {\n    var searchBtn = document.getElementById('mem-search-btn');\n    var searchInput = document.getElementById('mem-search');\n    var tagSelect = document.getElementById('mem-tag');\n\n    /* Search button */\n    if (searchBtn) searchBtn.onclick = function() {\n        S.mem.q = searchInput ? searchInput.value.trim() : '';\n        S.mem.tag = tagSelect ? tagSelect.value : '';\n        S.mem.page = 1;\n        loadMemories();\n    };\n    /* Enter in search */\n    if (searchInput) searchInput.onkeydown = function(e) {\n        if (e.key === 'Enter' && searchBtn) searchBtn.click();\n    };\n    /* Tag dropdown */\n    if (tagSelect) tagSelect.onchange = function() {\n        S.mem.tag = tagSelect.value;\n        S.mem.q = '';\n        if (searchInput) searchInput.value = '';\n        S.mem.page = 1;\n        loadMemories();\n    };\n\n    /* Page buttons */\n    document.querySelectorAll('.mem-page-btn').forEach(function(btn) {\n        btn.onclick = function() { loadMemories(parseInt(btn.dataset.page)); };\n    });\n\n    /* Memory card / compact row clicks */\n    document.querySelectorAll('[data-memjson]').forEach(function(card) {\n        card.onclick = function(e) {\n            /* Don't open modal when clicking checkbox */\n            if (e.target.type === 'checkbox') return;\n            try {\n                var mem = JSON.parse(decodeURIComponent(card.getAttribute('data-memjson')));\n                openMemModal(mem);\n            } catch(err) { console.error('Modal parse error', err); }\n        };\n    });\n\n    /* New Memory button */\n    var newBtn = document.getElementById('mem-new-btn');\n    if (newBtn) newBtn.onclick = function() { openCreateModal(); };\n\n    /* Select toggle */\n    var selToggle = document.getElementById('mem-select-toggle');\n    if (selToggle) selToggle.onclick = function() { toggleSelectMode(); };\n\n    /* Sort dropdown */\n    var sortSel = document.getElementById('mem-sort');\n    if (sortSel) sortSel.onchange = function() {\n        S.mem.sort = sortSel.value;\n        loadMemories();\n    };\n\n    /* View toggle */\n    document.querySelectorAll('.view-btn').forEach(function(btn) {\n        btn.onclick = function() {\n            S.mem.viewMode = btn.dataset.view;\n            loadMemories();\n        };\n    });\n\n    /* Advanced search toggle */\n    var advToggle = document.getElementById('adv-search-toggle');\n    if (advToggle) advToggle.onclick = function() { toggleAdvancedSearch(); };\n\n    /* Checkboxes */\n    document.querySelectorAll('.mem-checkbox').forEach(function(cb) {\n        cb.onchange = function() {\n            var k = cb.dataset.key;\n            if (cb.checked) S.mem.selected.add(k);\n            else S.mem.selected.delete(k);\n            var countEl = document.getElementById('batch-count');\n            if (countEl) countEl.textContent = S.mem.selected.size;\n        };\n    });\n\n    /* Batch bar buttons */\n    var batchAll = document.getElementById('batch-select-all');\n    if (batchAll) batchAll.onclick = function() {\n        document.querySelectorAll('.mem-checkbox').forEach(function(cb) {\n            cb.checked = true;\n            S.mem.selected.add(cb.dataset.key);\n        });\n        var countEl = document.getElementById('batch-count');\n        if (countEl) countEl.textContent = S.mem.selected.size;\n    };\n    var batchDesel = document.getElementById('batch-deselect');\n    if (batchDesel) batchDesel.onclick = function() {\n        document.querySelectorAll('.mem-checkbox').forEach(function(cb) { cb.checked = false; });\n        S.mem.selected.clear();\n        var countEl = document.getElementById('batch-count');\n        if (countEl) countEl.textContent = '0';\n    };\n    var batchDel = document.getElementById('batch-delete');\n    if (batchDel) batchDel.onclick = function() { batchDeleteMemories(); };\n\n    /* Advanced search: mode buttons */\n    document.querySelectorAll('.adv-mode-btn').forEach(function(btn) {\n        btn.onclick = function() {\n            document.querySelectorAll('.adv-mode-btn').forEach(function(b){ b.classList.remove('active'); });\n            btn.classList.add('active');\n            S.mem.searchMode = btn.dataset.mode;\n        };\n    });\n\n    /* Advanced search: importance sliders live update */\n    var impMinSlider = document.getElementById('adv-imp-min');\n    var impMaxSlider = document.getElementById('adv-imp-max');\n    if (impMinSlider) impMinSlider.oninput = function() {\n        var v = document.getElementById('adv-imp-min-val');\n        if (v) v.textContent = parseFloat(impMinSlider.value).toFixed(2);\n    };\n    if (impMaxSlider) impMaxSlider.oninput = function() {\n        var v = document.getElementById('adv-imp-max-val');\n        if (v) v.textContent = parseFloat(impMaxSlider.value).toFixed(2);\n    };\n\n    /* Advanced search: filter tag pills toggle */\n    document.querySelectorAll('.adv-filter-tag').forEach(function(pill) {\n        pill.onclick = function() { pill.classList.toggle('active'); };\n    });\n\n    /* Advanced search: Apply */\n    var advApply = document.getElementById('adv-apply-btn');\n    if (advApply) advApply.onclick = function() { applyAdvancedSearch(); };\n\n    /* Advanced search: Clear */\n    var advClear = document.getElementById('adv-clear-btn');\n    if (advClear) advClear.onclick = function() { clearAdvancedSearch(); };\n\n    /* Edit modal: importance slider live update */\n    var editImp = document.getElementById('edit-importance');\n    if (editImp) editImp.oninput = function() {\n        var v = document.getElementById('edit-imp-val');\n        if (v) v.textContent = parseFloat(editImp.value).toFixed(2);\n    };\n    /* Edit modal: emotion intensity slider live update */\n    var editEmo = document.getElementById('edit-emo-intensity');\n    if (editEmo) editEmo.oninput = function() {\n        var v = document.getElementById('edit-emo-val');\n        if (v) v.textContent = parseFloat(editEmo.value).toFixed(2);\n    };\n    /* Edit modal: tag input Enter to add */\n    var tagInput = document.getElementById('edit-tag-input');\n    if (tagInput) tagInput.onkeydown = function(e) {\n        if (e.key === 'Enter') {\n            e.preventDefault();\n            var val = tagInput.value.trim();\n            if (!val) return;\n            _addEditTag(val);\n            tagInput.value = '';\n        }\n    };\n}\n\n/* ================================================================\n   openMemModal 窶・OVERRIDE base.py version\n   ================================================================ */\nfunction openMemModal(mem) {\n    var overlay = document.getElementById('mem-modal-overlay');\n    var content = document.getElementById('mem-modal-content');\n    if (!overlay || !content) return;\n\n    var tags = (mem.tags || []);\n    var tagsHtml = tags.map(function(t){ return tagChipHtml(t); }).join(' ');\n    var emoColor = EMOTION_COLORS[mem.emotion_type] || '#94a3b8';\n\n    var h = '';\n    h += '<div class=\"mem-modal-header\">';\n    h += '<div>';\n    h += '<div style=\"font-size:0.7rem;color:var(--text-muted);margin-bottom:4px\">Memory Key</div>';\n    h += '<div style=\"display:flex;align-items:center;gap:6px\">';\n    h += '<span style=\"font-family:monospace;font-size:0.85rem;color:var(--accent-purple)\">' + esc(mem.memory_key) + '</span>';\n    h += '<button class=\"copy-btn\" onclick=\"navigator.clipboard.writeText(\\'' + esc(mem.memory_key).replace(/'/g,'\\\\\\'') + '\\');toast(\\'Key copied!\\',\\'info\\')\" title=\"Copy key\">\\uD83D\\uDCCB</button>';\n    h += '</div></div>';\n    h += '<button class=\"mem-modal-close\" onclick=\"closeMemModal()\">\\u2715</button>';\n    h += '</div>';\n\n    /* Full content */\n    h += '<div class=\"mem-modal-content\">' + esc(mem.content) + '</div>';\n\n    /* Tags */\n    if (tagsHtml) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Tags</span><span>' + tagsHtml + '</span></div>';\n    }\n\n    /* Emotion */\n    if (mem.emotion_type) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Emotion</span><span>';\n        h += '<span class=\"badge\" style=\"background:' + emoColor + '22;color:' + emoColor + ';border:1px solid ' + emoColor + '44\">' + esc(mem.emotion_type) + '</span>';\n        if (mem.emotion_intensity != null) {\n            h += ' <div class=\"modal-progress\" style=\"display:inline-flex;width:120px;vertical-align:middle\">';\n            h += '<div class=\"modal-progress-bar\"><div class=\"modal-progress-fill\" style=\"width:' + (mem.emotion_intensity * 100) + '%;background:' + emoColor + '\"></div></div>';\n            h += '<span style=\"font-size:0.75rem;color:' + emoColor + '\">' + mem.emotion_intensity.toFixed(2) + '</span></div>';\n        }\n        h += '</span></div>';\n    }\n\n    /* Importance */\n    if (mem.importance != null) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Importance</span><span>';\n        h += '<div class=\"modal-progress\" style=\"display:inline-flex;width:160px\">';\n        h += '<div class=\"modal-progress-bar\"><div class=\"modal-progress-fill\" style=\"width:' + (mem.importance * 100) + '%;background:linear-gradient(90deg,var(--accent-purple),var(--accent-yellow))\"></div></div>';\n        h += '<span style=\"font-size:0.78rem;color:var(--accent-yellow);font-weight:600\">' + mem.importance.toFixed(2) + '</span></div>';\n        h += '</span></div>';\n    }\n\n    /* Strength */\n    if (mem.strength != null) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Strength</span><span>';\n        h += '<div class=\"modal-progress\" style=\"display:inline-flex;width:160px\">';\n        h += '<div class=\"modal-progress-bar\"><div class=\"modal-progress-fill\" style=\"width:' + Math.min(mem.strength * 100, 100) + '%;background:linear-gradient(90deg,var(--accent-green),var(--accent-blue))\"></div></div>';\n        h += '<span style=\"font-size:0.78rem;color:var(--accent-green);font-weight:600\">' + mem.strength.toFixed(3) + '</span></div>';\n        h += '</span></div>';\n    }\n\n    /* Score (search) */\n    if (mem._score != null) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Search Score</span><span class=\"badge badge-green\">' + mem._score.toFixed(3) + '</span></div>';\n    }\n\n    /* Privacy */\n    if (mem.privacy_level) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Privacy</span><span>' + esc(mem.privacy_level) + '</span></div>';\n    }\n\n    /* Source context */\n    if (mem.source_context) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Source</span><span style=\"color:var(--text-muted)\">' + esc(mem.source_context) + '</span></div>';\n    }\n\n    /* Created at */\n    if (mem.created_at) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Created</span><span>\\uD83D\\uDCC5 ' + relativeTime(mem.created_at) + ' <span style=\"color:var(--text-muted);font-size:0.75rem\">(' + new Date(mem.created_at).toLocaleString() + ')</span></span></div>';\n    }\n\n    /* Updated at */\n    if (mem.updated_at) {\n        h += '<div class=\"mem-modal-row\"><span class=\"mem-modal-key\">Updated</span><span>\\uD83D\\uDCC5 ' + relativeTime(mem.updated_at) + ' <span style=\"color:var(--text-muted);font-size:0.75rem\">(' + new Date(mem.updated_at).toLocaleString() + ')</span></span></div>';\n    }\n\n    /* Action buttons */\n    h += '<div style=\"display:flex;gap:8px;margin-top:16px;justify-content:flex-end\">';\n    h += '<button class=\"glass-btn glass-btn-danger\" onclick=\"deleteMemory(\\'' + esc(mem.memory_key).replace(/'/g,'\\\\\\'') + '\\')\">\\uD83D\\uDDD1 Delete</button>';\n    h += '<button class=\"glass-btn glass-btn-success\" id=\"mem-modal-edit-btn\">\\u270F\\uFE0F Edit</button>';\n    h += '</div>';\n\n    content.innerHTML = h;\n    overlay.style.display = 'flex';\n    overlay.classList.add('show');\n    document.addEventListener('keydown', _memModalKeyHandler);\n\n    /* Bind the edit button - we store the mem object in closure */\n    var editBtn = document.getElementById('mem-modal-edit-btn');\n    if (editBtn) editBtn.onclick = function() { openEditModal(mem); };\n}\n\n/* ================================================================\n   openEditModal / openCreateModal\n   ================================================================ */\nvar _editTags = [];\n\nfunction _renderEditTags() {\n    var wrap = document.getElementById('edit-tags-wrap');\n    if (!wrap) return;\n    /* Remove existing chips, keep the input */\n    var chips = wrap.querySelectorAll('.tag-chip-edit');\n    chips.forEach(function(c){ c.remove(); });\n    var inp = document.getElementById('edit-tag-input');\n    _editTags.forEach(function(tag, idx) {\n        var hue = hashToHue(tag);\n        var chip = document.createElement('span');\n        chip.className = 'tag-chip-edit';\n        chip.style.cssText = '--chip-hue:' + hue;\n        chip.innerHTML = esc(tag) + ' <span class=\"tag-chip-remove\" data-tidx=\"' + idx + '\">\\u00D7</span>';\n        wrap.insertBefore(chip, inp);\n    });\n    /* Bind remove buttons */\n    wrap.querySelectorAll('.tag-chip-remove').forEach(function(btn) {\n        btn.onclick = function(e) {\n            e.stopPropagation();\n            var i = parseInt(btn.dataset.tidx);\n            _editTags.splice(i, 1);\n            _renderEditTags();\n        };\n    });\n}\n\nfunction _addEditTag(val) {\n    val = val.trim().toLowerCase();\n    if (!val || _editTags.indexOf(val) !== -1) return;\n    _editTags.push(val);\n    _renderEditTags();\n}\n\nfunction openEditModal(mem) {\n    document.getElementById('edit-modal-title').textContent = 'Edit Memory';\n    document.getElementById('edit-content').value = mem.content || '';\n    document.getElementById('edit-memory-key').value = mem.memory_key || '';\n\n    var imp = mem.importance != null ? mem.importance : 0.5;\n    document.getElementById('edit-importance').value = imp;\n    document.getElementById('edit-imp-val').textContent = imp.toFixed(2);\n\n    document.getElementById('edit-emotion').value = mem.emotion_type || '';\n\n    var emoInt = mem.emotion_intensity != null ? mem.emotion_intensity : 0;\n    document.getElementById('edit-emo-intensity').value = emoInt;\n    document.getElementById('edit-emo-val').textContent = emoInt.toFixed(2);\n\n    _editTags = (mem.tags || []).slice();\n    _renderEditTags();\n\n    document.getElementById('mem-edit-overlay').classList.add('active');\n}\n\nfunction openCreateModal() {\n    document.getElementById('edit-modal-title').textContent = 'New Memory';\n    document.getElementById('edit-content').value = '';\n    document.getElementById('edit-memory-key').value = '';\n\n    document.getElementById('edit-importance').value = 0.5;\n    document.getElementById('edit-imp-val').textContent = '0.50';\n\n    document.getElementById('edit-emotion').value = '';\n\n    document.getElementById('edit-emo-intensity').value = 0;\n    document.getElementById('edit-emo-val').textContent = '0.00';\n\n    _editTags = [];\n    _renderEditTags();\n\n    document.getElementById('mem-edit-overlay').classList.add('active');\n}\n\nfunction closeEditModal() {\n    document.getElementById('mem-edit-overlay').classList.remove('active');\n}\n\n/* ================================================================\n   saveMemory\n   ================================================================ */\nasync function saveMemory() {\n    var contentVal = document.getElementById('edit-content').value.trim();\n    if (!contentVal) { toast('Content is required', 'error'); return; }\n\n    var key = document.getElementById('edit-memory-key').value;\n    var imp = parseFloat(document.getElementById('edit-importance').value);\n    var emoType = document.getElementById('edit-emotion').value;\n    var emoInt = parseFloat(document.getElementById('edit-emo-intensity').value);\n\n    var body = { content: contentVal, importance: imp, tags: _editTags.slice() };\n    if (emoType) { body.emotion_type = emoType; body.emotion_intensity = emoInt; }\n\n    try {\n        if (key) {\n            /* Update existing */\n            await api('/api/memories/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(key), {\n                method: 'PUT', body: JSON.stringify(body)\n            });\n            toast('Memory updated', 'success');\n        } else {\n            /* Create new */\n            await api('/api/memories/' + encodeURIComponent(S.persona), {\n                method: 'POST', body: JSON.stringify(body)\n            });\n            toast('Memory created', 'success');\n        }\n        closeEditModal();\n        closeMemModal();\n        loadMemories();\n    } catch (e) {\n        toast('Save failed: ' + e.message, 'error');\n    }\n}\n\n/* ================================================================\n   deleteMemory\n   ================================================================ */\nasync function deleteMemory(key) {\n    if (!confirm('Are you sure? This cannot be undone.')) return;\n    try {\n        await api('/api/memories/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(key), {\n            method: 'DELETE'\n        });\n        toast('Memory deleted', 'success');\n        closeMemModal();\n        loadMemories();\n    } catch (e) {\n        toast('Delete failed: ' + e.message, 'error');\n    }\n}\n\n/* ================================================================\n   batchDeleteMemories\n   ================================================================ */\nasync function batchDeleteMemories() {\n    var keys = Array.from(S.mem.selected);\n    if (keys.length === 0) { toast('No memories selected', 'error'); return; }\n    if (!confirm('Delete ' + keys.length + ' memories? This cannot be undone.')) return;\n\n    var ok = 0, fail = 0;\n    for (var i = 0; i < keys.length; i++) {\n        try {\n            await api('/api/memories/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(keys[i]), {\n                method: 'DELETE'\n            });\n            ok++;\n        } catch (e) { fail++; }\n    }\n    S.mem.selected.clear();\n    toast('Deleted ' + ok + ' memories' + (fail ? ', ' + fail + ' failed' : ''), fail ? 'error' : 'success');\n    loadMemories();\n}\n\n/* ================================================================\n   toggleSelectMode\n   ================================================================ */\nfunction toggleSelectMode() {\n    S.mem.selectMode = !S.mem.selectMode;\n    if (!S.mem.selectMode) S.mem.selected.clear();\n    loadMemories();\n}\n\n/* ================================================================\n   toggleAdvancedSearch\n   ================================================================ */\nfunction toggleAdvancedSearch() {\n    S.mem.advOpen = !S.mem.advOpen;\n    var panel = document.getElementById('adv-search-panel');\n    if (panel) {\n        if (S.mem.advOpen) panel.classList.add('open');\n        else panel.classList.remove('open');\n    }\n}\n\n/* ================================================================\n   applyAdvancedSearch\n   ================================================================ */\nfunction applyAdvancedSearch() {\n    var df = document.getElementById('adv-date-from');\n    var dt = document.getElementById('adv-date-to');\n    var impMin = document.getElementById('adv-imp-min');\n    var impMax = document.getElementById('adv-imp-max');\n    var emo = document.getElementById('adv-emotion');\n\n    S.mem.dateFrom = df ? df.value : '';\n    S.mem.dateTo = dt ? dt.value : '';\n    S.mem.impMin = impMin ? parseFloat(impMin.value) : 0;\n    S.mem.impMax = impMax ? parseFloat(impMax.value) : 1;\n    S.mem.emotion = emo ? emo.value : '';\n\n    /* Gather active tag pills */\n    S.mem.searchTags = [];\n    document.querySelectorAll('.adv-filter-tag.active').forEach(function(pill) {\n        S.mem.searchTags.push(pill.dataset.tag);\n    });\n\n    loadMemories(1);\n}\n\n/* ================================================================\n   clearAdvancedSearch\n   ================================================================ */\nfunction clearAdvancedSearch() {\n    S.mem.dateFrom = '';\n    S.mem.dateTo = '';\n    S.mem.impMin = 0;\n    S.mem.impMax = 1;\n    S.mem.searchTags = [];\n    S.mem.emotion = '';\n    S.mem.searchMode = 'hybrid';\n    loadMemories(1);\n}\n\n\n/* =================================================================\n   MEMORY TIMELINE\n   ================================================================= */\nconst TL_EMOTION_COLORS = {\n    joy:         { bg: 'rgba(251,191,36,0.15)',  border: '#FBBF24', emoji: '・' },\n    sadness:     { bg: 'rgba(96,165,250,0.15)',  border: '#60A5FA', emoji: '个' },\n    anger:       { bg: 'rgba(248,113,113,0.15)', border: '#F87171', emoji: '丐' },\n    love:        { bg: 'rgba(244,114,182,0.15)', border: '#F472B6', emoji: '笶､・・ },\n    fear:        { bg: 'rgba(167,139,250,0.15)', border: '#A78BFA', emoji: '乖' },\n    surprise:    { bg: 'rgba(52,211,153,0.15)',  border: '#34D399', emoji: '亟' },\n    neutral:     { bg: 'rgba(156,163,175,0.15)', border: '#9CA3AF', emoji: '・' },\n    excitement:  { bg: 'rgba(245,158,11,0.15)',  border: '#F59E0B', emoji: '､ｩ' },\n    pride:       { bg: 'rgba(129,140,248,0.15)', border: '#818CF8', emoji: 'ｦ・ },\n    shame:       { bg: 'rgba(251,113,133,0.15)', border: '#FB7185', emoji: '亠' },\n    curiosity:   { bg: 'rgba(45,212,191,0.15)',  border: '#2DD4BF', emoji: '､・ },\n    anxiety:     { bg: 'rgba(248,113,113,0.12)', border: '#F87171', emoji: '于' },\n    frustration: { bg: 'rgba(251,146,60,0.15)',  border: '#FB923C', emoji: '丶' },\n    nostalgia:   { bg: 'rgba(167,139,250,0.12)', border: '#A78BFA', emoji: '桁' },\n    trust:       { bg: 'rgba(52,211,153,0.12)',  border: '#34D399', emoji: '､・ },\n    loneliness:  { bg: 'rgba(148,163,184,0.15)', border: '#94A3B8', emoji: '・' },\n    contentment: { bg: 'rgba(134,239,172,0.15)', border: '#86EFAC', emoji: '・' },\n    awe:         { bg: 'rgba(192,132,252,0.15)', border: '#C084FC', emoji: '血' },\n    relief:      { bg: 'rgba(110,231,183,0.15)', border: '#6EE7B7', emoji: '舒窶昨汳ｨ' },\n    disgust:     { bg: 'rgba(163,230,53,0.15)',  border: '#A3E635', emoji: '､｢' },\n    guilt:       { bg: 'rgba(252,165,165,0.15)', border: '#FCA5A5', emoji: '・' },\n};\n\nfunction getEmotionStyle(emotion) {\n    return TL_EMOTION_COLORS[emotion] || TL_EMOTION_COLORS['neutral'];\n}\n\nfunction buildEmotionLegend() {\n    const legend = document.getElementById('tl-legend');\n    if (!legend) return;\n    let html = '';\n    for (const [emo, style] of Object.entries(TL_EMOTION_COLORS)) {\n        html += '<span><span class=\"tl-legend-dot\" style=\"background:' + style.border + '\"></span>' + style.emoji + ' ' + emo + '</span>';\n    }\n    legend.innerHTML = html;\n    // Populate emotion filter dropdown\n    const sel = document.getElementById('tl-emotion');\n    if (sel) {\n        sel.innerHTML = '<option value=\"\">縺吶∋縺ｦ</option>';\n        for (const emo of Object.keys(TL_EMOTION_COLORS).sort()) {\n            sel.innerHTML += '<option value=\"' + emo + '\">' + TL_EMOTION_COLORS[emo].emoji + ' ' + emo + '</option>';\n        }\n    }\n}\n\nlet _timeline = null;\nlet _timelineItems = null;\nlet _timelineData = null;\n\nasync function loadTimeline() {\n    if (!S.persona) return;\n    const container = document.getElementById('tl-container');\n    const loading = document.getElementById('tl-loading');\n    if (!container) return;\n    const perPage = parseInt(document.getElementById('tl-per-page')?.value || '100');\n    const emotion = document.getElementById('tl-emotion')?.value || '';\n    const tag = document.getElementById('tl-tag')?.value.trim() || '';\n    const minImp = parseFloat(document.getElementById('tl-min-importance')?.value || '0');\n\n    if (loading) loading.style.display = 'flex';\n\n    try {\n        let allMemories = [];\n        let page = 1;\n        let totalPages = 1;\n        while (page <= totalPages && page <= 5) {  // max 5 pages\n            const resp = await api('/api/observations/' + encodeURIComponent(S.persona) +\n                '?page=' + page + '&per_page=' + perPage);\n            if (!resp.memories) break;\n            allMemories = allMemories.concat(resp.memories);\n            totalPages = resp.total_pages || 1;\n            page++;\n        }\n\n        // Filter client-side\n        if (emotion) allMemories = allMemories.filter(m => m.emotion_type === emotion);\n        if (tag) allMemories = allMemories.filter(m => (m.tags || []).some(t => t.toLowerCase().includes(tag.toLowerCase())));\n        if (minImp > 0) allMemories = allMemories.filter(m => (m.importance || 0) >= minImp);\n\n        _timelineData = allMemories;\n\n        if (loading) loading.style.display = 'none';\n\n        if (_timeline) { _timeline.destroy(); _timeline = null; }\n\n        const items = allMemories.map((m, i) => {\n            const style = getEmotionStyle(m.emotion_type || 'neutral');\n            const content = (m.content || '').substring(0, 100);\n            const imp = m.importance != null ? m.importance : 0.5;\n            return {\n                id: m.key || i,\n                content: style.emoji + ' ' + content,\n                start: m.created_at ? new Date(m.created_at) : new Date(),\n                title: '<div style=\"max-width:300px;white-space:normal;font-size:0.78rem;line-height:1.4;\">' +\n                       esc(m.content || '') + '</div>' +\n                       '<div style=\"font-size:0.68rem;color:var(--text-muted);margin-top:4px;\">' +\n                       (style.emoji + ' ' + (m.emotion_type || 'neutral') + ' ﾂｷ imp:' + imp.toFixed(2)) + '</div>',\n                style: 'background:' + style.bg + ';border-color:' + style.border + ';' +\n                       'font-size:' + (0.65 + imp * 0.2) + 'rem;',\n            };\n        });\n\n        _timelineItems = new vis.DataSet(items);\n\n        const options = {\n            height: '100%',\n            minHeight: '500px',\n            start: items.length > 0 ? new Date(items[items.length-1].start.getTime() - 86400000 * 7) : new Date(),\n            end: new Date(),\n            zoomable: true,\n            moveable: true,\n            selectable: true,\n            multiselect: false,\n            tooltip: { followMouse: true, overflowMethod: 'cap' },\n            margin: { item: { vertical: 4 } },\n            timeAxis: { scale: 'day', step: 1 },\n            orientation: { axis: 'top' },\n        };\n\n        _timeline = new vis.Timeline(container, _timelineItems, options);\n\n        _timeline.on('select', function(props) {\n            if (props.items.length > 0) {\n                const id = props.items[0];\n                const mem = _timelineData.find(m => (m.key || '') === id);\n                if (mem) showTimelineDetail(mem);\n            }\n        });\n\n        _timeline.on('doubleClick', function(props) {\n            if (props.what === 'background') {\n                _timeline.fit();\n            }\n        });\n\n    } catch (e) {\n        if (loading) { loading.textContent = '隱ｭ縺ｿ霎ｼ縺ｿ螟ｱ謨・ ' + e.message; loading.style.display = 'flex'; }\n    }\n}\n\nfunction showTimelineDetail(mem) {\n    const panel = document.getElementById('tl-detail-panel');\n    if (!panel) return;\n    document.getElementById('tl-detail-content').textContent = mem.content || '';\n    const style = getEmotionStyle(mem.emotion_type || 'neutral');\n    document.getElementById('tl-detail-emotion').innerHTML = style.emoji + ' ' + (mem.emotion_type || 'neutral');\n    document.getElementById('tl-detail-importance').textContent = (mem.importance != null ? mem.importance.toFixed(2) : '0.50');\n    document.getElementById('tl-detail-time').textContent = mem.created_at\n        ? new Date(mem.created_at).toLocaleString('ja-JP') : '窶・;\n    document.getElementById('tl-detail-tags').textContent = (mem.tags || []).join(', ') || '窶・;\n    panel.classList.add('open');\n}\n\nfunction closeTimelineDetail() {\n    document.getElementById('tl-detail-panel')?.classList.remove('open');\n}\n\n// Initialize on tab visibility\ndocument.addEventListener('DOMContentLoaded', () => {\n    buildEmotionLegend();\n    // Load when timeline tab becomes visible via MutationObserver or tab switch\n    const origSwitchTab = switchTab;\n    if (typeof switchTab !== 'undefined') {\n        switchTab = function(tabId) {\n            origSwitchTab(tabId);\n            if (tabId === 'timeline') {\n                setTimeout(loadTimeline, 200);\n            }\n        };\n    }\n});\n\n\n/* ================================================================\n *  Knowledge Graph 窶・vis-network interactive memory visualization\n * ================================================================ */\n\nlet graphNetwork = null;\nlet graphData = null;\nlet graphNodeLimit = 100;\n\n/* ---- Helpers ---- */\n\nfunction _graphFontColor() {\n    return document.documentElement.classList.contains('light') ? '#1e1b4b' : '#f1f5f9';\n}\nfunction _graphEdgeColor(isRelated) {\n    var isLight = document.documentElement.classList.contains('light');\n    if (isRelated) {\n        return {\n            color:     isLight ? 'rgba(109,40,217,0.75)' : 'rgba(167,139,250,0.85)',\n            highlight: isLight ? '#7c3aed' : '#c4b5fd',\n            hover:     isLight ? '#7c3aed' : '#c4b5fd'\n        };\n    }\n    return {\n        color:     isLight ? 'rgba(100,116,139,0.55)' : 'rgba(148,163,184,0.65)',\n        highlight: isLight ? '#475569' : '#94a3b8',\n        hover:     isLight ? '#475569' : '#94a3b8'\n    };\n}\n\n/* ---- Main loader ---- */\n\nasync function loadGraph() {\n    var el = document.getElementById('graph-content');\n    var container = document.getElementById('graph-container');\n    var loading = document.getElementById('graph-loading');\n    var statsEl = document.getElementById('graph-stats');\n\n    if (loading) loading.style.display = 'flex';\n\n    try {\n        var data = await api(\n            '/api/graph/' + encodeURIComponent(S.persona) + '?limit=' + graphNodeLimit\n        );\n        graphData = data;\n\n        populateGraphFilters(data.nodes);\n\n        var built = buildVisData(data.nodes, data.edges);\n        var filtered = applyGraphFilters(built.visNodes, built.visEdges);\n\n        renderNetwork(container, filtered.nodes, filtered.edges);\n\n        if (statsEl) {\n            statsEl.textContent = filtered.nodes.length + ' nodes ﾂｷ ' + filtered.edges.length + ' edges';\n        }\n\n    } catch (e) {\n        if (container) container.innerHTML = errorCard('Failed to load graph: ' + e.message);\n    } finally {\n        var l = document.getElementById('graph-loading');\n        if (l) l.style.display = 'none';\n        if (loading) loading.style.display = 'none';\n    }\n}\n\n/* ---- Populate filter dropdowns ---- */\n\nfunction populateGraphFilters(nodes) {\n    var tagSet = new Set();\n    var emotionSet = new Set();\n    nodes.forEach(function(n) {\n        (n.tags || []).forEach(function(t) { tagSet.add(t); });\n        if (n.emotion_type) emotionSet.add(n.emotion_type);\n    });\n\n    var tagFilter = document.getElementById('graph-tag-filter');\n    var emotionFilter = document.getElementById('graph-emotion-filter');\n    if (!tagFilter || !emotionFilter) return;\n    var currentTags = Array.from(tagFilter.selectedOptions).map(function(o) { return o.value; }).filter(Boolean);\n    tagFilter.innerHTML = '<option value=\"\">All Tags</option>' +\n        Array.from(tagSet).sort().map(function(t) {\n            return '<option value=\"' + esc(t) + '\"' +\n                   (currentTags.includes(t) ? ' selected' : '') + '>' + esc(t) + '</option>';\n        }).join('');\n\n    var currentEmo = emotionFilter.value;\n    emotionFilter.innerHTML = '<option value=\"\">All Emotions</option>' +\n        Array.from(emotionSet).sort().map(function(e) {\n            return '<option value=\"' + esc(e) + '\"' +\n                   (currentEmo === e ? ' selected' : '') + '>' + esc(e) + '</option>';\n        }).join('');\n}\n\n/* ---- Build vis-network DataSet arrays ---- */\n\nfunction buildVisData(nodes, edges) {\n    var fontColor = _graphFontColor();\n\n    var visNodes = nodes.map(function(n) {\n        var emoColor = EMOTION_COLORS[n.emotion_type] || '#94a3b8';\n        var sz = 10 + (n.importance || 0.5) * 30;\n        return {\n            id: n.key,\n            label: truncate(n.content, 20),\n            title: buildTooltip(n),\n            size: sz,\n            color: {\n                background: emoColor,\n                border: emoColor,\n                highlight: { background: emoColor, border: '#fff' },\n                hover:     { background: emoColor, border: '#fff' }\n            },\n            font: { color: fontColor, size: 11, face: 'system-ui' },\n            borderWidth: 2,\n            shadow: { enabled: true, color: emoColor, size: 8, x: 0, y: 0 },\n            _data: n\n        };\n    });\n\n    var visEdges = edges.map(function(e, i) {\n        var isRelated = (e.type === 'related');\n        return {\n            id: 'e' + i,\n            from: e.source,\n            to: e.target,\n            dashes: !isRelated,\n            width: isRelated ? 2.5 : 1.5,\n            color: _graphEdgeColor(isRelated),\n            smooth: { type: 'continuous' },\n            _type: e.type,\n            _tag:  e.tag || '',\n            _from: e.source,\n            _to:   e.target\n        };\n    });\n\n    return { visNodes: visNodes, visEdges: visEdges };\n}\n\n/* ---- Tooltip HTML ---- */\n\nfunction buildTooltip(n) {\n    var el = document.createElement('div');\n    el.style.cssText = 'background:#1e293b;color:#e2e8f0;border-radius:8px;padding:10px 12px;font-size:12px;line-height:1.6;max-width:300px;white-space:normal;word-break:break-word;box-shadow:0 4px 16px rgba(0,0,0,0.5);';\n    var h = '<div style=\"margin-bottom:6px;font-weight:600;color:#f8fafc\">' + esc(truncate(n.content, 120)) + '</div>';\n    if (n.tags && n.tags.length) {\n        h += '<div style=\"margin-bottom:4px;color:#94a3b8\">&#127991; ' + n.tags.map(function(t) { return esc(t); }).join(', ') + '</div>';\n    }\n    if (n.emotion_type) {\n        h += '<div style=\"margin-bottom:4px;color:#94a3b8\">&#128173; ' + esc(n.emotion_type) + '</div>';\n    }\n    h += '<div style=\"color:#94a3b8\">&#11088; Importance: ' + ((n.importance || 0) * 100).toFixed(0) + '%</div>';\n    el.innerHTML = h;\n    return el;\n}\n\n/* ---- Client-side filtering ---- */\n\nfunction applyGraphFilters(visNodes, visEdges) {\n    var tagFilter     = document.getElementById('graph-tag-filter');\n    var emotionFilter = document.getElementById('graph-emotion-filter');\n    var selectedTags  = Array.from(tagFilter.selectedOptions).map(function(o) { return o.value; }).filter(Boolean);\n    var selectedEmo   = emotionFilter.value;\n\n    var filtered = visNodes;\n\n    if (selectedTags.length > 0) {\n        filtered = filtered.filter(function(n) {\n            var tags = n._data.tags || [];\n            return selectedTags.some(function(t) { return tags.includes(t); });\n        });\n    }\n    if (selectedEmo) {\n        filtered = filtered.filter(function(n) { return n._data.emotion_type === selectedEmo; });\n    }\n\n    var visibleIds = new Set(filtered.map(function(n) { return n.id; }));\n    var filteredEdges = visEdges.filter(function(e) {\n        return visibleIds.has(e._from) && visibleIds.has(e._to);\n    });\n\n    return { nodes: filtered, edges: filteredEdges };\n}\n\n/* ---- Render / re-render vis.Network ---- */\n\nfunction renderNetwork(container, nodes, edges) {\n    if (typeof vis === 'undefined') {\n        container.innerHTML = errorCard('vis-network library not available. Please check internet connectivity.');\n        return;\n    }\n    var loading = document.getElementById('graph-loading');\n\n    /* Empty state */\n    if (nodes.length === 0) {\n        if (graphNetwork) { graphNetwork.destroy(); graphNetwork = null; }\n        if (loading) loading.style.display = 'none';\n        container.innerHTML =\n            '<div style=\"display:flex;align-items:center;justify-content:center;height:100%;' +\n            'color:var(--text-muted);text-align:center;padding:40px\">' +\n            '<div><div style=\"font-size:3rem;margin-bottom:16px\">\\ud83d\\udd78\\ufe0f</div>' +\n            '<p style=\"font-size:1.1rem\">No memories found. Create some memories first!</p></div></div>';\n        return;\n    }\n\n    var dataSet = {\n        nodes: new vis.DataSet(nodes),\n        edges: new vis.DataSet(edges)\n    };\n\n    var physicsEnabled = document.getElementById('graph-physics-toggle').checked;\n\n    var options = {\n        physics: {\n            enabled: physicsEnabled,\n            barnesHut: {\n                gravitationalConstant: -3000,\n                centralGravity: 0.3,\n                springLength: 120,\n                springConstant: 0.04,\n                damping: 0.09\n            },\n            stabilization: { iterations: 150, fit: true }\n        },\n        interaction: {\n            hover: true,\n            tooltipDelay: 200,\n            hideEdgesOnDrag: true,\n            hideEdgesOnZoom: true,\n            multiselect: false\n        },\n        nodes: {\n            shape: 'dot',\n            scaling: { min: 10, max: 40 },\n            font: { color: _graphFontColor(), size: 11 }\n        },\n        edges: {\n            smooth: { type: 'continuous', roundness: 0.2 }\n        },\n        layout: {\n            improvedLayout: (nodes.length < 150)\n        }\n    };\n\n    if (graphNetwork) { graphNetwork.destroy(); }\n\n    graphNetwork = new vis.Network(container, dataSet, options);\n\n    /* Click 竊・open side panel */\n    graphNetwork.on('click', function(params) {\n        if (params.nodes.length > 0) {\n            var nodeId = params.nodes[0];\n            var node = dataSet.nodes.get(nodeId);\n            if (node && node._data) {\n                openGraphDetailPanel(node._data);\n            }\n        } else {\n            closeGraphDetailPanel();\n        }\n    });\n\n    /* Double-click 竊・open full modal via openMemModal */\n    graphNetwork.on('doubleClick', function(params) {\n        if (params.nodes.length > 0) {\n            var nodeId = params.nodes[0];\n            var node = dataSet.nodes.get(nodeId);\n            if (node && node._data) {\n                var d = node._data;\n                openMemModal({\n                    memory_key:  d.key,\n                    content:     d.content,\n                    tags:        d.tags,\n                    emotion_type: d.emotion_type,\n                    importance:  d.importance\n                });\n            }\n        }\n    });\n\n    /* Stabilization done 竊・stop physics jitter */\n    graphNetwork.once('stabilizationIterationsDone', function() {\n        graphNetwork.setOptions({ physics: { stabilization: { enabled: false } } });\n    });\n}\n\n/* ---- Detail side panel ---- */\n\nfunction openGraphDetailPanel(data) {\n    var panel   = document.getElementById('graph-detail-panel');\n    var overlay = document.getElementById('graph-panel-overlay');\n    var body    = document.getElementById('graph-panel-body');\n\n    var tags = (data.tags || []).map(function(t) {\n        return '<span class=\"badge badge-purple\">' + esc(t) + '</span>';\n    }).join(' ');\n\n    var emoColor = EMOTION_COLORS[data.emotion_type] || '#94a3b8';\n\n    var html = '';\n    /* Key */\n    html += '<div style=\"margin-bottom:16px\">';\n    html += '  <div style=\"font-size:0.75rem;color:var(--text-muted);margin-bottom:4px\">Key</div>';\n    html += '  <div style=\"font-family:monospace;font-size:0.8rem;color:var(--accent-purple);word-break:break-all\">' + esc(data.key) + '</div>';\n    html += '</div>';\n\n    /* Content */\n    html += '<div style=\"margin-bottom:16px\">';\n    html += '  <div style=\"font-size:0.75rem;color:var(--text-muted);margin-bottom:4px\">Content</div>';\n    html += '  <div style=\"color:var(--text-primary);line-height:1.6;white-space:pre-wrap\">' + esc(data.content) + '</div>';\n    html += '</div>';\n\n    /* Tags */\n    if (tags) {\n        html += '<div style=\"margin-bottom:16px\">';\n        html += '  <div style=\"font-size:0.75rem;color:var(--text-muted);margin-bottom:6px\">Tags</div>';\n        html += '  <div style=\"display:flex;flex-wrap:wrap;gap:4px\">' + tags + '</div>';\n        html += '</div>';\n    }\n\n    /* Emotion */\n    if (data.emotion_type) {\n        html += '<div style=\"margin-bottom:16px\">';\n        html += '  <div style=\"font-size:0.75rem;color:var(--text-muted);margin-bottom:4px\">Emotion</div>';\n        html += '  <div style=\"display:flex;align-items:center;gap:6px\">';\n        html += '    <span style=\"width:10px;height:10px;border-radius:50%;background:' + emoColor + ';display:inline-block\"></span>';\n        html += '    <span style=\"color:var(--text-secondary)\">' + esc(data.emotion_type) + '</span>';\n        html += '  </div>';\n        html += '</div>';\n    }\n\n    /* Importance bar */\n    if (data.importance != null) {\n        var pct = (data.importance * 100).toFixed(0);\n        html += '<div style=\"margin-bottom:16px\">';\n        html += '  <div style=\"font-size:0.75rem;color:var(--text-muted);margin-bottom:4px\">Importance</div>';\n        html += '  <div style=\"display:flex;align-items:center;gap:8px\">';\n        html += '    <div style=\"flex:1;height:6px;background:rgba(255,255,255,0.1);border-radius:3px;overflow:hidden\">';\n        html += '      <div style=\"width:' + pct + '%;height:100%;background:var(--accent-yellow);border-radius:3px\"></div>';\n        html += '    </div>';\n        html += '    <span style=\"color:var(--accent-yellow);font-size:0.85rem\">' + pct + '%</span>';\n        html += '  </div>';\n        html += '</div>';\n    }\n\n    body.innerHTML = html;\n    panel.style.right = '0';\n    overlay.style.display = 'block';\n}\n\nfunction closeGraphDetailPanel() {\n    var panel   = document.getElementById('graph-detail-panel');\n    var overlay = document.getElementById('graph-panel-overlay');\n    if (panel)   panel.style.right = '-400px';\n    if (overlay) overlay.style.display = 'none';\n}\n\n/* ---- Helper: re-apply filters without refetch ---- */\n\nfunction _graphRefilter() {\n    if (!graphData) return;\n    var built    = buildVisData(graphData.nodes, graphData.edges);\n    var filtered = applyGraphFilters(built.visNodes, built.visEdges);\n    renderNetwork(document.getElementById('graph-container'), filtered.nodes, filtered.edges);\n    var statsEl = document.getElementById('graph-stats');\n    if (statsEl) {\n        statsEl.textContent = filtered.nodes.length + ' nodes \\u00b7 ' + filtered.edges.length + ' edges';\n    }\n}\n\n/* ---- Event wiring (runs once at parse time) ---- */\n\n(function setupGraphEvents() {\n    /* Limit buttons */\n    document.querySelectorAll('.graph-limit-btn').forEach(function(btn) {\n        btn.addEventListener('click', function() {\n            document.querySelectorAll('.graph-limit-btn').forEach(function(b) {\n                b.classList.remove('active');\n            });\n            this.classList.add('active');\n            graphNodeLimit = parseInt(this.dataset.limit, 10);\n            loadGraph();\n        });\n    });\n\n    /* Tag filter 竊・re-apply (no refetch) */\n    document.getElementById('graph-tag-filter').addEventListener('change', _graphRefilter);\n\n    /* Emotion filter 竊・re-apply (no refetch) */\n    document.getElementById('graph-emotion-filter').addEventListener('change', _graphRefilter);\n\n    /* Physics toggle */\n    document.getElementById('graph-physics-toggle').addEventListener('change', function() {\n        if (graphNetwork) {\n            graphNetwork.setOptions({ physics: { enabled: this.checked } });\n        }\n    });\n\n    /* Refresh button */\n    document.getElementById('graph-refresh-btn').addEventListener('click', loadGraph);\n\n    /* Close panel */\n    document.getElementById('graph-panel-close').addEventListener('click', closeGraphDetailPanel);\n    document.getElementById('graph-panel-overlay').addEventListener('click', closeGraphDetailPanel);\n\n    /* ESC key closes panel */\n    document.addEventListener('keydown', function(e) {\n        if (e.key === 'Escape') {\n            var panel = document.getElementById('graph-detail-panel');\n            if (panel && panel.style.right === '0px') {\n                closeGraphDetailPanel();\n            }\n        }\n    });\n})();\n\n\n// === Import/Export Tab ===\n\nasync function loadImportExport() {\n    loadExportPreview();\n}\n\n// --- Conversation File Import ---\nasync function importConversation() {\n    var filePath = (document.getElementById('conv-import-path').value || '').trim();\n    var resultEl = document.getElementById('conv-import-result');\n    if (!filePath) { toast('File path is required', 'error'); return; }\n    resultEl.style.display = 'block';\n    resultEl.style.color = 'var(--text-muted)';\n    resultEl.textContent = 'Importing...';\n    try {\n        var resp = await api('/api/import-conversation/' + encodeURIComponent(S.persona), {\n            method: 'POST',\n            headers: {'Content-Type': 'application/json'},\n            body: JSON.stringify({file_path: filePath})\n        });\n        resultEl.style.color = 'var(--accent-green)';\n        resultEl.textContent = '笨・Imported ' + (resp.imported || 0) + ' messages' + (resp.skipped ? ' (' + resp.skipped + ' skipped)' : '') + '.';\n        toast('Conversation imported successfully', 'success');\n    } catch (e) {\n        resultEl.style.color = 'var(--accent-red)';\n        resultEl.textContent = '笶・' + (e.message || 'Import failed');\n    }\n}\n\n// --- Drag & Drop ---\n(function initDropZone() {\n    document.addEventListener('DOMContentLoaded', function() {\n        var dz = document.getElementById('drop-zone');\n        var fi = document.getElementById('import-file');\n        if (!dz || !fi) return;\n\n        dz.addEventListener('click', function() { fi.click(); });\n        fi.addEventListener('change', function(e) {\n            if (e.target.files[0]) importData(e.target.files[0]);\n        });\n\n        dz.addEventListener('dragover', function(e) {\n            e.preventDefault();\n            dz.style.borderColor = 'var(--accent)';\n            dz.style.background = 'rgba(168,85,247,0.1)';\n        });\n        dz.addEventListener('dragleave', function(e) {\n            e.preventDefault();\n            dz.style.borderColor = 'var(--glass-border)';\n            dz.style.background = '';\n        });\n        dz.addEventListener('drop', function(e) {\n            e.preventDefault();\n            dz.style.borderColor = 'var(--glass-border)';\n            dz.style.background = '';\n            var file = e.dataTransfer.files[0];\n            if (file && file.name.endsWith('.zip')) {\n                importData(file);\n            } else {\n                toast('Please drop a .zip file', 'error');\n            }\n        });\n    });\n})();\n\n// --- Import ---\nasync function importData(file) {\n    var progress = document.getElementById('import-progress');\n    var bar = document.getElementById('import-progress-bar');\n    var status = document.getElementById('import-status');\n    var results = document.getElementById('import-results');\n\n    // Reset & show progress\n    progress.style.display = 'block';\n    results.style.display = 'none';\n    bar.style.width = '0%';\n    bar.style.background = 'linear-gradient(to right,#a855f7,#ec4899)';\n    status.textContent = 'Uploading...';\n\n    // Simulate progress\n    var pct = 0;\n    var interval = setInterval(function() {\n        pct = Math.min(pct + Math.random() * 15, 90);\n        bar.style.width = pct + '%';\n    }, 300);\n\n    try {\n        var fd = new FormData();\n        fd.append('file', file);\n        status.textContent = 'Importing ' + esc(file.name) + '...';\n\n        var resp = await fetch('/api/import/' + encodeURIComponent(S.persona), {\n            method: 'POST',\n            body: fd\n        });\n        clearInterval(interval);\n\n        if (!resp.ok) {\n            var errBody = await resp.json().catch(function() { return {}; });\n            throw new Error(errBody.detail || errBody.error || 'Import failed');\n        }\n\n        var data = await resp.json();\n        bar.style.width = '100%';\n        status.textContent = 'Import complete!';\n\n        // Show results\n        var imp = data.imported || {};\n        var cards = Object.keys(imp).map(function(k) {\n            return '<div class=\"glass p-3\" style=\"text-align:center;border-radius:8px\">'\n                + '<div style=\"font-size:1.5rem;font-weight:700;color:var(--accent)\">' + esc(String(imp[k])) + '</div>'\n                + '<div style=\"font-size:0.8rem;color:var(--text-muted)\">' + esc(k) + '</div>'\n                + '</div>';\n        }).join('');\n\n        results.style.display = 'block';\n        results.innerHTML =\n            '<div style=\"color:var(--text-primary);font-weight:600;margin-bottom:8px\">\\u2705 Import Successful</div>'\n            + '<div style=\"display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px\">'\n            + cards\n            + '</div>';\n\n        toast('Import completed successfully!', 'success');\n        loadExportPreview();\n    } catch (e) {\n        clearInterval(interval);\n        bar.style.width = '100%';\n        bar.style.background = 'linear-gradient(to right,#ef4444,#dc2626)';\n        status.textContent = 'Import failed: ' + e.message;\n        toast('Import failed: ' + e.message, 'error');\n    }\n\n    // Reset file input\n    document.getElementById('import-file').value = '';\n}\n\n// --- Export ---\nasync function exportData() {\n    var fmt = document.getElementById('export-format').value;\n    if (!S.persona) { toast('No persona selected', 'error'); return; }\n\n    try {\n        toast('Preparing export...', 'info');\n\n        if (fmt === 'zip') {\n            var url = '/api/export/' + encodeURIComponent(S.persona);\n            var a = document.createElement('a');\n            a.href = url;\n            a.download = S.persona + '_export.zip';\n            document.body.appendChild(a);\n            a.click();\n            document.body.removeChild(a);\n            toast('Download started!', 'success');\n        } else {\n            var data = await api('/api/dashboard/' + encodeURIComponent(S.persona));\n            var blob = new Blob([JSON.stringify(data, null, 2)], {type: 'application/json'});\n            var blobUrl = URL.createObjectURL(blob);\n            var a2 = document.createElement('a');\n            a2.href = blobUrl;\n            a2.download = S.persona + '_memories.json';\n            document.body.appendChild(a2);\n            a2.click();\n            document.body.removeChild(a2);\n            URL.revokeObjectURL(blobUrl);\n            toast('JSON export downloaded!', 'success');\n        }\n    } catch (e) {\n        toast('Export failed: ' + e.message, 'error');\n    }\n}\n\n// --- Export Preview ---\nasync function loadExportPreview() {\n    var el = document.getElementById('export-preview');\n    if (!el || !S.persona) return;\n\n    try {\n        var data = await api('/api/dashboard/' + encodeURIComponent(S.persona));\n        var stats = data.stats || {};\n        var items = data.items || [];\n        var equip = data.equipment || {};\n        var equipCount = Object.values(equip).filter(function(v) { return v; }).length;\n\n        el.innerHTML =\n            '<div style=\"display:flex;gap:16px;flex-wrap:wrap\">'\n            + '<span>\\uD83D\\uDCDD <strong>' + (stats.total_count || 0) + '</strong> memories</span>'\n            + '<span>\\uD83C\\uDF92 <strong>' + items.length + '</strong> items</span>'\n            + '<span>\\u2694\\uFE0F <strong>' + equipCount + '</strong> equipped slots</span>'\n            + '</div>';\n    } catch (e) {\n        el.innerHTML = '<span style=\"color:#ef4444\">Failed to load preview</span>';\n    }\n}\n\n// === Persona Management Tab ===\n\nasync function loadPersonas() {\n    var grid = document.getElementById('persona-grid');\n    if (!grid) return;\n    grid.innerHTML = '<div style=\"text-align:center;color:var(--text-muted);padding:40px\">Loading personas...</div>';\n    try {\n        var listData = await api('/api/personas');\n        var personas = listData.personas || [];\n        if (personas.length === 0) {\n            grid.innerHTML = '<div style=\"text-align:center;color:var(--text-muted);padding:40px\">No personas found. Create one!</div>';\n            return;\n        }\n        var details = await Promise.allSettled(\n            personas.map(function(p) { return api('/api/dashboard/' + encodeURIComponent(p)); })\n        );\n        var html = '';\n        var emotionEmoji = {\n            joy: '・', sadness: '个', anger: '丐', fear: '于',\n            surprise: '亟', disgust: '､｢', trust: '､・, anticipation: '､ｩ',\n            love: '\\u2764\\ufe0f', neutral: '・'\n        };\n        personas.forEach(function(name, i) {\n            var d = details[i].status === 'fulfilled' ? details[i].value : {};\n            var stats = d.stats || {};\n            var ctx = d.context || {};\n            var isActive = name === S.persona;\n            var lastConv = ctx.last_conversation_time;\n            var memCount = stats.total_count || 0;\n            var emotionType = ctx.emotion || 'neutral';\n            var emotionIntensity = ctx.emotion_intensity != null ? ctx.emotion_intensity : 0;\n            var emoji = emotionEmoji[emotionType] || '・';\n            var activeBorder = isActive\n                ? 'border:2px solid var(--accent);box-shadow:0 0 20px rgba(168,85,247,0.3)'\n                : 'border:1px solid var(--glass-border)';\n            var activeBadge = isActive\n                ? '<span style=\"font-size:0.75rem;background:var(--accent);color:white;padding:2px 8px;border-radius:9999px;margin-left:8px\">Active</span>'\n                : '';\n            var switchBtn = !isActive\n                ? '<button onclick=\"switchPersonaTo(\\'' + esc(name) + '\\')\" class=\"glass-btn\" style=\"padding:6px 14px;font-size:0.85rem\">売 Switch</button>'\n                : '';\n            var deleteStyle = name === 'default'\n                ? 'padding:6px 14px;font-size:0.85rem;opacity:0.5;cursor:not-allowed'\n                : 'padding:6px 14px;font-size:0.85rem';\n            var deleteDisabled = name === 'default' ? ' disabled' : '';\n            html += '<div class=\"glass p-5\" style=\"border-radius:12px;' + activeBorder + '\">'\n                + '<div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:12px\">'\n                + '<div style=\"font-size:1.1rem;font-weight:600;color:var(--text-primary)\">'\n                + '側 ' + esc(name) + activeBadge\n                + '</div></div>'\n                + '<div style=\"display:flex;flex-direction:column;gap:6px;font-size:0.9rem;color:var(--text-muted);margin-bottom:16px\">'\n                + '<div>統 <strong>' + memCount + '</strong> memories</div>'\n                + '<div>眺 Last: ' + (lastConv ? relativeTime(lastConv) : 'Never') + '</div>'\n                + '<div>' + emoji + ' ' + esc(emotionType) + ' (' + emotionIntensity.toFixed(1) + ')</div>'\n                + '</div>'\n                + '<div style=\"display:flex;gap:8px;flex-wrap:wrap\">'\n                + '<button onclick=\"editPersonaProfile(\\'' + esc(name) + '\\')\" class=\"glass-btn\" style=\"padding:6px 14px;font-size:0.85rem\">\\u270f\\ufe0f Edit</button>'\n                + switchBtn\n                + '<button onclick=\"deletePersona(\\'' + esc(name) + '\\')\" class=\"glass-btn\" style=\"' + deleteStyle + '\"' + deleteDisabled + '>卵・・Delete</button>'\n                + '</div></div>';\n        });\n        grid.innerHTML = html;\n    } catch (e) {\n        grid.innerHTML = '<div style=\"text-align:center;color:#ef4444;padding:40px\">Failed to load personas: ' + esc(e.message) + '</div>';\n    }\n}\n\n// --- Create Persona ---\nfunction showCreatePersona() {\n    var modal = document.getElementById('create-persona-modal');\n    modal.style.display = 'flex';\n    document.getElementById('new-persona-name').value = '';\n    document.getElementById('new-persona-name').focus();\n}\n\nfunction hideCreatePersona() {\n    document.getElementById('create-persona-modal').style.display = 'none';\n}\n\nasync function createPersona() {\n    var name = document.getElementById('new-persona-name').value.trim();\n    if (!name) { toast('Please enter a name', 'error'); return; }\n    if (!/^[a-zA-Z0-9_-]{1,50}$/.test(name)) {\n        toast('Name must be 1-50 chars: letters, numbers, _, -', 'error');\n        return;\n    }\n    try {\n        await api('/api/personas', {\n            method: 'POST',\n            headers: {'Content-Type': 'application/json'},\n            body: JSON.stringify({name: name})\n        });\n        toast('Persona \"' + name + '\" created!', 'success');\n        hideCreatePersona();\n        loadPersonas();\n    } catch (e) {\n        toast('Failed to create persona: ' + e.message, 'error');\n    }\n}\n\n// --- Edit Profile ---\nasync function editPersonaProfile(name) {\n    var modal = document.getElementById('profile-edit-modal');\n    document.getElementById('edit-persona-name').value = name;\n    document.getElementById('edit-persona-name-display').textContent = name;\n    try {\n        var data = await api('/api/dashboard/' + encodeURIComponent(name));\n        var ctx = data.context || {};\n        var ui = ctx.user_info || {};\n        var pi = ctx.persona_info || {};\n        document.getElementById('edit-user-name').value = ui.name || '';\n        document.getElementById('edit-user-nickname').value = ui.nickname || '';\n        document.getElementById('edit-user-preferred-address').value = ui.preferred_address || '';\n        document.getElementById('edit-persona-nickname').value = pi.nickname || '';\n        document.getElementById('edit-relationship-status').value = ctx.relationship_status || '';\n    } catch (e) {\n        document.getElementById('edit-user-name').value = '';\n        document.getElementById('edit-user-nickname').value = '';\n        document.getElementById('edit-user-preferred-address').value = '';\n        document.getElementById('edit-persona-nickname').value = '';\n        document.getElementById('edit-relationship-status').value = '';\n    }\n    modal.style.display = 'flex';\n}\n\nfunction hideEditProfile() {\n    document.getElementById('profile-edit-modal').style.display = 'none';\n}\n\nasync function saveProfile() {\n    var name = document.getElementById('edit-persona-name').value;\n    var userName = document.getElementById('edit-user-name').value.trim();\n    var userNickname = document.getElementById('edit-user-nickname').value.trim();\n    var userPreferred = document.getElementById('edit-user-preferred-address').value.trim();\n    var personaNickname = document.getElementById('edit-persona-nickname').value.trim();\n    var relStatus = document.getElementById('edit-relationship-status').value.trim();\n    var body = {};\n    var userInfo = {};\n    if (userName) userInfo.name = userName;\n    if (userNickname) userInfo.nickname = userNickname;\n    if (userPreferred) userInfo.preferred_address = userPreferred;\n    if (Object.keys(userInfo).length > 0) body.user_info = userInfo;\n    var personaInfo = {};\n    if (personaNickname) personaInfo.nickname = personaNickname;\n    if (Object.keys(personaInfo).length > 0) body.persona_info = personaInfo;\n    if (relStatus) body.relationship_status = relStatus;\n    if (Object.keys(body).length === 0) {\n        toast('No changes to save', 'info');\n        return;\n    }\n    try {\n        await api('/api/personas/' + encodeURIComponent(name) + '/profile', {\n            method: 'PUT',\n            headers: {'Content-Type': 'application/json'},\n            body: JSON.stringify(body)\n        });\n        toast('Profile updated!', 'success');\n        hideEditProfile();\n        loadPersonas();\n    } catch (e) {\n        toast('Failed to update profile: ' + e.message, 'error');\n    }\n}\n\n// --- Delete Persona ---\nasync function deletePersona(name) {\n    if (name === 'default') {\n        toast('Cannot delete the default persona', 'error');\n        return;\n    }\n    if (name === S.persona) {\n        toast('Cannot delete the active persona. Switch first.', 'error');\n        return;\n    }\n    if (!confirm('Are you sure you want to delete persona \"' + name + '\"?\\nAll memories will be permanently lost.')) return;\n    try {\n        await api('/api/personas/' + encodeURIComponent(name), { method: 'DELETE' });\n        toast('Persona \"' + name + '\" deleted', 'success');\n        loadPersonas();\n    } catch (e) {\n        toast('Failed to delete persona: ' + e.message, 'error');\n    }\n}\n\n// --- Switch Persona ---\nfunction switchPersonaTo(name) {\n    S.persona = name;\n    var sel = document.getElementById('persona-select');\n    if (sel) sel.value = name;\n    loadPersonas();\n    toast('Switched to persona: ' + name, 'success');\n}\n\n\n/* =================================================================\n   CHAT TAB\n   ================================================================= */\nconst CHAT = {\n    streaming: false,\n    sidebarOpen: true,\n    memoryPanelOpen: true,\n    messages: [],  // { role, content, time }\n    mcpServers: [],\n    enabledSkills: [],\n    abortController: null,  // F4: AbortController for streaming cancel\n    attachments: [],  // { filename, url, workspace_path, mime_type, size }\n};\n\nfunction loadChat() {\n    if (!S.persona) return;\n    loadChatConfig();\n    loadSkillsForChat();\n    restoreChatHistory();\n    loadChatCommitments();\n}\n\nasync function loadChatCommitments() {\n    if (!S.persona) return;\n    try {\n        const data = await api('/api/chat/' + encodeURIComponent(S.persona) + '/commitments');\n        if (Array.isArray(data.goals) || Array.isArray(data.promises)) {\n            updateMemoryPanel(undefined, undefined, data.goals || [], data.promises || []);\n        }\n        if (data.insights && data.insights.length > 0) {\n            updateReflectionPanel(data.insights);\n        }\n    } catch (_e) {\n        // commitments API unavailable 窶・ignore silently\n    }\n}\n\nasync function loadSkillsForChat() {\n    try {\n        const skills = await api('/api/skills');\n        renderSkillsList(skills, CHAT.enabledSkills);\n    } catch (_e) {\n        // skills API not available yet, ignore\n    }\n}\n\nasync function loadChatConfig() {\n    try {\n        const cfg = await api('/api/chat/' + encodeURIComponent(S.persona) + '/config');\n        applyChatConfig(cfg);\n    } catch (e) {\n        document.getElementById('chat-config-status').textContent = '險ｭ螳夊ｪｭ霎ｼ螟ｱ謨・ ' + e.message;\n    }\n}\n\nfunction applyChatConfig(cfg) {\n    if (!cfg) return;\n    const set = (id, v) => { const el = document.getElementById(id); if (el && v !== undefined && v !== null) el.value = v; };\n    const setChecked = (id, v) => { const el = document.getElementById(id); if (el) el.checked = v === true; };\n    set('chat-provider', cfg.provider);\n    set('chat-model', cfg.model || '');\n    set('chat-api-key', cfg.api_key || '');\n    set('chat-base-url', cfg.base_url || '');\n    set('chat-temperature', cfg.temperature != null ? cfg.temperature : 0.7);\n    set('chat-max-tokens', cfg.max_tokens || 2048);\n    set('chat-window-turns', cfg.max_window_turns || 3);\n    set('chat-max-tool-calls', cfg.max_tool_calls || 5);\n    set('chat-system-prompt', cfg.system_prompt || '');\n    setChecked('chat-auto-extract', cfg.auto_extract !== false);\n    set('chat-extract-model', cfg.extract_model || '');\n    set('chat-extract-max-tokens', cfg.extract_max_tokens || 512);\n    setChecked('chat-enable-memory-tools', cfg.enable_memory_tools !== false);\n    // Temperature display sync\n    const tempEl = document.getElementById('chat-temp-val');\n    const tempSlider = document.getElementById('chat-temperature');\n    if (tempEl && tempSlider) {\n        tempEl.textContent = parseFloat(tempSlider.value).toFixed(2);\n    }\n    onChatProviderChange();\n    CHAT.mcpServers = cfg.mcp_servers || [];\n    renderMcpJson(CHAT.mcpServers);\n    const toolMax = document.getElementById('chat-tool-result-max');\n    const toolMaxVal = document.getElementById('chat-tool-max-val');\n    if (toolMax && cfg.tool_result_max_chars) {\n        toolMax.value = cfg.tool_result_max_chars;\n        if (toolMaxVal) toolMaxVal.textContent = cfg.tool_result_max_chars;\n    }\n    CHAT.enabledSkills = cfg.enabled_skills || [];\n    // Reflection settings\n    setChecked('chat-reflection-enabled', cfg.reflection_enabled !== false);\n    set('chat-reflection-threshold', cfg.reflection_threshold != null ? cfg.reflection_threshold : 1.0);\n    set('chat-reflection-interval', cfg.reflection_min_interval_hours != null ? cfg.reflection_min_interval_hours : 1.0);\n    setChecked('chat-session-summarize', cfg.session_summarize !== false);\n    // Mental model settings\n    setChecked('chat-mental-model-enabled', cfg.mental_model_enabled !== false);\n    set('chat-mental-model-min-samples', cfg.mental_model_min_samples != null ? cfg.mental_model_min_samples : 3);\n    // Retrieval weights\n    const setSlider = (id, valId, v) => {\n        const el = document.getElementById(id);\n        const vel = document.getElementById(valId);\n        if (el && v != null) { el.value = v; if (vel) vel.textContent = parseFloat(v).toFixed(2); }\n    };\n    setSlider('chat-recency-weight', 'chat-recency-weight-val', cfg.retrieval_recency_weight != null ? cfg.retrieval_recency_weight : 0.3);\n    setSlider('chat-importance-weight', 'chat-importance-weight-val', cfg.retrieval_importance_weight != null ? cfg.retrieval_importance_weight : 0.3);\n    setSlider('chat-relevance-weight', 'chat-relevance-weight-val', cfg.retrieval_relevance_weight != null ? cfg.retrieval_relevance_weight : 0.4);\n    // Housekeeping settings\n    set('chat-display-history-turns', cfg.display_history_turns != null ? cfg.display_history_turns : 20);\n    set('chat-housekeeping-threshold', cfg.housekeeping_threshold != null ? cfg.housekeeping_threshold : 10);\n    // Sandbox settings\n    setChecked('chat-sandbox-enabled', cfg.sandbox_enabled === true);\n    onSandboxEnabledChange();\n    // Debug mode\n    setChecked('chat-debug-mode', cfg.debug_mode === true);\n    const statusEl = document.getElementById('chat-config-status');\n    if (statusEl) {\n        if (cfg.is_configured) {\n            statusEl.innerHTML = '<span style=\"color:var(--accent-green)\">笨・API繧ｭ繝ｼ險ｭ螳壽ｸ医∩</span>';\n        } else {\n            statusEl.innerHTML = '<span style=\"color:var(--accent-yellow)\">笞 API繧ｭ繝ｼ譛ｪ險ｭ螳・/span>';\n        }\n    }\n}\n\nfunction onChatProviderChange() {\n    const provider = document.getElementById('chat-provider').value;\n    const baseUrlRow = document.getElementById('chat-base-url-row');\n    if (baseUrlRow) {\n        baseUrlRow.style.display = (provider === 'openrouter' || provider === 'openai') ? '' : 'none';\n    }\n}\n\nasync function saveChatConfig() {\n    if (!S.persona) { toast('繝壹Ν繧ｽ繝翫ｒ驕ｸ謚槭＠縺ｦ縺上□縺輔＞', 'error'); return; }\n    const apiKeyEl = document.getElementById('chat-api-key');\n    const apiKeyVal = apiKeyEl ? apiKeyEl.value.trim() : '';\n    const getChecked = (id) => document.getElementById(id)?.checked ?? false;\n    const payload = {\n        provider: document.getElementById('chat-provider').value,\n        model: document.getElementById('chat-model').value.trim(),\n        api_key: apiKeyVal,\n        base_url: document.getElementById('chat-base-url').value.trim(),\n        temperature: parseFloat(document.getElementById('chat-temperature').value),\n        max_tokens: parseInt(document.getElementById('chat-max-tokens').value),\n        max_window_turns: parseInt(document.getElementById('chat-window-turns').value),\n        max_tool_calls: parseInt(document.getElementById('chat-max-tool-calls')?.value || '5'),\n        system_prompt: document.getElementById('chat-system-prompt').value.trim(),\n        auto_extract: getChecked('chat-auto-extract'),\n        extract_model: document.getElementById('chat-extract-model')?.value.trim() || '',\n        extract_max_tokens: parseInt(document.getElementById('chat-extract-max-tokens')?.value || '512'),\n        enable_memory_tools: getChecked('chat-enable-memory-tools'),\n        mcp_servers: parseMcpJson(),\n        tool_result_max_chars: parseInt(document.getElementById('chat-tool-result-max')?.value || '4000'),\n        enabled_skills: CHAT.enabledSkills,\n        reflection_enabled: getChecked('chat-reflection-enabled'),\n        reflection_threshold: parseFloat(document.getElementById('chat-reflection-threshold')?.value || '1.0'),\n        reflection_min_interval_hours: parseFloat(document.getElementById('chat-reflection-interval')?.value || '1.0'),\n        session_summarize: getChecked('chat-session-summarize'),\n        retrieval_recency_weight: parseFloat(document.getElementById('chat-recency-weight')?.value || '0.3'),\n        retrieval_importance_weight: parseFloat(document.getElementById('chat-importance-weight')?.value || '0.3'),\n        retrieval_relevance_weight: parseFloat(document.getElementById('chat-relevance-weight')?.value || '0.4'),\n        display_history_turns: parseInt(document.getElementById('chat-display-history-turns')?.value || '20'),\n        housekeeping_threshold: parseInt(document.getElementById('chat-housekeeping-threshold')?.value || '10'),\n        sandbox_enabled: getChecked('chat-sandbox-enabled'),\n        mental_model_enabled: getChecked('chat-mental-model-enabled'),\n        mental_model_min_samples: parseInt(document.getElementById('chat-mental-model-min-samples')?.value || '3'),\n        debug_mode: getChecked('chat-debug-mode'),\n    };\n    try {\n        const cfg = await api('/api/chat/' + encodeURIComponent(S.persona) + '/config', {\n            method: 'POST',\n            body: JSON.stringify(payload),\n        });\n        applyChatConfig(cfg);\n        toast('繝√Ε繝・ヨ險ｭ螳壹ｒ菫晏ｭ倥＠縺ｾ縺励◆', 'success');\n    } catch (e) {\n        toast('菫晏ｭ伜､ｱ謨・ ' + e.message, 'error');\n    }\n}\n\nfunction renderMcpJson(servers) {\n    const ta = document.getElementById('chat-mcp-json');\n    if (!ta) return;\n    if (!servers || servers.length === 0) {\n        ta.value = '{\\n  \"mcpServers\": {}\\n}';\n        return;\n    }\n    const mcpServers = {};\n    (servers || []).forEach(srv => {\n        const entry = {};\n        if (srv.transport === 'http') {\n            entry.url = srv.url || '';\n            if (srv.headers && Object.keys(srv.headers).length) entry.headers = srv.headers;\n        } else {\n            entry.command = srv.command || '';\n            if (srv.args && srv.args.length) entry.args = srv.args;\n            if (srv.headers && Object.keys(srv.headers).length) entry.env = srv.headers;\n        }\n        mcpServers[srv.name] = entry;\n    });\n    ta.value = JSON.stringify({ mcpServers }, null, 2);\n}\n\nfunction parseMcpJson() {\n    const ta = document.getElementById('chat-mcp-json');\n    const errEl = document.getElementById('chat-mcp-json-error');\n    if (!ta) return CHAT.mcpServers;\n    if (errEl) errEl.style.display = 'none';\n    const raw = ta.value.trim();\n    if (!raw || raw === '{\\n  \"mcpServers\": {}\\n}') return [];\n    try {\n        const parsed = JSON.parse(raw);\n        const dict = parsed.mcpServers || {};\n        return Object.entries(dict).map(([name, cfg]) => ({\n            name,\n            transport: cfg.url ? 'http' : 'stdio',\n            url: cfg.url || '',\n            command: cfg.command || '',\n            args: cfg.args || [],\n            headers: cfg.headers || cfg.env || {},\n            enabled: true,\n        }));\n    } catch (e) {\n        if (errEl) { errEl.textContent = 'JSON蠖｢蠑上お繝ｩ繝ｼ: ' + e.message; errEl.style.display = ''; }\n        return CHAT.mcpServers;\n    }\n}\n\nfunction renderSkillsList(allSkills, enabledSkills) {\n    const list = document.getElementById('chat-skills-list');\n    if (!list) return;\n    list.innerHTML = '';\n    if (!allSkills || allSkills.length === 0) {\n        list.innerHTML = '<div style=\"font-size:0.75rem;color:var(--text-muted);\">繧ｹ繧ｭ繝ｫ縺後≠繧翫∪縺帙ｓ</div>';\n        return;\n    }\n    allSkills.forEach(skill => {\n        const enabled = (enabledSkills || []).includes(skill.name);\n        const item = document.createElement('div');\n        item.style.cssText = 'display:flex;align-items:center;gap:8px;';\n        const cb = document.createElement('input');\n        cb.type = 'checkbox';\n        cb.checked = enabled;\n        cb.id = 'skill-cb-' + skill.name;\n        cb.style.cssText = 'width:14px;height:14px;accent-color:var(--accent-purple);cursor:pointer;';\n        cb.addEventListener('change', () => {\n            if (cb.checked) {\n                if (!CHAT.enabledSkills.includes(skill.name)) CHAT.enabledSkills.push(skill.name);\n            } else {\n                CHAT.enabledSkills = CHAT.enabledSkills.filter(n => n !== skill.name);\n            }\n        });\n        const label = document.createElement('label');\n        label.htmlFor = cb.id;\n        label.style.cssText = 'font-size:0.78rem;color:var(--text-secondary);cursor:pointer;';\n        label.title = skill.description || '';\n        label.textContent = skill.name;\n        item.appendChild(cb);\n        item.appendChild(label);\n        list.appendChild(item);\n    });\n}\n\nfunction toggleSettingsPanel() {\n    const sidebar = document.getElementById('settings-panel');\n    const btn = document.getElementById('chat-sidebar-toggle-btn');\n    CHAT.sidebarOpen = !CHAT.sidebarOpen;\n    if (CHAT.sidebarOpen) {\n        sidebar.style.width = '280px';\n        sidebar.style.overflow = 'auto';\n        sidebar.style.padding = '16px';\n        sidebar.style.display = 'flex';\n        if (btn) btn.textContent = '笞呻ｸ・險ｭ螳・;\n    } else {\n        sidebar.style.width = '0';\n        sidebar.style.overflow = 'hidden';\n        sidebar.style.padding = '0';\n        if (btn) btn.textContent = '笞呻ｸ・;\n    }\n}\n\nfunction toggleMemoryPanel() {\n    const panel = document.getElementById('memory-panel');\n    CHAT.memoryPanelOpen = !CHAT.memoryPanelOpen;\n    if (!panel) return;\n    if (CHAT.memoryPanelOpen) {\n        panel.style.display = 'flex';\n    } else {\n        panel.style.display = 'none';\n    }\n    document.querySelectorAll('.mem-panel-toggle').forEach(b => b.classList.toggle('active', CHAT.memoryPanelOpen));\n}\n\nfunction renderDebugPanel(anchorEl, data) {\n    try {\n        console.group('[debug_info]');\n        const SECTIONS = ['system_prompt','context_summary','memories_raw','tool_calls','messages_sent','context_state','skills_raw'];\n        for (const key of SECTIONS) {\n            if (data[key] !== undefined && data[key] !== null) {\n                console.debug(key + ':', data[key]);\n            }\n        }\n        const extra = Object.fromEntries(Object.entries(data).filter(([k]) => !['type',...SECTIONS].includes(k)));\n        if (Object.keys(extra).length) console.debug('extra:', extra);\n        console.groupEnd();\n    } catch (e) {\n        console.error('[debug panel render error]', e);\n    }\n}\n\n/* 笏笏 Memory Panel helpers 笏笏 */\nfunction updateMemoryPanel(retrieved, saved, goals, promises) {\n    const escAttr = (s) => String(s).replace(/&/g,'&amp;').replace(/\"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');\n    if (retrieved !== undefined) {\n        const retrievedList = document.getElementById('memory-retrieved-list');\n        if (retrievedList) {\n            if (!retrieved || retrieved.length === 0) {\n                retrievedList.innerHTML = '<div class=\"memory-empty\">縺ｪ縺・/div>';\n            } else {\n                retrievedList.innerHTML = retrieved.map(m => {\n                    const score = m.score != null ? parseFloat(m.score).toFixed(3) : '';\n                    const imp = m.importance != null ? parseFloat(m.importance).toFixed(2) : '';\n                    const content = esc((m.content || '').substring(0, 80));\n                    const meta = [score ? 'score:' + score : '', imp ? 'imp:' + imp : ''].filter(Boolean).join(' ');\n                    const key = m.key || '';\n                    return '<div class=\"memory-item-card\" data-key=\"' + escAttr(key) + '\" data-content=\"' + escAttr(m.content || '') + '\" data-importance=\"' + (m.importance || 0.5) + '\" data-tags=\"' + escAttr((m.tags || []).join(',')) + '\" onclick=\"openMemEdit(this)\">' +\n                        (meta ? '<div class=\"mem-score\">' + esc(meta) + '</div>' : '') +\n                        content +\n                        '<div class=\"mem-actions\"><button class=\"mem-action-btn del\" onclick=\"event.stopPropagation();deleteMemCard(\\'' + escAttr(key) + '\\')\">蜑企勁</button></div>' +\n                        '</div>';\n                }).join('');\n            }\n        }\n    }\n    if (saved !== undefined) {\n        const savedList = document.getElementById('memory-saved-list');\n        if (savedList) {\n            if (!saved || saved.length === 0) {\n                savedList.innerHTML = '<div class=\"memory-empty\">縺ｪ縺・/div>';\n            } else {\n                savedList.innerHTML = saved.map(m => {\n                    const content = esc((m.content || '').substring(0, 80));\n                    const tags = m.tags ? m.tags.join(', ') : '';\n                    const key = m.key || '';\n                    return '<div class=\"memory-item-card\" data-key=\"' + escAttr(key) + '\" data-content=\"' + escAttr(m.content || '') + '\" data-importance=\"' + (m.importance || 0.5) + '\" data-tags=\"' + escAttr((m.tags || []).join(',')) + '\" onclick=\"openMemEdit(this)\">' + content +\n                        (tags ? '<div class=\"mem-score\">' + esc(tags) + '</div>' : '') +\n                        '<div class=\"mem-actions\"><button class=\"mem-action-btn del\" onclick=\"event.stopPropagation();deleteMemCard(\\'' + escAttr(key) + '\\')\">蜑企勁</button></div>' +\n                        '</div>';\n                }).join('');\n            }\n        }\n    }\n    if (goals !== undefined) {\n        const goalsList = document.getElementById('memory-goals-list');\n        if (goalsList) {\n            if (!goals || goals.length === 0) {\n                goalsList.innerHTML = '<div class=\"memory-empty\">縺ｪ縺・/div>';\n            } else {\n                goalsList.innerHTML = goals.map(g => {\n                    const key = g.key || '';\n                    return '<div class=\"memory-item-card\" data-key=\"' + escAttr(key) + '\" data-content=\"' + escAttr(g.content || '') + '\" data-importance=\"' + (g.importance || 0.75) + '\" data-tags=\"' + escAttr((g.tags || []).join(',')) + '\" onclick=\"openMemEdit(this)\">' +\n                        '識 ' + esc((g.content || '').substring(0, 80)) +\n                        '<div class=\"mem-actions\"><button class=\"mem-action-btn done\" onclick=\"event.stopPropagation();completeGoal(\\'' + escAttr(key) + '\\',\\'' + escAttr((g.content || '').substring(0, 50)) + '\\')\">螳御ｺ・/button><button class=\"mem-action-btn del\" onclick=\"event.stopPropagation();deleteMemCard(\\'' + escAttr(key) + '\\')\">蜑企勁</button></div>' +\n                        '</div>';\n                }).join('');\n            }\n        }\n    }\n    if (promises !== undefined) {\n        const promisesList = document.getElementById('memory-promises-list');\n        if (promisesList) {\n            if (!promises || promises.length === 0) {\n                promisesList.innerHTML = '<div class=\"memory-empty\">縺ｪ縺・/div>';\n            } else {\n                promisesList.innerHTML = promises.map(p => {\n                    const key = p.key || '';\n                    return '<div class=\"memory-item-card\" data-key=\"' + escAttr(key) + '\" data-content=\"' + escAttr(p.content || '') + '\" data-importance=\"' + (p.importance || 0.8) + '\" data-tags=\"' + escAttr((p.tags || []).join(',')) + '\" onclick=\"openMemEdit(this)\">' +\n                        '､・' + esc((p.content || '').substring(0, 80)) +\n                        '<div class=\"mem-actions\"><button class=\"mem-action-btn done\" onclick=\"event.stopPropagation();fulfillPromise(\\'' + escAttr(key) + '\\',\\'' + escAttr((p.content || '').substring(0, 50)) + '\\')\">驕り｡・/button><button class=\"mem-action-btn del\" onclick=\"event.stopPropagation();deleteMemCard(\\'' + escAttr(key) + '\\')\">蜑企勁</button></div>' +\n                        '</div>';\n                }).join('');\n            }\n        }\n    }\n}\n\nfunction showReflectionStart() {\n    const header = document.getElementById('reflection-header');\n    if (header) header.textContent = '笨ｨ 繝ｪ繝輔Ξ繧ｯ繧ｷ繝ｧ繝ｳ (螳溯｡御ｸｭ...)';\n    const list = document.getElementById('memory-reflection-list');\n    if (list) list.innerHTML = '<div class=\"memory-empty\" style=\"color:var(--accent-purple);\">蛻・梵荳ｭ...</div>';\n}\n\nfunction updateReflectionPanel(insights) {\n    const header = document.getElementById('reflection-header');\n    if (header) header.textContent = '笨ｨ 繝ｪ繝輔Ξ繧ｯ繧ｷ繝ｧ繝ｳ';\n    const list = document.getElementById('memory-reflection-list');\n    if (!list) return;\n    if (!insights || insights.length === 0) {\n        list.innerHTML = '<div class=\"memory-empty\">豢槫ｯ溘↑縺・/div>';\n        return;\n    }\n    list.innerHTML = insights.map(s =>\n        '<div class=\"reflection-insight\">' + esc(s) + '</div>'\n    ).join('');\n}\n\nfunction showSessionSummarized(summary) {\n    const statusEl = document.getElementById('chat-status');\n    if (statusEl) {\n        statusEl.textContent = '統 繧ｻ繝・す繝ｧ繝ｳ繧定ｦ∫ｴ・＠縺ｾ縺励◆';\n        setTimeout(() => { if (statusEl) statusEl.textContent = ''; }, 3000);\n    }\n}\n\nfunction clearChatHistory() {\n    CHAT.messages = [];\n    const container = document.getElementById('chat-messages');\n    container.innerHTML = `\n        <div class=\"chat-welcome\" id=\"chat-welcome\">\n            <div class=\"chat-welcome-icon\">町</div>\n            <p>繝√Ε繝・ヨ繧帝幕蟋九☆繧九↓縺ｯ荳九・繝・く繧ｹ繝医・繝・け繧ｹ縺ｫ繝｡繝・そ繝ｼ繧ｸ繧貞・蜉帙＠縺ｦ縺上□縺輔＞縲・/p>\n        </div>`;\n    // Delete server-side session (F3)\n    const oldSid = getChatSessionId();\n    if (S.persona && oldSid) {\n        fetch('/api/chat/' + encodeURIComponent(S.persona) + '/sessions/' + encodeURIComponent(oldSid), { method: 'DELETE' })\n            .catch(() => {/* ignore */});\n    }\n    // Generate a new session ID (persona-scoped key)\n    const newSession = 'sess_' + Date.now();\n    const storageKey = 'chat_session_id_' + (S.persona || 'default');\n    localStorage.setItem(storageKey, newSession);\n    document.getElementById('chat-status').textContent = '莨夊ｩｱ繧偵Μ繧ｻ繝・ヨ縺励∪縺励◆';\n    setTimeout(() => { document.getElementById('chat-status').textContent = ''; }, 2000);\n}\n\nfunction getChatSessionId() {\n    const storageKey = 'chat_session_id_' + (S.persona || 'default');\n    let sid = localStorage.getItem(storageKey);\n    if (!sid) {\n        sid = 'sess_' + Date.now();\n        localStorage.setItem(storageKey, sid);\n    }\n    return sid;\n}\n\nfunction appendChatMessage(role, content, timeStr, isMarkdown) {\n    const container = document.getElementById('chat-messages');\n    // Remove welcome message if present\n    const welcome = container.querySelector('.chat-welcome');\n    if (welcome) welcome.remove();\n\n    const div = document.createElement('div');\n    div.className = 'chat-msg ' + role;\n    const bubble = document.createElement('div');\n    bubble.className = 'chat-bubble';\n    if (isMarkdown && role === 'assistant') {\n        bubble.innerHTML = safeMarkdown(content);\n    } else {\n        bubble.textContent = content;\n    }\n    const timeDiv = document.createElement('div');\n    timeDiv.className = 'chat-time';\n    timeDiv.textContent = timeStr || new Date().toLocaleTimeString('ja-JP', {hour:'2-digit',minute:'2-digit'});\n    div.appendChild(bubble);\n    div.appendChild(timeDiv);\n\n    // Action buttons\n    const actions = document.createElement('div');\n    actions.className = 'chat-msg-actions';\n    if (role === 'user') {\n        const editBtn = document.createElement('button');\n        editBtn.className = 'chat-msg-action-btn edit';\n        editBtn.textContent = '笨擾ｸ・邱ｨ髮・;\n        editBtn.onclick = () => {\n            const inputEl = document.getElementById('chat-input');\n            if (inputEl) {\n                inputEl.value = content;\n                inputEl.focus();\n                inputEl.dispatchEvent(new Event('input'));\n            }\n        };\n        actions.appendChild(editBtn);\n    } else if (role === 'assistant') {\n        const retryBtn = document.createElement('button');\n        retryBtn.className = 'chat-msg-action-btn retry';\n        retryBtn.textContent = '売 蜀咲函謌・;\n        retryBtn.onclick = () => { chatSend(true); };\n        actions.appendChild(retryBtn);\n        const copyBtn = document.createElement('button');\n        copyBtn.className = 'chat-msg-action-btn';\n        copyBtn.textContent = '搭';\n        copyBtn.title = '繧ｳ繝斐・';\n        copyBtn.onclick = () => {\n            navigator.clipboard.writeText(content).then(() => toast('繧ｳ繝斐・縺励∪縺励◆', 'success'));\n        };\n        actions.appendChild(copyBtn);\n    }\n    div.appendChild(actions);\n\n    container.appendChild(div);\n    container.scrollTop = container.scrollHeight;\n    return div;\n}\n\n// F1: Safe Markdown renderer using marked.js + DOMPurify\nfunction safeMarkdown(text) {\n    if (!text) return '';\n    try {\n        if (typeof marked !== 'undefined' && typeof DOMPurify !== 'undefined') {\n            // Pre-process fenced code blocks to preserve onclick handlers through DOMPurify\n            const codeBlocks = [];\n            const textWithPlaceholders = text.replace(/```(\\w*)\\n([\\s\\S]*?)```/g, function(_, lang, code) {\n                const idx = codeBlocks.length;\n                codeBlocks.push(renderCodeBlock(lang || '', code.trimEnd()));\n                return 'CODEBLOCK_PLACEHOLDER_' + idx + '_END';\n            });\n            const html = marked.parse(textWithPlaceholders, { breaks: true, gfm: true });\n            let sanitized = DOMPurify.sanitize(html, {\n                ALLOWED_TAGS: ['p','strong','em','b','i','u','s','code','pre','ul','ol','li',\n                               'h1','h2','h3','h4','blockquote','a','br','hr','table','thead',\n                               'tbody','tr','th','td','span'],\n                ALLOWED_ATTR: ['href','title','class'],\n            });\n            // Restore code blocks (renderCodeBlock output is already escaped/safe)\n            codeBlocks.forEach(function(block, idx) {\n                sanitized = sanitized.replace('CODEBLOCK_PLACEHOLDER_' + idx + '_END', block);\n            });\n            return sanitized;\n        }\n    } catch (e) { /* fallback to escaped text */ }\n    return esc(text).replace(/\\n/g, '<br>');\n}\n\n// F2: Restore chat history from server on page load / persona switch\nasync function restoreChatHistory() {\n    if (!S.persona) return;\n    const sid = getChatSessionId();\n    const container = document.getElementById('chat-messages');\n    // Always reset DOM first to prevent previous persona's messages from lingering\n    CHAT.messages = [];\n    container.innerHTML = `\n        <div class=\"chat-welcome\" id=\"chat-welcome\">\n            <div class=\"chat-welcome-icon\">町</div>\n            <p>繝√Ε繝・ヨ繧帝幕蟋九☆繧九↓縺ｯ荳九・繝・く繧ｹ繝医・繝・け繧ｹ縺ｫ繝｡繝・そ繝ｼ繧ｸ繧貞・蜉帙＠縺ｦ縺上□縺輔＞縲・/p>\n        </div>`;\n    try {\n        const data = await api('/api/chat/' + encodeURIComponent(S.persona) + '/sessions/' + encodeURIComponent(sid));\n        if (!data || !data.messages || data.messages.length === 0) return;\n        // display_history_turns 莉ｶ謨ｰ蛻・ｼ域怙譁ｰN turns = N*2 messages・峨↓蛻ｶ髯申n        const displayTurns = parseInt(document.getElementById('chat-display-history-turns')?.value || '20');\n        const maxMsgs = displayTurns * 2;\n        const msgs = data.messages.slice(-maxMsgs);\n        container.innerHTML = '';\n        for (const msg of msgs) {\n            appendChatMessage(msg.role, msg.content, msg.time, msg.role === 'assistant');\n        }\n    } catch (_e) {\n        // Session not found or API unavailable 窶・start fresh\n    }\n}\n\n// Housekeeping: manual trigger\nasync function runHousekeeping() {\n    if (!S.persona) { toast('繝壹Ν繧ｽ繝翫ｒ驕ｸ謚槭＠縺ｦ縺上□縺輔＞', 'error'); return; }\n    const statusEl = document.getElementById('chat-housekeeping-status');\n    if (statusEl) statusEl.innerHTML = '<span style=\"color:var(--text-muted)\">謨ｴ逅・ｸｭ...</span>';\n    try {\n        const result = await api('/api/chat/' + encodeURIComponent(S.persona) + '/housekeeping', {\n            method: 'POST',\n        });\n        const g = (result.cancelled_goals || []).length;\n        const p = (result.cancelled_promises || []).length;\n        const i = (result.removed_items || []).length;\n        const msg = `螳御ｺ・ goals ${g}莉ｶ / promises ${p}莉ｶ / items ${i}莉ｶ 繧呈紛逅・;\n        if (statusEl) statusEl.innerHTML = `<span style=\"color:var(--accent-green)\">${msg}</span>`;\n        toast(msg, 'success');\n    } catch (e) {\n        if (statusEl) statusEl.innerHTML = `<span style=\"color:var(--accent-red)\">螟ｱ謨・ ${e.message}</span>`;\n        toast('謨ｴ逅・､ｱ謨・ ' + e.message, 'error');\n    }\n}\n\n// F4: Cancel streaming\nfunction chatCancel() {\n    CHAT.streaming = false;\n    if (CHAT.abortController) {\n        CHAT.abortController.abort();\n        CHAT.abortController = null;\n    }\n    const cancelBtn = document.getElementById('chat-cancel-btn');\n    const sendBtn = document.getElementById('chat-send-btn');\n    const statusEl = document.getElementById('chat-status');\n    if (cancelBtn) cancelBtn.style.display = 'none';\n    if (sendBtn) sendBtn.style.display = '';\n    if (statusEl) statusEl.textContent = '荳ｭ譁ｭ縺励∪縺励◆';\n    removeTypingIndicator();\n}\n\n/* 笏笏 Export chat history 笏笏 */\nfunction exportChatHistory() {\n    const container = document.getElementById('chat-messages');\n    if (!container) return;\n    const bubbles = container.querySelectorAll('.chat-msg');\n    if (bubbles.length === 0) { toast('繧ｨ繧ｯ繧ｹ繝昴・繝医☆繧倶ｼ夊ｩｱ縺後≠繧翫∪縺帙ｓ', 'error'); return; }\n    const lines = [];\n    const persona = S.persona || 'default';\n    lines.push('# 莨夊ｩｱ繝ｭ繧ｰ - ' + persona);\n    lines.push('> 繧ｨ繧ｯ繧ｹ繝昴・繝域律譎・ ' + new Date().toISOString());\n    lines.push('');\n    bubbles.forEach(msg => {\n        const role = msg.classList.contains('user') ? '**側 繝ｦ繝ｼ繧ｶ繝ｼ**' : '**､・繧｢繧ｷ繧ｹ繧ｿ繝ｳ繝・*';\n        const bubble = msg.querySelector('.chat-bubble');\n        const time = msg.querySelector('.chat-time')?.textContent || '';\n        const content = bubble ? bubble.textContent : '';\n        lines.push('### ' + role + ' _' + time + '_');\n        lines.push('');\n        lines.push(content);\n        lines.push('');\n    });\n    const blob = new Blob([lines.join('\\n')], { type: 'text/markdown;charset=utf-8' });\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement('a');\n    a.href = url;\n    a.download = 'chat-' + persona + '-' + new Date().toISOString().slice(0, 10) + '.md';\n    document.body.appendChild(a);\n    a.click();\n    document.body.removeChild(a);\n    URL.revokeObjectURL(url);\n    toast('莨夊ｩｱ繧偵お繧ｯ繧ｹ繝昴・繝医＠縺ｾ縺励◆', 'success');\n}\n\n/* 笏笏 Voice input (Web Speech API) 笏笏 */\nlet _voiceRecognition = null;\nfunction toggleVoiceInput() {\n    const btn = document.getElementById('chat-voice-btn');\n    if (!('webkitSpeechRecognition' in window || 'SpeechRecognition' in window)) {\n        toast('縺贋ｽｿ縺・・繝悶Λ繧ｦ繧ｶ縺ｯ髻ｳ螢ｰ蜈･蜉帙↓蟇ｾ蠢懊＠縺ｦ縺・∪縺帙ｓ', 'error');\n        return;\n    }\n    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;\n    if (_voiceRecognition) {\n        _voiceRecognition.stop();\n        _voiceRecognition = null;\n        if (btn) { btn.textContent = '痔'; btn.style.color = ''; }\n        return;\n    }\n    _voiceRecognition = new SpeechRecognition();\n    _voiceRecognition.lang = 'ja-JP';\n    _voiceRecognition.interimResults = false;\n    _voiceRecognition.continuous = false;\n    if (btn) { btn.textContent = '閥'; btn.style.color = 'var(--accent-red)'; }\n    _voiceRecognition.onresult = (event) => {\n        const transcript = event.results[0][0].transcript;\n        const inputEl = document.getElementById('chat-input');\n        if (inputEl) {\n            inputEl.value = (inputEl.value ? inputEl.value + ' ' : '') + transcript;\n            inputEl.dispatchEvent(new Event('input'));\n        }\n        _voiceRecognition = null;\n        if (btn) { btn.textContent = '痔'; btn.style.color = ''; }\n    };\n    _voiceRecognition.onerror = () => {\n        toast('髻ｳ螢ｰ隱崎ｭ倥お繝ｩ繝ｼ', 'error');\n        _voiceRecognition = null;\n        if (btn) { btn.textContent = '痔'; btn.style.color = ''; }\n    };\n    _voiceRecognition.onend = () => {\n        if (btn) { btn.textContent = '痔'; btn.style.color = ''; }\n    };\n    _voiceRecognition.start();\n}\n}\n\nfunction appendToolEvent(eventType, data) {\n    const container = document.getElementById('chat-messages');\n\n    if (eventType === 'tool_call') {\n        const div = document.createElement('div');\n        div.className = 'chat-tool-call';\n        div.dataset.toolId = data.id || '';\n        let inputStr;\n        try { inputStr = JSON.stringify(data.input, null, 2); } catch (e) { inputStr = String(data.input); }\n        div.innerHTML =\n            '<details><summary>肌 <strong>' + esc(data.name) + '</strong>' +\n            '<span class=\"chat-tool-status\">螳溯｡御ｸｭ...</span></summary>' +\n            '<pre class=\"chat-tool-detail\">' + esc(inputStr) + '</pre></details>';\n        container.appendChild(div);\n        container.scrollTop = container.scrollHeight;\n        return div;\n\n    } else if (eventType === 'tool_result') {\n        let resultStr;\n        try {\n            resultStr = typeof data.result === 'object' ? JSON.stringify(data.result, null, 2) : String(data.result);\n        } catch (e) { resultStr = String(data.result); }\n\n        // Find matching tool_call div by id and update it\n        const callDiv = data.id ? container.querySelector('[data-tool-id=\"' + CSS.escape(data.id) + '\"]') : null;\n        if (callDiv) {\n            const statusEl = callDiv.querySelector('.chat-tool-status');\n            if (statusEl) statusEl.textContent = ' 笨・螳御ｺ・;\n            const details = callDiv.querySelector('details');\n            if (details) {\n                const resultPre = document.createElement('pre');\n                resultPre.className = 'chat-tool-detail chat-tool-result-content';\n                resultPre.textContent = resultStr;\n                details.appendChild(resultPre);\n            }\n            callDiv.classList.add('done');\n        } else {\n            const div = document.createElement('div');\n            div.className = 'chat-tool-result';\n            div.innerHTML =\n                '<details><summary>笨・<strong>' + esc(data.name) + '</strong></summary>' +\n                '<pre class=\"chat-tool-detail chat-tool-result-content\">' + esc(resultStr) + '</pre></details>';\n            container.appendChild(div);\n            container.scrollTop = container.scrollHeight;\n            return div;\n        }\n    }\n}\n\nfunction showTypingIndicator() {\n    const container = document.getElementById('chat-messages');\n    const typing = document.createElement('div');\n    typing.id = 'chat-typing';\n    typing.className = 'chat-msg assistant';\n    typing.innerHTML = '<div class=\"chat-bubble chat-typing\"><span></span><span></span><span></span></div>';\n    container.appendChild(typing);\n    container.scrollTop = container.scrollHeight;\n}\n\nfunction removeTypingIndicator() {\n    const el = document.getElementById('chat-typing');\n    if (el) el.remove();\n}\n\nasync function uploadAttachment(file) {\n    if (!S.persona) { toast('繝壹Ν繧ｽ繝翫ｒ驕ｸ謚槭＠縺ｦ縺上□縺輔＞', 'error'); return; }\n    const formData = new FormData();\n    formData.append('file', file);\n    try {\n        const res = await fetch('/api/chat/' + encodeURIComponent(S.persona) + '/attachment/upload', {\n            method: 'POST',\n            body: formData,\n        });\n        if (!res.ok) throw new Error('HTTP ' + res.status);\n        const data = await res.json();\n        CHAT.attachments.push(data);\n        renderAttachmentBadge(data);\n    } catch (e) {\n        toast('繝輔ぃ繧､繝ｫ縺ｮ繧｢繝・・繝ｭ繝ｼ繝峨↓螟ｱ謨励＠縺ｾ縺励◆: ' + e.message, 'error');\n    }\n}\n\nfunction renderAttachmentBadge(att) {\n    const area = document.getElementById('chat-attachments');\n    if (!area) return;\n    const badge = document.createElement('div');\n    badge.className = 'chat-attachment-badge';\n    badge.dataset.filename = att.filename;\n\n    const isImage = att.mime_type && att.mime_type.startsWith('image/');\n    const isVideo = att.mime_type && att.mime_type.startsWith('video/');\n\n    if (isImage) {\n        const img = document.createElement('img');\n        img.className = 'thumb';\n        img.src = att.url;\n        img.alt = att.filename;\n        img.onclick = () => openMediaViewer(att.url, 'image');\n        badge.appendChild(img);\n    } else if (isVideo) {\n        const vid = document.createElement('video');\n        vid.className = 'thumb';\n        vid.src = att.url;\n        vid.muted = true;\n        vid.onclick = () => openMediaViewer(att.url, 'video');\n        badge.appendChild(vid);\n    } else {\n        const icon = document.createElement('span');\n        const ext = att.filename.split('.').pop().toLowerCase();\n        icon.textContent = ext === 'pdf' ? '燈' : (ext === 'zip' || ext === 'tar' || ext === 'gz' ? '逃' : '塘');\n        badge.appendChild(icon);\n    }\n\n    const nameSpan = document.createElement('span');\n    nameSpan.className = 'attach-name';\n    nameSpan.textContent = att.filename;\n    badge.appendChild(nameSpan);\n\n    const removeBtn = document.createElement('button');\n    removeBtn.className = 'attach-remove';\n    removeBtn.textContent = '笨・;\n    removeBtn.onclick = () => {\n        CHAT.attachments = CHAT.attachments.filter(a => a.filename !== att.filename);\n        badge.remove();\n    };\n    badge.appendChild(removeBtn);\n    area.appendChild(badge);\n}\n\nfunction openMediaViewer(url, type) {\n    const overlay = document.getElementById('media-viewer-overlay');\n    const inner = document.getElementById('media-viewer-inner');\n    if (!overlay || !inner) return;\n    inner.innerHTML = '';\n    if (type === 'image') {\n        const img = document.createElement('img');\n        img.src = url;\n        inner.appendChild(img);\n    } else {\n        const vid = document.createElement('video');\n        vid.src = url;\n        vid.controls = true;\n        vid.autoplay = true;\n        inner.appendChild(vid);\n    }\n    overlay.classList.add('visible');\n    // ESC to close\n    const escHandler = (e) => {\n        if (e.key === 'Escape') { closeMediaViewer(); document.removeEventListener('keydown', escHandler); }\n    };\n    document.addEventListener('keydown', escHandler);\n}\n\nfunction closeMediaViewer() {\n    const overlay = document.getElementById('media-viewer-overlay');\n    const inner = document.getElementById('media-viewer-inner');\n    if (overlay) overlay.classList.remove('visible');\n    if (inner) {\n        const vid = inner.querySelector('video');\n        if (vid) vid.pause();\n        inner.innerHTML = '';\n    }\n}\n\n/* 笏笏 Memory CRUD operations 笏笏 */\nlet _memEditKey = null;\n\nfunction openMemEdit(card) {\n    _memEditKey = card.dataset.key;\n    document.getElementById('mem-edit-content').value = card.dataset.content || '';\n    document.getElementById('mem-edit-importance').value = card.dataset.importance || '0.5';\n    document.getElementById('mem-edit-tags').value = card.dataset.tags || '';\n    document.getElementById('mem-edit-overlay').classList.add('show');\n}\n\nfunction closeMemEdit() {\n    document.getElementById('mem-edit-overlay').classList.remove('show');\n    _memEditKey = null;\n}\n\nasync function saveMemEdit() {\n    if (!_memEditKey || !S.persona) return;\n    const content = document.getElementById('mem-edit-content').value.trim();\n    const importance = parseFloat(document.getElementById('mem-edit-importance').value) || 0.5;\n    const tagsStr = document.getElementById('mem-edit-tags').value.trim();\n    const tags = tagsStr ? tagsStr.split(',').map(t => t.trim()).filter(Boolean) : [];\n    if (!content) { toast('蜀・ｮｹ繧貞・蜉帙＠縺ｦ縺上□縺輔＞', 'error'); return; }\n    try {\n        await api('/api/memories/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(_memEditKey), {\n            method: 'PUT',\n            body: JSON.stringify({ content, importance, tags }),\n        });\n        closeMemEdit();\n        toast('繝｡繝｢繝ｪ繧呈峩譁ｰ縺励∪縺励◆', 'success');\n        loadChatCommitments(); // refresh panels\n    } catch (e) {\n        toast('譖ｴ譁ｰ螟ｱ謨・ ' + e.message, 'error');\n    }\n}\n\nasync function deleteMemCard(key) {\n    const k = key || _memEditKey;\n    if (!k || !S.persona) return;\n    if (!confirm('縺薙・繝｡繝｢繝ｪ繧貞炎髯､縺励∪縺吶°・・)) return;\n    try {\n        await api('/api/memories/' + encodeURIComponent(S.persona) + '/' + encodeURIComponent(k), {\n            method: 'DELETE',\n        });\n        closeMemEdit();\n        toast('繝｡繝｢繝ｪ繧貞炎髯､縺励∪縺励◆', 'success');\n        loadChatCommitments(); // refresh panels\n    } catch (e) {\n        toast('蜑企勁螟ｱ謨・ ' + e.message, 'error');\n    }\n}\n\nasync function completeGoal(key, content) {\n    if (!S.persona) return;\n    try {\n        const resp = await api('/api/chat/' + encodeURIComponent(S.persona) + '/tool', {\n            method: 'POST',\n            body: JSON.stringify({ tool: 'goal_achieve', input: { content } }),\n        });\n        if (resp.status === 'ok') {\n            toast('逶ｮ讓吶ｒ驕疲・縺励∪縺励◆: ' + (resp.updated || content), 'success');\n            loadChatCommitments();\n        } else {\n            toast('螳御ｺ・､ｱ謨・ ' + (resp.message || ''), 'error');\n        }\n    } catch (e) {\n        toast('繧ｨ繝ｩ繝ｼ: ' + e.message, 'error');\n    }\n}\n\nasync function fulfillPromise(key, content) {\n    if (!S.persona) return;\n    try {\n        const resp = await api('/api/chat/' + encodeURIComponent(S.persona) + '/tool', {\n            method: 'POST',\n            body: JSON.stringify({ tool: 'promise_fulfill', input: { content } }),\n        });\n        if (resp.status === 'ok') {\n            toast('邏・據繧帝≠陦後＠縺ｾ縺励◆: ' + (resp.updated || content), 'success');\n            loadChatCommitments();\n        } else {\n            toast('驕り｡悟､ｱ謨・ ' + (resp.message || ''), 'error');\n        }\n    } catch (e) {\n        toast('繧ｨ繝ｩ繝ｼ: ' + e.message, 'error');\n    }\n}\n\n/* 笏笏 Slash command handler 笏笏 */\nasync function handleSlashCommand(toolName, toolInput) {\n    const inputEl = document.getElementById('chat-input');\n    const rawInput = inputEl.value.trim();\n    inputEl.value = '';\n    inputEl.style.height = 'auto';\n    const timeStr = new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit' });\n    appendChatMessage('user', rawInput, timeStr);\n    showTypingIndicator();\n    try {\n        const resp = await api('/api/chat/' + encodeURIComponent(S.persona) + '/tool', {\n            method: 'POST',\n            body: JSON.stringify({ tool: toolName, input: toolInput }),\n        });\n        removeTypingIndicator();\n        const resultMsg = resp.status === 'ok'\n            ? '笨・' + (resp.key ? '菴懈・: ' + resp.key : resp.updated ? '譖ｴ譁ｰ: ' + resp.updated : '螳溯｡悟ｮ御ｺ・)\n            : '笨・' + (resp.message || resp.error || '繧ｨ繝ｩ繝ｼ');\n        appendChatMessage('assistant', resultMsg, new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit' }));\n        if (resp.status === 'ok') toast(resultMsg, 'success');\n    } catch (ex) {\n        removeTypingIndicator();\n        appendChatMessage('assistant', '笨・繧ｳ繝槭Φ繝牙ｮ溯｡悟､ｱ謨・ ' + ex.message,\n            new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit' }));\n        toast('繧ｳ繝槭Φ繝牙､ｱ謨・ ' + ex.message, 'error');\n    }\n}\n\nasync function chatSend(retry) {\n    if (!S.persona) { toast('繝壹Ν繧ｽ繝翫ｒ驕ｸ謚槭＠縺ｦ縺上□縺輔＞', 'error'); return; }\n    if (CHAT.streaming) return;\n\n    const inputEl = document.getElementById('chat-input');\n    let rawInput;\n    if (retry) {\n        // Find last user message\n        const msgs = document.querySelectorAll('.chat-msg.user .chat-bubble');\n        rawInput = msgs.length > 0 ? msgs[msgs.length - 1].textContent : '';\n        if (!rawInput) { toast('蜀埼√☆繧九Γ繝・そ繝ｼ繧ｸ縺後≠繧翫∪縺帙ｓ', 'error'); return; }\n    } else {\n        rawInput = inputEl.value.trim();\n    }\n    let message = rawInput;\n    if (!message && CHAT.attachments.length === 0) return;\n    if (!message) message = '';\n\n    // Web search toggle\n    const webSearchEl = document.getElementById('chat-web-search');\n    if (webSearchEl && webSearchEl.checked && message) {\n        message = '[Web讀懃ｴ｢繝｢繝ｼ繝云\\n莉･荳九・雉ｪ蝠上↓縺､縺・※縲√∪縺啗eb讀懃ｴ｢繧定｡後＞譛譁ｰ縺ｮ諠・ｱ繧貞叙蠕励＠縺ｦ縺九ｉ蝗樒ｭ斐＠縺ｦ縺上□縺輔＞縲・\n\\n' + message;\n        webSearchEl.checked = false; // one-shot\n    }\n\n    const sendBtn = document.getElementById('chat-send-btn');\n    const cancelBtn = document.getElementById('chat-cancel-btn');\n    const statusEl = document.getElementById('chat-status');\n\n    // Append attachment references to message\n    if (CHAT.attachments.length > 0) {\n        const TEXT_EXTS = new Set(['txt','csv','json','py','js','ts','md','yaml','yml','toml','ini','cfg','sh','bash','html','css','xml','log','sql','rs','go','java','cpp','c','h']);\n        const attachParts = [];\n        for (const att of CHAT.attachments) {\n            const ext = att.filename.split('.').pop().toLowerCase();\n            const isText = TEXT_EXTS.has(ext);\n            if (isText) {\n                try {\n                    const res = await fetch(att.url);\n                    const content = await res.text();\n                    attachParts.push('\\n\\n--- 豺ｻ莉・ ' + att.filename + ' ---\\n' + content + '\\n---');\n                } catch (_e) {\n                    attachParts.push('\\n[豺ｻ莉倥ヵ繧｡繧､繝ｫ: ' + att.workspace_path + ']');\n                }\n            } else if (att.mime_type && att.mime_type.startsWith('image/')) {\n                attachParts.push('\\n[豺ｻ莉倡判蜒・ ' + att.workspace_path + ']');\n            } else {\n                attachParts.push('\\n[豺ｻ莉倥ヵ繧｡繧､繝ｫ: ' + att.workspace_path + ']');\n            }\n        }\n        if (attachParts.length > 0) {\n            message = message + attachParts.join('');\n        }\n    }\n\n    inputEl.value = '';\n    inputEl.style.height = 'auto';\n    // Save attachment info before clearing\n    const attNames = CHAT.attachments.map(a => a.filename);\n    CHAT.attachments = [];\n    const attArea = document.getElementById('chat-attachments');\n    if (attArea) attArea.innerHTML = '';\n\n    // Show user message with filename display\n    const displayMsg = rawInput || (attNames.length > 0 ? '梼 ' + attNames.join(', ') : '');\n    const timeStr = new Date().toLocaleTimeString('ja-JP', {hour:'2-digit',minute:'2-digit'});\n    appendChatMessage('user', displayMsg, timeStr);\n    showTypingIndicator();\n\n    CHAT.streaming = true;\n    CHAT.abortController = new AbortController();\n    sendBtn.style.display = 'none';\n    if (cancelBtn) cancelBtn.style.display = '';\n    statusEl.textContent = '蠢懃ｭ比ｸｭ...';\n\n    const sessionId = getChatSessionId();\n    let assistantText = '';\n    let assistantBubble = null;\n    let assistantDiv = null;\n\n    try {\n        const response = await fetch('/api/chat/' + encodeURIComponent(S.persona), {\n            method: 'POST',\n            headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ message, session_id: sessionId, debug: false }),\n            signal: CHAT.abortController.signal,\n        });\n\n        if (!response.ok) {\n            throw new Error('HTTP ' + response.status);\n        }\n\n        const reader = response.body.getReader();\n        const decoder = new TextDecoder();\n        let buffer = '';\n        let streamDone = false;\n\n        removeTypingIndicator();\n\n        while (true) {\n            const { value, done } = await reader.read();\n            if (done) break;\n            buffer += decoder.decode(value, { stream: true });\n\n            const lines = buffer.split('\\n');\n            buffer = lines.pop();  // keep incomplete line\n\n            for (const line of lines) {\n                if (!line.startsWith('data: ')) continue;\n                let evt;\n                try { evt = JSON.parse(line.slice(6)); } catch { continue; }\n\n                if (evt.type === 'text_delta') {\n                    if (!assistantDiv) {\n                        const container = document.getElementById('chat-messages');\n                        assistantDiv = document.createElement('div');\n                        assistantDiv.className = 'chat-msg assistant';\n                        assistantBubble = document.createElement('div');\n                        assistantBubble.className = 'chat-bubble';\n                        const timeDiv = document.createElement('div');\n                        timeDiv.className = 'chat-time';\n                        timeDiv.textContent = new Date().toLocaleTimeString('ja-JP', {hour:'2-digit',minute:'2-digit'});\n                        assistantDiv.appendChild(assistantBubble);\n                        assistantDiv.appendChild(timeDiv);\n                        container.appendChild(assistantDiv);\n                    }\n                    assistantText += evt.content;\n                    // F1: stream as plain text for performance; render markdown on done\n                    assistantBubble.textContent = assistantText;\n                    document.getElementById('chat-messages').scrollTop = document.getElementById('chat-messages').scrollHeight;\n\n                } else if (evt.type === 'tool_call') {\n                    if (MEMORY_TOOL_NAMES.has(evt.name)) {\n                        handleMemoryToolCall(evt);\n                    } else {\n                        const sbEnabled = document.getElementById('chat-sandbox-enabled')?.checked;\n                        if (FILE_OP_TOOLS.has(evt.name) && sbEnabled) {\n                            handleFileToolCall(evt);\n                        } else {\n                            appendToolEvent('tool_call', evt);\n                        }\n                    }\n                    statusEl.textContent = '肌 ' + evt.name + ' 繧貞ｮ溯｡御ｸｭ...';\n                    sandboxHandleToolEvent(evt);\n\n                } else if (evt.type === 'tool_result') {\n                    if (MEMORY_TOOL_NAMES.has(evt.name)) {\n                        handleMemoryToolResult(evt);\n                    } else {\n                        const sbEnabled = document.getElementById('chat-sandbox-enabled')?.checked;\n                        if (!FILE_OP_TOOLS.has(evt.name) || !sbEnabled) {\n                            appendToolEvent('tool_result', evt);\n                        }\n                    }\n                    statusEl.textContent = '蠢懃ｭ比ｸｭ...';\n                    sandboxHandleToolEvent(evt);\n\n                } else if (evt.type === 'memory_activity') {\n                    updateMemoryPanel(evt.retrieved, evt.saved, undefined, undefined);\n                    setTimeout(() => loadChatCommitments(), 300);\n\n                } else if (evt.type === 'reflection_start') {\n                    showReflectionStart();\n\n                } else if (evt.type === 'reflection_done') {\n                    updateReflectionPanel(evt.insights);\n\n                } else if (evt.type === 'session_summarized') {\n                    showSessionSummarized(evt.summary);\n\n                } else if (evt.type === 'error') {\n                    removeTypingIndicator();\n                    toast('繧ｨ繝ｩ繝ｼ: ' + evt.message, 'error');\n                    statusEl.textContent = '';\n                    streamDone = true;\n                    break;\n\n                } else if (evt.type === 'debug_info') {\n                    console.debug('[debug_info received]', Object.keys(evt));\n                    renderDebugPanel(assistantDiv, evt);\n\n                } else if (evt.type === 'done') {\n                    // F1: final Markdown render\n                    if (assistantBubble && assistantText) {\n                        assistantBubble.innerHTML = safeMarkdown(assistantText);\n                    }\n                    statusEl.textContent = '';\n                }\n            }\n            if (streamDone) break;\n        }\n\n    } catch (e) {\n        removeTypingIndicator();\n        if (e.name !== 'AbortError') {\n            toast('騾∽ｿ｡螟ｱ謨・ ' + e.message, 'error');\n        }\n        statusEl.textContent = '';\n    } finally {\n        CHAT.streaming = false;\n        CHAT.abortController = null;\n        sendBtn.style.display = '';\n        if (cancelBtn) cancelBtn.style.display = 'none';\n        inputEl.focus();\n        // Fallback: render markdown if stream ended without 'done' event\n        if (assistantBubble && assistantText && assistantBubble.textContent === assistantText) {\n            assistantBubble.innerHTML = safeMarkdown(assistantText);\n        }\n    }\n}\n\n// Chat input auto-resize and keyboard handler\ndocument.addEventListener('DOMContentLoaded', () => {\n    const input = document.getElementById('chat-input');\n    if (!input) return;\n    input.addEventListener('keydown', (e) => {\n        if (e.key === 'Enter' && !e.shiftKey) {\n            e.preventDefault();\n            const val = input.value.trim();\n            // Slash commands\n            if (val.startsWith('/memory ')) {\n                handleSlashCommand('memory_create', { content: val.slice(8).trim(), importance: 0.7, tags: [] });\n            } else if (val.startsWith('/goal ')) {\n                handleSlashCommand('goal_create', { content: val.slice(6).trim(), importance: 0.8 });\n            } else if (val.startsWith('/promise ')) {\n                handleSlashCommand('promise_create', { content: val.slice(9).trim(), importance: 0.8 });\n            } else if (val.startsWith('/code ') && S.persona) {\n                handleSlashCommand('execute_code', { code: val.slice(6).trim(), language: 'python' });\n            } else {\n                chatSend();\n            }\n        }\n    });\n    input.addEventListener('input', () => {\n        input.style.height = 'auto';\n        input.style.height = Math.min(input.scrollHeight, 160) + 'px';\n    });\n    // File drag-and-drop on chat input\n    input.addEventListener('dragover', (e) => {\n        e.preventDefault();\n        input.classList.add('dragover');\n    });\n    input.addEventListener('dragleave', () => {\n        input.classList.remove('dragover');\n    });\n    input.addEventListener('drop', async (e) => {\n        e.preventDefault();\n        input.classList.remove('dragover');\n        const files = Array.from(e.dataTransfer.files);\n        for (const file of files) {\n            await uploadAttachment(file);\n        }\n    });\n});\n\n// Reload chat config when persona changes\nwindow.__chatPersonaWatcher = setInterval(() => {\n    const sel = document.getElementById('persona-select');\n    if (!sel) return;\n    if (!sel._chatBound) {\n        sel._chatBound = true;\n        sel.addEventListener('change', () => {\n            // DOM reset + history restore is handled by base.py's loadTab() 竊・loadChat() 竊・restoreChatHistory()\n            // Do NOT call clearChatHistory() here 窶・it would destroy the session ID and break history\n            if (S.tab === 'chat') {\n                loadChatConfig();\n                loadChatCommitments();\n            }\n        });\n        clearInterval(window.__chatPersonaWatcher);\n    }\n}, 500);\n\n/* 笏笏 Memory tool filtering 笏笏 */\nconst MEMORY_TOOL_NAMES = new Set([\n    // MCP tools\n    'memory', 'search_memory', 'update_context', 'item', 'get_context',\n    // Builtin tools\n    'memory_create', 'memory_search', 'memory_update',\n    'context_update', 'context_recall',\n    'goal_create', 'goal_achieve', 'goal_cancel',\n    'promise_create', 'promise_fulfill', 'promise_cancel',\n    'invoke_skill',\n]);\nconst FILE_OP_TOOLS = new Set(['edit', 'create', 'view', 'bash', 'powershell', 'str_replace_editor',\n    'write_file', 'read_file', 'delete_file', 'list_files', 'glob', 'grep']);\n\n// Track in-flight memory ops for result pairing\nconst _memOps = {};\n\nfunction handleMemoryToolCall(evt) {\n    const el = document.getElementById('memory-tool-ops-list');\n    if (!el) return;\n    const empty = el.querySelector('.memory-empty');\n    if (empty) empty.remove();\n    const op = evt.input?.operation || '';\n    const icons = { memory:'沈', search_memory:'剥', update_context:'売', item:'賜', get_context:'投' };\n    const icon = icons[evt.name] || '肌';\n    const label = evt.name + (op ? '.' + op : '');\n    const id = 'mop-' + (evt.id || (evt.name + Date.now()));\n    const card = document.createElement('div');\n    card.className = 'memory-item-card';\n    card.id = id;\n    card.innerHTML = '<div class=\"mem-score\">' + esc(icon + ' ' + label) + '</div>' +\n        '<span style=\"opacity:0.5;font-size:0.7rem\">螳溯｡御ｸｭ...</span>';\n    el.prepend(card);\n    const cards = el.querySelectorAll('.memory-item-card');\n    if (cards.length > 8) cards[cards.length - 1].remove();\n    _memOps[evt.id || label] = id;\n}\n\nfunction handleMemoryToolResult(evt) {\n    const key = evt.id || (evt.name + (evt.input?.operation || ''));\n    const cardId = _memOps[key];\n    if (cardId) {\n        const card = document.getElementById(cardId);\n        if (card) {\n            const span = card.querySelector('span');\n            if (span) span.remove();\n            const resultStr = typeof evt.result === 'string' ? evt.result : JSON.stringify(evt.result);\n            const detail = document.createElement('div');\n            detail.style.cssText = 'font-size:0.7rem;opacity:0.75;margin-top:2px;';\n            detail.textContent = resultStr.substring(0, 100) + (resultStr.length > 100 ? '...' : '');\n            card.appendChild(detail);\n        }\n        delete _memOps[key];\n    }\n}\n\nfunction handleFileToolCall(evt) {\n    const icons = { edit:'笨擾ｸ・, create:'統', view:'早・・, bash:'笞呻ｸ・, powershell:'笞呻ｸ・,\n        str_replace_editor:'笨擾ｸ・, delete_file:'卵・・, list_files:'唐',\n        write_file:'統', read_file:'早・・, glob:'剥', grep:'剥' };\n    const icon = icons[evt.name] || '肌';\n    const detail = evt.input?.path || evt.input?.file_path || evt.input?.command ||\n        evt.input?.pattern || evt.input?.glob || '';\n    sandboxLog(icon + ' ' + evt.name + (detail ? ': ' + String(detail).substring(0, 60) : ''), 'system');\n}\n\nfunction sandboxLog(text, type = '') {\n    if (typeof isCodingAgentOpen === 'function' && isCodingAgentOpen() &&\n        typeof caAppendOutput === 'function') {\n        caAppendOutput(text + '\\n', type === 'stderr' ? 'stderr' : 'stdout');\n    }\n}\n\nfunction onSandboxEnabledChange() {\n    const enabled = document.getElementById('chat-sandbox-enabled')?.checked;\n    if (!enabled && typeof isCodingAgentOpen === 'function' && isCodingAgentOpen()) {\n        closeCodingAgent();\n    }\n}\n\n/* 笏笏 Sandbox: Add artifact to tab 笏笏 */\nfunction sandboxAddArtifact(base64png, label) {\n    const list = document.getElementById('sandbox-artifacts-list');\n    if (!list) return;\n    // Clear placeholder\n    const placeholder = list.querySelector('div[style*=\"text-muted\"]');\n    if (placeholder) placeholder.remove();\n\n    const thumb = document.createElement('div');\n    thumb.className = 'artifact-thumb';\n    const img = document.createElement('img');\n    img.src = 'data:image/png;base64,' + base64png;\n    img.alt = label || 'artifact';\n    img.onclick = () => window.open(img.src, '_blank');\n    const lbl = document.createElement('div');\n    lbl.className = 'artifact-thumb-label';\n    lbl.textContent = label || new Date().toLocaleTimeString();\n    thumb.appendChild(img);\n    thumb.appendChild(lbl);\n    list.appendChild(thumb);\n}\n\n/* 笏笏 Code block Run button 笏笏 */\nasync function sandboxRunBlock(code, language, resultEl, runBtn) {\n    if (!S.persona) return;\n    if (typeof openCodingAgent === 'function') {\n        openCodingAgent({ code, language });\n        if (resultEl) {\n            resultEl.className = 'hljs-run-result stdout';\n            resultEl.textContent = '笆ｶ Coding Agent 縺ｧ髢九″縺ｾ縺励◆';\n            resultEl.style.display = 'block';\n        }\n        if (runBtn) runBtn.textContent = '笆ｶ Run';\n        return;\n    }\n    runBtn.disabled = true;\n    runBtn.textContent = '竢ｳ';\n    resultEl.className = 'hljs-run-result running';\n    resultEl.textContent = '螳溯｡御ｸｭ...';\n    resultEl.style.display = 'block';\n    try {\n        const resp = await api('/api/chat/' + encodeURIComponent(S.persona) + '/sandbox/execute', {\n            method: 'POST',\n            body: JSON.stringify({ code, language }),\n        });\n        const out = (resp.stdout || '').trim();\n        const err = (resp.stderr || '').trim();\n        if (err) {\n            resultEl.className = 'hljs-run-result stderr';\n            resultEl.textContent = err;\n        } else {\n            resultEl.className = 'hljs-run-result stdout';\n            resultEl.textContent = out || '(蜃ｺ蜉帙↑縺・';\n        }\n        if (resp.artifacts && resp.artifacts.length > 0) {\n            resp.artifacts.forEach((a, i) => {\n                const img = document.createElement('img');\n                img.src = 'data:image/png;base64,' + a;\n                img.className = 'hljs-artifact-img';\n                img.title = '繧ｯ繝ｪ繝・け縺ｧ諡｡螟ｧ';\n                img.onclick = () => window.open(img.src, '_blank');\n                resultEl.parentNode.insertBefore(img, resultEl.nextSibling);\n                sandboxAddArtifact(a, 'chart-' + new Date().toLocaleTimeString());\n            });\n        }\n        sandboxLog('笆ｶ [' + language + '] ' + code.split('\\n')[0].substring(0, 60) + (code.includes('\\n') ? '...' : ''), 'system');\n        if (out) out.split('\\n').forEach(l => l && sandboxLog(l, 'success'));\n        if (err) err.split('\\n').forEach(l => l && sandboxLog(l, 'stderr'));\n    } catch (ex) {\n        resultEl.className = 'hljs-run-result stderr';\n        resultEl.textContent = 'Error: ' + ex.message;\n    } finally {\n        runBtn.disabled = false;\n        runBtn.textContent = '笆ｶ Run';\n    }\n}\n\n/* 笏笏 Markdown code block rendering with syntax highlighting 笏笏 */\nfunction renderCodeBlock(lang, code) {\n    const sandboxEnabled = document.getElementById('chat-sandbox-enabled')?.checked;\n    const runnable = sandboxEnabled && lang && lang !== 'text' && lang !== 'output';\n    const escaped = esc(code);\n    // Try highlight.js\n    let highlighted = escaped;\n    try {\n        if (typeof hljs !== 'undefined' && lang && hljs.getLanguage(lang)) {\n            highlighted = hljs.highlight(code, { language: lang }).value;\n        } else if (typeof hljs !== 'undefined') {\n            highlighted = hljs.highlightAuto(code).value;\n        }\n    } catch (_) { /* fallback to plain */ }\n\n    const uid = 'codeblock-' + Math.random().toString(36).slice(2);\n    const runBtnHtml = runnable\n        ? '<button class=\"hljs-run-btn\" id=\"runbtn-' + uid + '\" onclick=\"sandboxRunBlock(' +\n          JSON.stringify(code) + ', ' + JSON.stringify(lang || 'python') + ', document.getElementById(\\'result-' + uid + '\\'), this)\">笆ｶ Run</button>'\n        : '';\n\n    return '<div class=\"hljs-block-wrapper\">' +\n        '<div class=\"hljs-block-header\">' +\n            '<span class=\"hljs-lang-badge\">' + esc(lang || '') + '</span>' +\n            '<div class=\"hljs-block-actions\">' +\n                '<button class=\"hljs-copy-btn\" onclick=\"navigator.clipboard.writeText(' + JSON.stringify(code) + ').then(()=>toast(\\'繧ｳ繝斐・縺励∪縺励◆\\',\\'success\\'))\">搭 Copy</button>' +\n                runBtnHtml +\n            '</div>' +\n        '</div>' +\n        '<pre style=\"margin:0;padding:8px 10px;background:#0d1117;overflow-x:auto;\"><code class=\"hljs language-' + esc(lang || '') + '\">' + highlighted + '</code></pre>' +\n        '<div id=\"result-' + uid + '\" class=\"hljs-run-result\" style=\"display:none;\"></div>' +\n    '</div>';\n}\n\n\nconst DEPENDS_RULES = {\n    'summarization.use_llm': { field: 'summarization.enabled', value: true },\n    'summarization.llm_api_url': { field: 'summarization.use_llm', value: true },\n    'summarization.llm_api_key': { field: 'summarization.use_llm', value: true },\n    'summarization.llm_model': { field: 'summarization.use_llm', value: true },\n    'summarization.llm_max_tokens': { field: 'summarization.use_llm', value: true },\n    'summarization.check_interval_seconds': { field: 'summarization.enabled', value: true },\n    'summarization.min_importance': { field: 'summarization.enabled', value: true }\n};\n\nconst BUILTIN_PROFILES = {\n    'Development': {\n        server: { host: '0.0.0.0', port: 26262 },\n        embedding: { model: 'cl-nagoya/ruri-v3-30m', device: 'cpu', batch_size: 32 },\n        reranker: { model: 'hotchpotch/japanese-reranker-xsmall-v2', enabled: true },\n        general: { log_level: 'DEBUG', contradiction_threshold: 0.85, duplicate_threshold: 0.90 },\n        forgetting: { enabled: true, decay_interval_seconds: 3600, min_strength: 0.01 }\n    },\n    'Production': {\n        embedding: { model: 'cl-nagoya/ruri-v3-30m', device: 'auto', batch_size: 64 },\n        reranker: { model: 'hotchpotch/japanese-reranker-xsmall-v2', enabled: true },\n        general: { log_level: 'WARNING', contradiction_threshold: 0.85, duplicate_threshold: 0.90 },\n        forgetting: { enabled: true, decay_interval_seconds: 1800, min_strength: 0.01 }\n    }\n};\n\nconst CATEGORY_ICONS = {\n    server: '箕・・, embedding: 'ｧ', reranker: '剥', qdrant: '逃',\n    worker: '竢ｰ', general: '笞呻ｸ・, search: '博', persona: '側',\n    summarization: '､・, forgetting: 'ｧｹ'\n};\n\nasync function loadSettings() {\n    const el = document.getElementById('settings-content');\n    try {\n        const [resp, status] = await Promise.all([\n            api('/api/settings'),\n            api('/api/settings/status')\n        ]);\n        const settingsData = resp.settings || resp;\n        S.settingsData = settingsData;\n        S.settingsReloadStatus = status;\n        renderSettings(el, settingsData, status);\n        updateLastTime();\n    } catch (e) {\n        el.innerHTML = errorCard('Failed to load settings: ' + e.message);\n    }\n}\n\nfunction sourceIcon(src) {\n    if (src === 'env') return '<span class=\"setting-source source-env\">倹 env</span>';\n    if (src === 'override') return '<span class=\"setting-source source-override\">統 override</span>';\n    return '<span class=\"setting-source source-default\">搭 default</span>';\n}\n\nfunction renderSettings(el, settings, status) {\n    const reloadStatus = (status && status.reload_status) || {};\n    let html = '';\n\n    /* 笏笏 Profiles section 笏笏 */\n    html += '<div class=\"glass p-4 mb-6\">';\n    html += '<div style=\"display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px\">';\n    html += '<h3 style=\"font-size:1rem;font-weight:600;color:var(--text-primary)\">搭 Settings Profiles</h3>';\n    html += '<button id=\"save-profile-btn\" class=\"glass-btn\" style=\"padding:6px 14px;font-size:0.8rem\">沈 Save Current as Profile</button>';\n    html += '</div>';\n    html += '<div id=\"profiles-list\" style=\"display:flex;flex-wrap:wrap;gap:8px;margin-top:12px\"></div>';\n    html += '</div>';\n\n    /* 笏笏 Search bar 笏笏 */\n    html += '<div class=\"glass p-4 mb-6\" style=\"position:sticky;top:120px;z-index:30\">';\n    html += '<div style=\"position:relative\">';\n    html += '<span style=\"position:absolute;left:14px;top:50%;transform:translateY(-50%);color:var(--text-muted);font-size:0.9rem\">剥</span>';\n    html += '<input id=\"settings-search\" type=\"text\" class=\"glass-input\" placeholder=\"Search settings...\" style=\"width:100%;padding-left:38px;padding-right:36px;font-size:0.9rem\" oninput=\"filterSettings(this.value)\">';\n    html += '<button id=\"settings-search-clear\" style=\"position:absolute;right:10px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--text-muted);cursor:pointer;font-size:0.85rem;display:none\">笨・/button>';\n    html += '</div>';\n    html += '</div>';\n\n    /* 笏笏 Category cards 笏笏 */\n    for (const [cat, fields] of Object.entries(settings)) {\n        if (cat === 'reload_status') continue;\n        if (typeof fields !== 'object' || fields === null) continue;\n        const hasFields = Object.values(fields).some(f => typeof f === 'object' && f !== null);\n        if (!hasFields) continue;\n\n        const icon = CATEGORY_ICONS[cat] || '笞呻ｸ・;\n        const catLabel = cat.charAt(0).toUpperCase() + cat.slice(1);\n\n        /* Diff detection for category */\n        let hasDiffs = false;\n        const catSearchText = cat + ' ' + catLabel;\n        for (const [key, meta] of Object.entries(fields)) {\n            if (typeof meta !== 'object' || meta === null) continue;\n            if (meta.value != null && meta.default_value != null && String(meta.value) !== '***') {\n                if (String(meta.value) !== String(meta.default_value)) { hasDiffs = true; break; }\n            }\n        }\n\n        /* Reload status */\n        const catStatus = reloadStatus[cat];\n        let statusHtml = '';\n        if (catStatus && catStatus.status && catStatus.status !== 'idle') {\n            const st = catStatus.status;\n            if (st === 'loading' || st === 'reloading') {\n                statusHtml = '<div style=\"margin-top:8px\"><div style=\"font-size:0.78rem;color:var(--accent-yellow);margin-bottom:4px\">竢ｳ ' + esc(catStatus.message || 'Loading...') + '</div><div class=\"progress-wrap\"><div class=\"progress-bar progress-indeterminate\"></div></div></div>';\n            } else if (st === 'ready' || st === 'success') {\n                statusHtml = '<div style=\"margin-top:8px;font-size:0.78rem;color:var(--accent-green)\">笨・' + esc(catStatus.message || 'Ready') + '</div>';\n            } else if (st === 'error') {\n                statusHtml = '<div style=\"margin-top:8px;font-size:0.78rem;color:var(--accent-red)\">笶・' + esc(catStatus.message || 'Error') + '</div>';\n            }\n        }\n\n        /* Card wrapper */\n        html += '<div class=\"glass p-6 mb-6 setting-category-card\" data-category=\"' + esc(cat) + '\" data-searchtext=\"' + esc(catSearchText) + '\">';\n        html += '<div style=\"display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;margin-bottom:16px\">';\n        html += '<div style=\"display:flex;align-items:center;gap:10px\">';\n        html += '<button class=\"cat-toggle-btn\" id=\"cat-toggle-' + cat + '\" data-toggle-cat=\"' + cat + '\">笆ｼ</button>';\n        html += '<span class=\"card-title\" style=\"margin:0\">' + icon + ' ' + esc(catLabel) + ' Settings</span>';\n        html += '</div>';\n        if (hasDiffs) {\n            html += '<button class=\"cat-reset-btn\" data-reset-cat=\"' + cat + '\">竊ｩ Reset Category</button>';\n        }\n        html += '</div>';\n        html += statusHtml;\n        html += '<div id=\"cat-body-' + cat + '\" class=\"cat-body\">';\n\n        /* 笏笏 Fields 笏笏 */\n        for (const [key, meta] of Object.entries(fields)) {\n            if (typeof meta !== 'object' || meta === null) continue;\n            const val = meta.value != null ? meta.value : '';\n            const defaultVal = meta.default_value;\n            const src = meta.source || 'default';\n            const hot = meta.hot_reload !== false;\n            const inputId = 'setting-' + cat + '-' + key;\n            const isPassword = key.toLowerCase().includes('key') || key.toLowerCase().includes('password') || key.toLowerCase().includes('secret');\n            const isBool = val === true || val === false;\n            const desc = meta.description || '';\n            const isMasked = String(val) === '***';\n            const isDiff = !isMasked && defaultVal != null && String(val) !== String(defaultVal);\n            const reloadHint = hot ? '売 Hot-reload OK' : '白 Requires restart';\n            const tooltipText = reloadHint + (meta.reload_time ? ' (竢ｱ ' + meta.reload_time + ')' : '');\n            const searchText = key.replace(/_/g, ' ') + ' ' + desc + ' ' + cat;\n\n            html += '<div class=\"setting-row\" data-setting-key=\"' + cat + '.' + key + '\" data-category=\"' + cat + '\" data-searchtext=\"' + esc(searchText) + '\">';\n\n            /* Label column with blue dot */\n            html += '<div style=\"display:flex;flex-direction:column;gap:2px;flex:0 0 auto;min-width:160px;position:relative\">';\n            html += '<span class=\"setting-diff-dot\" style=\"' + (isDiff ? '' : 'display:none;') + 'position:absolute;left:-14px;top:8px;width:8px;height:8px;border-radius:50%;background:var(--accent-blue)\"></span>';\n            html += '<label class=\"setting-label\" for=\"' + inputId + '\" title=\"' + esc(tooltipText) + '\" style=\"margin-bottom:0\">' + esc(key.replace(/_/g, ' ')) + '</label>';\n            if (desc) html += '<span style=\"font-size:0.7rem;color:var(--text-muted);line-height:1.3\">' + esc(desc) + '</span>';\n            html += '</div>';\n\n            /* Source icon */\n            html += sourceIcon(src);\n\n            /* Lock icon */\n            if (!hot) html += '<span title=\"Restart required\" style=\"cursor:help\">白</span>';\n\n            /* Input element */\n            if (key === 'log_level') {\n                html += '<select id=\"' + inputId + '\" class=\"glass-input\" style=\"flex:1;min-width:120px\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\">';\n                ['DEBUG','INFO','WARNING','ERROR','CRITICAL'].forEach(lv => {\n                    html += '<option value=\"' + lv + '\"' + (String(val).toUpperCase() === lv ? ' selected' : '') + '>' + lv + '</option>';\n                });\n                html += '</select>';\n            } else if (key === 'device') {\n                html += '<select id=\"' + inputId + '\" class=\"glass-input\" style=\"flex:1;min-width:120px\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\">';\n                ['cpu','cuda','mps','auto'].forEach(d => {\n                    html += '<option value=\"' + d + '\"' + (String(val) === d ? ' selected' : '') + '>' + d + '</option>';\n                });\n                html += '</select>';\n            } else if (isBool) {\n                html += '<select id=\"' + inputId + '\" class=\"glass-input\" style=\"flex:1;min-width:120px\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\">';\n                html += '<option value=\"true\"' + (val === true ? ' selected' : '') + '>true</option>';\n                html += '<option value=\"false\"' + (val === false ? ' selected' : '') + '>false</option>';\n                html += '</select>';\n            } else {\n                const inputType = isPassword ? 'password' : (typeof val === 'number' ? 'number' : 'text');\n                html += '<input id=\"' + inputId + '\" type=\"' + inputType + '\" class=\"glass-input\" style=\"flex:1;min-width:160px\" value=\"' + esc(String(val)) + '\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\"' + (typeof val === 'number' ? ' step=\"any\"' : '') + '>';\n            }\n\n            /* Apply button */\n            html += '<button class=\"glass-btn setting-apply-btn\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\" data-input=\"' + inputId + '\" style=\"padding:6px 12px;font-size:0.78rem\">' + (hot ? '笨・Apply' : '白 Apply*') + '</button>';\n\n            /* Reset button (hidden when no diff) */\n            html += '<button class=\"setting-reset-btn\" data-cat=\"' + esc(cat) + '\" data-key=\"' + esc(key) + '\" style=\"' + (isDiff ? '' : 'display:none;') + 'padding:4px 10px;font-size:0.72rem\">竊ｩ Reset</button>';\n\n            /* Restart hint */\n            if (!hot) html += '<span style=\"font-size:0.7rem;color:var(--accent-yellow)\">Restart required</span>';\n\n            /* Validation error placeholder */\n            html += '<div class=\"setting-validation-error\" style=\"display:none;width:100%;font-size:0.72rem;color:var(--accent-red);margin-top:2px\"></div>';\n\n            html += '</div>'; /* end setting-row */\n        }\n\n        html += '</div>'; /* end cat-body */\n        html += '</div>'; /* end category card */\n    }\n\n    /* 笏笏 Source legend & action buttons 笏笏 */\n    html += '<div class=\"glass p-6\">';\n    html += '<div class=\"card-title\">沈 Configuration Source Priority</div>';\n    html += '<div style=\"font-size:0.85rem;color:var(--text-secondary);margin-bottom:16px\">';\n    html += '<span class=\"setting-source source-env\">倹 env</span>';\n    html += '<span style=\"margin:0 8px\">></span>';\n    html += '<span class=\"setting-source source-override\">統 override</span>';\n    html += '<span style=\"margin:0 8px\">></span>';\n    html += '<span class=\"setting-source source-default\">搭 default</span>';\n    html += '</div>';\n    html += '<div style=\"display:flex;gap:10px;flex-wrap:wrap\">';\n    html += '<button id=\"export-config-btn\" class=\"glass-btn-success glass-btn\">豆 Export Config</button>';\n    html += '<button id=\"reset-config-btn\" class=\"glass-btn-danger glass-btn\">卵・・Reset All to Defaults</button>';\n    html += '</div>';\n    html += '</div>';\n\n    el.innerHTML = html;\n\n    /* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・EVENT BINDING 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\n    /* Save profile button */\n    var saveProfileBtn = document.getElementById('save-profile-btn');\n    if (saveProfileBtn) saveProfileBtn.onclick = saveSettingsProfile;\n\n    /* Search clear button */\n    var searchClearBtn = document.getElementById('settings-search-clear');\n    if (searchClearBtn) searchClearBtn.onclick = function() {\n        document.getElementById('settings-search').value = '';\n        filterSettings('');\n    };\n\n    /* Category toggle buttons */\n    document.querySelectorAll('.cat-toggle-btn').forEach(function(btn) {\n        btn.onclick = function() { toggleCategory(this.dataset.toggleCat); };\n    });\n\n    /* Category reset buttons */\n    document.querySelectorAll('.cat-reset-btn').forEach(function(btn) {\n        btn.onclick = function() { resetCategory(this.dataset.resetCat); };\n    });\n\n    /* Per-field reset buttons */\n    document.querySelectorAll('.setting-reset-btn').forEach(function(btn) {\n        btn.onclick = function() {\n            var cat = this.dataset.cat;\n            var key = this.dataset.key;\n            var meta = S.settingsData && S.settingsData[cat] && S.settingsData[cat][key];\n            if (meta && meta.default_value != null) resetField(cat, key, meta.default_value);\n        };\n    });\n\n    /* Apply buttons */\n    document.querySelectorAll('.setting-apply-btn').forEach(function(btn) {\n        btn.onclick = async function() {\n            var cat = btn.dataset.cat;\n            var key = btn.dataset.key;\n            var input = document.getElementById(btn.dataset.input);\n            var value = input.value;\n            /* Type coercion */\n            if (input.tagName === 'SELECT') {\n                if (value === 'true') value = true;\n                else if (value === 'false') value = false;\n            } else if (input.type === 'number') {\n                value = parseFloat(value);\n            }\n            /* Validation */\n            var meta = S.settingsData && S.settingsData[cat] && S.settingsData[cat][key];\n            if (meta) {\n                var result = validateField(cat, key, value, meta);\n                if (!result.valid) {\n                    var errEl = btn.closest('.setting-row').querySelector('.setting-validation-error');\n                    if (errEl) { errEl.textContent = result.error; errEl.style.display = 'block'; }\n                    input.style.borderColor = 'var(--accent-red)';\n                    toast('笶・Validation error: ' + result.error, 'error');\n                    return;\n                }\n            }\n            btn.textContent = '竢ｳ';\n            btn.disabled = true;\n            try {\n                await api('/api/settings', { method: 'PUT', body: JSON.stringify({ category: cat, key: key, value: value }) });\n                toast('笨・Setting saved: ' + cat + '.' + key, 'success');\n                btn.textContent = '笨・Done';\n                if (cat === 'embedding' || cat === 'reranker') startStatusPoll();\n                setTimeout(function() { loadSettings(); }, 1500);\n            } catch (e) {\n                toast('笶・Failed to save: ' + e.message, 'error');\n                btn.textContent = '笶・Error';\n            }\n            setTimeout(function() { btn.disabled = false; }, 2000);\n        };\n    });\n\n    /* Input validation listeners */\n    document.querySelectorAll('.setting-row input, .setting-row select').forEach(function(input) {\n        input.addEventListener('input', function() {\n            var cat = this.dataset.cat;\n            var key = this.dataset.key;\n            var meta = S.settingsData && S.settingsData[cat] && S.settingsData[cat][key];\n            if (!meta) return;\n            var result = validateField(cat, key, this.value, meta);\n            var errEl = this.closest('.setting-row').querySelector('.setting-validation-error');\n            var applyBtn = this.closest('.setting-row').querySelector('.setting-apply-btn');\n            if (!result.valid) {\n                this.style.borderColor = 'var(--accent-red)';\n                if (errEl) { errEl.textContent = result.error; errEl.style.display = 'block'; }\n                if (applyBtn) applyBtn.disabled = true;\n            } else {\n                this.style.borderColor = '';\n                if (errEl) { errEl.textContent = ''; errEl.style.display = 'none'; }\n                if (applyBtn) applyBtn.disabled = false;\n            }\n        });\n    });\n\n    /* Export button */\n    var expBtn = document.getElementById('export-config-btn');\n    if (expBtn) expBtn.onclick = function() {\n        var blob = new Blob([JSON.stringify(settings, null, 2)], {type: 'application/json'});\n        var a = document.createElement('a');\n        a.href = URL.createObjectURL(blob);\n        a.download = 'memorymcp-config.json';\n        a.click();\n        toast('豆 Config exported', 'success');\n    };\n\n    /* Reset All button */\n    var rstBtn = document.getElementById('reset-config-btn');\n    if (rstBtn) rstBtn.onclick = async function() {\n        if (!confirm('Reset ALL settings to defaults? This cannot be undone.')) return;\n        try {\n            for (const [rCat, rFields] of Object.entries(settings)) {\n                if (typeof rFields !== 'object') continue;\n                for (const [rKey, rMeta] of Object.entries(rFields)) {\n                    if (rMeta && rMeta.source === 'override' && rMeta.default_value != null) {\n                        await api('/api/settings', { method: 'PUT', body: JSON.stringify({ category: rCat, key: rKey, value: rMeta.default_value }) });\n                    }\n                }\n            }\n            toast('笨・All settings reset to defaults', 'success');\n            setTimeout(function() { loadSettings(); }, 500);\n        } catch (e) {\n            toast('笶・Reset failed: ' + e.message, 'error');\n        }\n    };\n\n    /* Profile event delegation */\n    var profilesList = document.getElementById('profiles-list');\n    if (profilesList) {\n        profilesList.addEventListener('click', function(e) {\n            var btn = e.target.closest('[data-profile-action]');\n            if (!btn) return;\n            var action = btn.dataset.profileAction;\n            var name = btn.dataset.profileName;\n            if (action === 'load-builtin') {\n                loadSettingsProfile(name, BUILTIN_PROFILES[name]);\n            } else if (action === 'load-user') {\n                var data = localStorage.getItem('memorymcp_profile_' + name);\n                if (data) loadSettingsProfile(name, JSON.parse(data));\n            } else if (action === 'delete') {\n                deleteSettingsProfile(name);\n            }\n        });\n    }\n\n    applyDependsRules();\n    renderSettingsProfiles();\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・SEARCH / FILTER 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction filterSettings(query) {\n    var q = query.toLowerCase().trim();\n    var clearBtn = document.getElementById('settings-search-clear');\n    if (clearBtn) clearBtn.style.display = q ? 'block' : 'none';\n\n    document.querySelectorAll('.setting-category-card').forEach(function(card) {\n        var cat = card.dataset.category || '';\n        var catText = (card.dataset.searchtext || '').toLowerCase();\n        var rows = card.querySelectorAll('.setting-row');\n\n        if (!q) {\n            card.style.display = '';\n            rows.forEach(function(r) { r.style.display = ''; });\n            return;\n        }\n\n        var catMatch = catText.includes(q);\n        var anyRowMatch = false;\n\n        rows.forEach(function(r) {\n            var rowText = (r.dataset.searchtext || '').toLowerCase();\n            if (catMatch) {\n                r.style.display = '';\n                anyRowMatch = true;\n            } else if (rowText.includes(q)) {\n                r.style.display = '';\n                anyRowMatch = true;\n            } else {\n                r.style.display = 'none';\n            }\n        });\n\n        card.style.display = (catMatch || anyRowMatch) ? '' : 'none';\n\n        /* Auto-expand matching categories */\n        if (catMatch || anyRowMatch) {\n            var body = document.getElementById('cat-body-' + cat);\n            var toggle = document.getElementById('cat-toggle-' + cat);\n            if (body) body.style.display = 'block';\n            if (toggle) toggle.textContent = '笆ｼ';\n        }\n    });\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・CATEGORY TOGGLE 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction toggleCategory(catId) {\n    var body = document.getElementById('cat-body-' + catId);\n    var toggle = document.getElementById('cat-toggle-' + catId);\n    if (body.style.display === 'none') {\n        body.style.display = 'block';\n        toggle.textContent = '笆ｼ';\n    } else {\n        body.style.display = 'none';\n        toggle.textContent = '笆ｶ';\n    }\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・RESET FUNCTIONS 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nasync function resetField(cat, key, defaultVal) {\n    try {\n        await api('/api/settings', { method: 'PUT', body: JSON.stringify({ category: cat, key: key, value: defaultVal }) });\n        toast('笨・Reset ' + cat + '.' + key + ' to default', 'success');\n        setTimeout(function() { loadSettings(); }, 800);\n    } catch (e) {\n        toast('笶・Reset failed: ' + e.message, 'error');\n    }\n}\n\nasync function resetCategory(cat) {\n    if (!confirm('Reset all ' + cat + ' settings to defaults?')) return;\n    var settings = S.settingsData;\n    if (!settings || !settings[cat]) return;\n    try {\n        for (const [key, meta] of Object.entries(settings[cat])) {\n            if (meta && meta.source === 'override' && meta.default_value != null) {\n                await api('/api/settings', { method: 'PUT', body: JSON.stringify({ category: cat, key: key, value: meta.default_value }) });\n            }\n        }\n        toast('笨・Category ' + cat + ' reset to defaults', 'success');\n        setTimeout(function() { loadSettings(); }, 800);\n    } catch (e) {\n        toast('笶・Reset failed: ' + e.message, 'error');\n    }\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・DEPENDENCY RULES 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction applyDependsRules() {\n    for (const [targetKey, rule] of Object.entries(DEPENDS_RULES)) {\n        var parts = rule.field.split('.');\n        var depCat = parts[0];\n        var depKey = parts[1];\n        var settings = S.settingsData;\n        if (!settings || !settings[depCat] || !settings[depCat][depKey]) continue;\n        var depValue = settings[depCat][depKey].value;\n        var isEnabled = depValue === rule.value || depValue === String(rule.value);\n        var row = document.querySelector('[data-setting-key=\"' + targetKey + '\"]');\n        if (row) {\n            row.style.opacity = isEnabled ? '1' : '0.4';\n            row.style.pointerEvents = isEnabled ? 'auto' : 'none';\n            var input = row.querySelector('input, select');\n            var btn = row.querySelector('.setting-apply-btn');\n            if (!isEnabled) {\n                if (input) input.disabled = true;\n                if (btn) btn.disabled = true;\n            } else {\n                if (input) input.disabled = false;\n                if (btn) btn.disabled = false;\n            }\n        }\n    }\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・FIELD VALIDATION 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction validateField(cat, key, value, meta) {\n    /* Number validation */\n    if (typeof meta.default_value === 'number' || meta.default_value === 0) {\n        var num = parseFloat(value);\n        if (isNaN(num)) return { valid: false, error: 'Must be a number' };\n        if (key === 'port' && (num < 1 || num > 65535)) return { valid: false, error: 'Port must be 1-65535' };\n        if (key === 'batch_size' && num < 1) return { valid: false, error: 'Must be >= 1' };\n        if (key === 'min_strength' && (num < 0 || num > 1)) return { valid: false, error: 'Must be 0-1' };\n        if (key === 'min_importance' && (num < 0 || num > 1)) return { valid: false, error: 'Must be 0-1' };\n        if (key === 'contradiction_threshold' && (num < 0 || num > 1)) return { valid: false, error: 'Must be 0-1' };\n        if (key === 'duplicate_threshold' && (num < 0 || num > 1)) return { valid: false, error: 'Must be 0-1' };\n        if (key.includes('interval') && num < 0) return { valid: false, error: 'Must be >= 0' };\n        if (key === 'llm_max_tokens' && num < 1) return { valid: false, error: 'Must be >= 1' };\n    }\n    /* URL validation */\n    if (key.includes('url') && value && !(String(value).startsWith('http://') || String(value).startsWith('https://'))) {\n        return { valid: false, error: 'Must start with http:// or https://' };\n    }\n    return { valid: true, error: '' };\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・PROFILES 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction saveSettingsProfile() {\n    var name = prompt('Enter profile name:');\n    if (!name || !name.trim()) return;\n    var settings = S.settingsData;\n    if (!settings) { toast('No settings loaded', 'error'); return; }\n    var profile = {};\n    for (const [cat, fields] of Object.entries(settings)) {\n        if (typeof fields !== 'object' || fields === null) continue;\n        profile[cat] = {};\n        for (const [key, meta] of Object.entries(fields)) {\n            if (meta && meta.value != null) profile[cat][key] = meta.value;\n        }\n    }\n    localStorage.setItem('memorymcp_profile_' + name.trim(), JSON.stringify(profile));\n    toast('沈 Profile \"' + esc(name.trim()) + '\" saved', 'success');\n    renderSettingsProfiles();\n}\n\nasync function loadSettingsProfile(name, profile) {\n    if (!confirm('Load profile \"' + esc(name) + '\"? This will apply all settings from the profile.')) return;\n    try {\n        var count = 0;\n        for (const [cat, fields] of Object.entries(profile)) {\n            for (const [key, value] of Object.entries(fields)) {\n                await api('/api/settings', { method: 'PUT', body: JSON.stringify({ category: cat, key: key, value: value }) });\n                count++;\n            }\n        }\n        toast('笨・Loaded profile \"' + esc(name) + '\" (' + count + ' settings)', 'success');\n        setTimeout(function() { loadSettings(); }, 1000);\n    } catch (e) {\n        toast('笶・Failed to load profile: ' + e.message, 'error');\n    }\n}\n\nfunction deleteSettingsProfile(name) {\n    if (!confirm('Delete profile \"' + esc(name) + '\"?')) return;\n    localStorage.removeItem('memorymcp_profile_' + name);\n    toast('Profile \"' + esc(name) + '\" deleted', 'info');\n    renderSettingsProfiles();\n}\n\nfunction renderSettingsProfiles() {\n    var container = document.getElementById('profiles-list');\n    if (!container) return;\n    var html = '';\n    /* Built-in profiles */\n    for (const [name] of Object.entries(BUILTIN_PROFILES)) {\n        html += '<button data-profile-action=\"load-builtin\" data-profile-name=\"' + esc(name) + '\" class=\"glass-btn profile-chip\" style=\"padding:5px 14px;font-size:0.78rem;background:linear-gradient(135deg,rgba(167,139,250,0.15),rgba(244,114,182,0.15));border-color:rgba(167,139,250,0.3)\">';\n        html += '逃 ' + esc(name);\n        html += '</button>';\n    }\n    /* User profiles from localStorage */\n    for (var i = 0; i < localStorage.length; i++) {\n        var k = localStorage.key(i);\n        if (k && k.startsWith('memorymcp_profile_')) {\n            var pName = k.replace('memorymcp_profile_', '');\n            html += '<div style=\"display:inline-flex;align-items:center;gap:0\">';\n            html += '<button data-profile-action=\"load-user\" data-profile-name=\"' + esc(pName) + '\" class=\"glass-btn profile-chip\" style=\"padding:5px 14px;font-size:0.78rem;border-top-right-radius:0;border-bottom-right-radius:0\">';\n            html += '側 ' + esc(pName);\n            html += '</button>';\n            html += '<button data-profile-action=\"delete\" data-profile-name=\"' + esc(pName) + '\" class=\"glass-btn glass-btn-danger\" style=\"padding:5px 8px;font-size:0.72rem;border-top-left-radius:0;border-bottom-left-radius:0;border-left:none\" title=\"Delete profile\">笨・/button>';\n            html += '</div>';\n        }\n    }\n    if (!html) html = '<span style=\"font-size:0.8rem;color:var(--text-muted)\">No profiles yet</span>';\n    container.innerHTML = html;\n}\n\n/* 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・STATUS POLLING 笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊絶武笊・*/\n\nfunction startStatusPoll() {\n    if (S.statusPoll) clearInterval(S.statusPoll);\n    S.statusPoll = setInterval(async function() {\n        try {\n            var status = await api('/api/settings/status');\n            var rs = status.reload_status || {};\n            var allDone = Object.values(rs).every(function(s) {\n                return !s.status || s.status === 'idle' || s.status === 'ready' || s.status === 'success' || s.status === 'error';\n            });\n            if (allDone) {\n                clearInterval(S.statusPoll);\n                S.statusPoll = null;\n                loadSettings();\n            } else {\n                var el = document.getElementById('settings-content');\n                var settings = S.settingsData;\n                if (settings) renderSettings(el, settings, status);\n            }\n        } catch(e) { /* ignore poll errors */ }\n    }, 2000);\n}\nasync function loadAdmin() {\n    const el = document.getElementById('admin-content');\n    try {\n        const [health, dashData] = await Promise.all([\n            api('/health'),\n            S.dashCache ? Promise.resolve(S.dashCache) : api('/api/dashboard/' + encodeURIComponent(S.persona))\n        ]);\n        if (!S.dashCache) S.dashCache = dashData;\n        const stats = dashData.stats || {};\n        const uptimeMs = Date.now() - S.initTime;\n        const uptimeStr = uptimeMs < 3600000 ? Math.floor(uptimeMs/60000) + 'm' : Math.floor(uptimeMs/3600000) + 'h ' + Math.floor((uptimeMs%3600000)/60000) + 'm';\n\n        el.innerHTML = `\n        <div class=\"grid grid-cols-1 md:grid-cols-3 gap-6 mb-6\">\n            <div class=\"glass p-6\">\n                <div class=\"card-title\">売 Rebuild Vector Store</div>\n                <p style=\"font-size:0.85rem;color:var(--text-secondary);margin-bottom:16px\">Rebuild the Qdrant vector collection for the current persona. This may take a few minutes.</p>\n                <button id=\"rebuild-btn\" class=\"glass-btn\" style=\"width:100%\">売 Rebuild Vectors</button>\n                <div id=\"rebuild-status\" style=\"margin-top:12px;font-size:0.82rem;color:var(--text-muted);text-align:center\"></div>\n            </div>\n            <div class=\"glass p-6\">\n                <div class=\"card-title\">投 Database Stats</div>\n                <div style=\"display:grid;gap:10px\">\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Total Memories</span><span style=\"font-weight:600\">${stats.total_count ?? '--'}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Blocks</span><span style=\"font-weight:600\">${(dashData.blocks || []).length}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Unique Tags</span><span style=\"font-weight:600\">${Object.keys(stats.tag_distribution || {}).length}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Emotions Tracked</span><span style=\"font-weight:600\">${Object.keys(stats.emotion_distribution || {}).length}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Goals</span><span style=\"font-weight:600\">${(dashData.goals || []).length}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Promises</span><span style=\"font-weight:600\">${(dashData.promises || []).length}</span></div>\n                </div>\n            </div>\n            <div class=\"glass p-6\">\n                <div class=\"card-title\">搭 System Info</div>\n                <div style=\"display:grid;gap:10px\">\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Version</span><span style=\"font-weight:600\">${esc(health.version || '--')}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Status</span><span class=\"badge ${health.status === 'ok' ? 'badge-green' : 'badge-red'}\">${esc(health.status || '--')}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Qdrant</span><span class=\"badge ${health.qdrant === 'connected' ? 'badge-green' : 'badge-yellow'}\">${esc(health.qdrant || '--')}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Session</span><span style=\"font-weight:600\">${uptimeStr}</span></div>\n                    <div style=\"display:flex;justify-content:space-between\"><span style=\"color:var(--text-muted)\">Persona</span><span style=\"font-weight:600\">${esc(S.persona)}</span></div>\n                </div>\n            </div>\n        </div>`;\n\n        // Rebuild button\n        document.getElementById('rebuild-btn').onclick = async () => {\n            const btn = document.getElementById('rebuild-btn');\n            const statusEl = document.getElementById('rebuild-status');\n            btn.disabled = true;\n            btn.textContent = '竢ｳ Rebuilding...';\n            statusEl.innerHTML = '<div class=\"progress-wrap\"><div class=\"progress-bar progress-indeterminate\"></div></div>';\n            try {\n                await api('/api/admin/rebuild/' + encodeURIComponent(S.persona), { method: 'POST' });\n                statusEl.innerHTML = '<span style=\"color:var(--accent-green)\">笨・Rebuild started successfully</span>';\n                toast('Vector rebuild initiated', 'success');\n            } catch (e) {\n                statusEl.innerHTML = '<span style=\"color:var(--accent-red)\">笶・' + esc(e.message) + '</span>';\n                toast('Rebuild failed: ' + e.message, 'error');\n            }\n            btn.disabled = false;\n            btn.textContent = '売 Rebuild Vectors';\n        };\n        updateLastTime();\n    } catch (e) {\n        el.innerHTML = errorCard('Failed to load admin: ' + e.message);\n    }\n}\n"
